const UUID_RE = '[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}';
// Stage 8.8.23 — POST /staff/bookings/:booking_id/service-records/create-payment-link
