function editWriteContactSnapshot(row) {
  return {
    guest_name: row.guest_name,
    phone:      row.phone || null,
    email:      row.email || null,
  };
}

function editWriteContactFieldsMatch(a, b) {
  return String(a.guest_name || '') === String(b.guest_name || '')
    && String(a.phone || '') === String(b.phone || '')
    && String(a.email || '') === String(b.email || '');
}

/** phone/email: null or '' clears; undefined = leave unchanged. */
function editWriteNormalizeOptionalContactField(value) {
  if (value === null || value === undefined) return null;
  const trimmed = String(value).trim();
  return trimmed === '' ? null : trimmed;
}

function editWriteParseContactPatch(body) {
  const patch = {};
  if (Object.prototype.hasOwnProperty.call(body, 'guest_name')) {
    patch.guest_name = body.guest_name === null
      ? null
      : String(body.guest_name).trim();
  }
  if (Object.prototype.hasOwnProperty.call(body, 'phone')) {
    patch.phone = editWriteNormalizeOptionalContactField(body.phone);
  }
  if (Object.prototype.hasOwnProperty.call(body, 'email')) {
    patch.email = editWriteNormalizeOptionalContactField(body.email);
  }
  return patch;
}

function editWriteMergeContactFields(bookingRow, patch) {
  return {
    guest_name: patch.guest_name !== undefined
      ? patch.guest_name
      : bookingRow.guest_name,
    phone: patch.phone !== undefined
      ? patch.phone
      : (bookingRow.phone || null),
    email: patch.email !== undefined
      ? patch.email
      : (bookingRow.email || null),
  };
}

function editWriteContactBookingSummary(row) {
  return {
    booking_id:   row.booking_id,
    booking_code: row.booking_code,
    guest_name:   row.guest_name,
    phone:        row.phone || null,
    email:        row.email || null,
  };
}

function editWritePackageSnapshot(row) {
  return {
    package_code:        row.package_code || null,
    total_amount_cents:  row.total_amount_cents != null ? Number(row.total_amount_cents) : null,
    balance_due_cents:   row.balance_due_cents != null ? Number(row.balance_due_cents) : null,
  };
}

function editWritePackageBookingSummary(row) {
  return {
    booking_id:   row.booking_id,
    booking_code: row.booking_code,
    package_code: row.package_code || null,
    guest_name:   row.guest_name,
    phone:        row.phone || null,
    email:        row.email || null,
  };
}

function editWriteInvoiceImpactFromPreview(invoicePreview, packageChanged) {
  const proposed = (invoicePreview && invoicePreview.proposed) || {};
  return {
    requires_reprice:     !!(invoicePreview && invoicePreview.requires_reprice),
    package_changed:    !!packageChanged,
    payment_mutation:   false,
    stripe_mutation:    false,
    total_amount_cents: proposed.total_amount_cents != null ? proposed.total_amount_cents : null,
    balance_due_cents:  proposed.balance_due_cents != null ? proposed.balance_due_cents : null,
    needs_refund:           proposed.needs_refund === true,
    refund_review_needed:   proposed.needs_refund === true,
    delta_amount_cents: invoicePreview && invoicePreview.delta_amount_cents != null
      ? invoicePreview.delta_amount_cents
      : null,
  };
}

function editPreviewBookingSummary(row) {
  return {
    booking_id:     row.booking_id,
    booking_code:   row.booking_code,
    guest_name:     row.guest_name,
    phone:          row.phone || null,
    email:          row.email || null,
    guest_count:    row.guest_count != null ? Number(row.guest_count) : null,
    package_code:   row.package_code || null,
    check_in:       row.check_in,
    check_out:      row.check_out,
    payment_status: row.payment_status,
  };
}

function editPreviewSvcSum(svcRows) {
  return (svcRows || []).reduce((s, r) => s + serviceRecordBillableCents(r), 0);
}

function editPreviewAccommodationCents(bk, svcRows, quoteSnap) {
  if (quoteSnap && Array.isArray(quoteSnap.line_items)) {
    let sum = 0;
    let any = false;
    for (const li of quoteSnap.line_items) {
      if (li.code && EDIT_PREVIEW_ACCOMM_LINE_CODES[li.code] && li.total_cents != null) {
        sum += Number(li.total_cents);
        any = true;
      }
    }
    if (any) return sum;
  }
  const svcSum = editPreviewSvcSum(svcRows);
  if (bk && bk.total_amount_cents != null) {
    const total = Number(bk.total_amount_cents);
    const derived = total - svcSum;
    return derived >= 0 ? derived : total;
  }
  return null;
}

function editPreviewAccFromQuote(quote) {
  if (!quote || !quote.success || !Array.isArray(quote.line_items)) return null;
  let sum = 0;
  let any = false;
  for (const li of quote.line_items) {
    if (li.code && EDIT_PREVIEW_ACCOMM_LINE_CODES[li.code] && li.total_cents != null) {
      sum += Number(li.total_cents);
      any = true;
    }
  }
  return any ? sum : null;
}

function editPreviewBuildLineItems(accCents, svcRows, quoteLineItems) {
  const items = [];
  if (quoteLineItems && quoteLineItems.length) {
    for (const li of quoteLineItems) {
      if (li.code && EDIT_PREVIEW_ACCOMM_LINE_CODES[li.code]) {
        items.push({
          kind: 'accommodation',
          code: li.code,
          label: li.label || li.description || li.code,
          amount_cents: Number(li.total_cents),
        });
      }
    }
  } else if (accCents != null) {
    items.push({ kind: 'accommodation', code: 'accommodation', label: 'Accommodation', amount_cents: accCents });
  }
  for (const sr of (svcRows || [])) {
    items.push({
      kind: 'addon',
      code: sr.service_type,
      label: sr.service_type,
      amount_cents: sr.amount_due_cents != null ? Number(sr.amount_due_cents) : null,
    });
  }
  return items;
}

function editPreviewInvoiceSide(accCents, svcRows, paidCents, quoteLineItems) {
  const svcSum = editPreviewSvcSum(svcRows);
  const line_items = editPreviewBuildLineItems(accCents, svcRows, quoteLineItems);
  const total_amount_cents = accCents != null ? accCents + svcSum : null;
  const paid_amount_cents = paidCents != null ? Number(paidCents) : null;
  let balance_due_cents = null;
  let needs_refund = false;
  if (total_amount_cents != null && paid_amount_cents != null) {
    if (total_amount_cents > paid_amount_cents) {
      balance_due_cents = total_amount_cents - paid_amount_cents;
    } else if (total_amount_cents < paid_amount_cents) {
      needs_refund = true;
      balance_due_cents = 0;
    } else {
      balance_due_cents = 0;
    }
  }
  return { line_items, total_amount_cents, paid_amount_cents, balance_due_cents, needs_refund };
}

function editPreviewTryQuote(clientSlug, checkIn, checkOut, guestCount, packageCode) {
  try {
    return calculateWolfhouseQuote({
      client_slug:    clientSlug,
      check_in:       checkIn,
      check_out:      checkOut,
      guest_count:    guestCount,
      package_code:   packageCode,
      room_type:      'shared',
      payment_choice: 'deposit',
      add_ons:        [],
    });
  } catch (err) {
    return { success: false, error: err.message };
  }
}

function staffPackageDisplayLabel(code) {
  const c = String(code || '').trim().toLowerCase();
  if (!c || c === 'no_package' || c === 'package_none') return 'No package';
  return c.charAt(0).toUpperCase() + c.slice(1);
}

function normalizeGuestPackagesFromBooking(booking, metadata) {
  const guestCount = Math.max(1, Number(booking && booking.guest_count) || 1);
  const md = metadata || (booking && booking.metadata) || {};
  const raw = md.guest_packages;
  const fallbackPkg = booking && booking.package_code ? String(booking.package_code).trim().toLowerCase() : 'no_package';
  if (Array.isArray(raw) && raw.length > 0) {
    const out = [];
    for (let i = 0; i < guestCount; i++) {
      const byIndex = raw[i];
      const byNumber = raw.find((gp) => Number(gp && gp.guest_number) === i + 1);
      const item = byIndex || byNumber || null;
      const code = item && item.package_code
        ? String(item.package_code).trim().toLowerCase()
        : fallbackPkg;
      out.push({ guest_number: i + 1, package_code: code || 'no_package' });
    }
    return out;
  }
  return Array.from({ length: guestCount }, (_, i) => ({
    guest_number: i + 1,
    package_code: fallbackPkg,
  }));
}

function guestQuoteAccommodationCents(quote) {
  if (!quote || !quote.success) return null;
  const items = quote.line_items || [];
  let sum = 0;
  let any = false;
  for (const li of items) {
    if (li.code && EDIT_PREVIEW_ACCOMM_LINE_CODES[li.code] && li.total_cents != null) {
      sum += Number(li.total_cents);
      any = true;
    }
  }
  if (any) return sum;
  return quote.total_cents != null ? Number(quote.total_cents) : null;
}

function buildGuestAccommodationLines(clientSlug, booking, metadata) {
  const guestPackages = normalizeGuestPackagesFromBooking(booking, metadata);
  const nights = movePreviewNights(booking.check_in, booking.check_out);
  return guestPackages.map((gp) => {
    const pkgRaw = gp.package_code;
    const quoteCode = editPreviewQuotePackageCode(pkgRaw);
    let accommodation_cents = 0;
    const quote = editPreviewTryQuote(clientSlug, booking.check_in, booking.check_out, 1, quoteCode);
    const cents = guestQuoteAccommodationCents(quote);
    if (cents != null) accommodation_cents = cents;
    return {
      guest_number: gp.guest_number,
      package_code: pkgRaw,
      package_label: staffPackageDisplayLabel(pkgRaw),
      nights,
      accommodation_cents,
    };
  });
}

function guestPackagesMajorityStorageCode(guestPackages) {
  const counts = new Map();
  for (const gp of guestPackages) {
    const stored = editPreviewPackageStorageCode(gp.package_code);
    const key = stored || '__no_package__';
    counts.set(key, (counts.get(key) || 0) + 1);
  }
  let bestKey = null;
  let bestCount = 0;
  for (const [key, count] of counts.entries()) {
    if (count > bestCount) {
      bestCount = count;
      bestKey = key;
    }
  }
  if (bestKey === '__no_package__') return null;
  return bestKey;
}

function normalizeGuestPackagesInput(raw, guestCount, fallbackPackageCode) {
  if (!Array.isArray(raw) || raw.length === 0) {
    return { error: 'guest_packages array is required' };
  }
  if (raw.length !== guestCount) {
    return {
      error: `guest_packages length (${raw.length}) must match guest_count (${guestCount})`,
    };
  }
  const normalized = [];
  for (let i = 0; i < guestCount; i++) {
    const item = raw[i];
    const guestNumber = Number(item && item.guest_number) || (i + 1);
    const packageCodeRaw = String(
      (item && item.package_code) || fallbackPackageCode || '',
    ).trim().toLowerCase();
    if (!packageCodeRaw) {
      return { error: `package_code is required for guest ${guestNumber}` };
    }
    if (!editPreviewIsValidPackage(packageCodeRaw, fallbackPackageCode)) {
      return { error: `Invalid package_code for guest ${guestNumber}` };
    }
    normalized.push({ guest_number: i + 1, package_code: packageCodeRaw });
  }
  return { guest_packages: normalized };
}

function editWriteStayRequiresPackageCode(nights) {
  return nights != null && nights >= EDIT_WRITE_PACKAGE_MIN_NIGHTS;
}

function editWriteShortStayAccFromQuoteSnapshot(quoteSnap, nights, guestCount) {
  if (!quoteSnap || !Array.isArray(quoteSnap.line_items) || nights == null || nights <= 0) return null;
  const guests = Math.max(1, Number(guestCount) || 1);
  for (const li of quoteSnap.line_items) {
    if (!li.code || !EDIT_PREVIEW_ACCOMM_LINE_CODES[li.code]) continue;
    if (li.unit_cents != null && li.nights > 0) {
      const perNight = Number(li.unit_cents);
      return perNight * nights * guests;
    }
    if (li.total_cents != null && li.nights > 0 && li.guest_count > 0) {
      const perNightPerGuest = Number(li.total_cents) / (li.nights * li.guest_count);
      return Math.round(perNightPerGuest * nights * guests);
    }
    if (li.total_cents != null && li.nights > 0) {
      const perNight = Number(li.total_cents) / li.nights;
      return Math.round(perNight * nights * guests);
    }
  }
  return null;
}

function editWriteScaleAccommodationCents(curAccCents, curNights, newNights, curGuests, newGuests) {
  if (curAccCents == null || curNights == null || curNights <= 0 || newNights == null || newNights <= 0) {
    return null;
  }
  const perNight = curAccCents / curNights;
  const curG = Math.max(1, Number(curGuests) || 1);
  const newG = Math.max(1, Number(newGuests) || 1);
  const guestFactor = newG / curG;
  return Math.round(perNight * newNights * guestFactor);
}

function editWriteResolveProposedAccommodation(bookingRow, svcRows, proposedFields, pricingAffects) {
  const calculation_warnings = [];
  const checkIn = proposedFields.check_in || bookingRow.check_in;
  const checkOut = proposedFields.check_out || bookingRow.check_out;
  const guestCount = proposedFields.guest_count != null
    ? proposedFields.guest_count
    : Number(bookingRow.guest_count) || 1;
  const packageCodeRaw = proposedFields.package_code !== undefined
    ? proposedFields.package_code
    : bookingRow.package_code;
  const packageCode = editPreviewPackageStorageCode(packageCodeRaw);
  const nights = movePreviewNights(checkIn, checkOut);
  const metadata = bookingRow.metadata || {};
  const quoteSnap = (metadata && typeof metadata === 'object' && metadata.quote_snapshot) || null;
  const curAcc = editPreviewAccommodationCents(bookingRow, svcRows, quoteSnap);
  const curNights = movePreviewNights(bookingRow.check_in, bookingRow.check_out);
  const curGuests = Number(bookingRow.guest_count) || 1;

  if (!pricingAffects) {
    return {
      proposedAcc: curAcc,
      proposedQuoteLines: null,
      requires_reprice: false,
      package_required_for_long_stay: false,
      calculation_warnings,
    };
  }

  if (editWriteStayRequiresPackageCode(nights) && !packageCode) {
    return {
      proposedAcc: null,
      proposedQuoteLines: null,
      requires_reprice: true,
      package_required_for_long_stay: true,
      calculation_warnings: ['package_required_for_long_stay'],
    };
  }

  if (!packageCode) {
    const q = editPreviewTryQuote(
      bookingRow._client_slug || DEFAULT_CLIENT,
      checkIn,
      checkOut,
      guestCount,
      'no_package',
    );
    if (q && q.success) {
      const proposedAcc = editPreviewAccFromQuote(q);
      if (proposedAcc != null) {
        return {
          proposedAcc,
          proposedQuoteLines: q.line_items,
          requires_reprice: false,
          package_required_for_long_stay: false,
          calculation_warnings: ['No package priced from Malibu reference rate.'],
        };
      }
      calculation_warnings.push('No-package quote returned no accommodation line items.');
    } else {
      const blockers = (q && Array.isArray(q.blockers)) ? q.blockers.map(String) : [];
      if (q && q.error) calculation_warnings.push(String(q.error));
      else if (blockers.length) calculation_warnings.push(...blockers);
      else calculation_warnings.push('No-package quote calculation blocked or incomplete.');
    }
  }

  if (packageCode) {
    const q = editPreviewTryQuote(
      bookingRow._client_slug || DEFAULT_CLIENT,
      checkIn,
      checkOut,
      guestCount,
      packageCode,
    );
    if (q && q.success) {
      const proposedAcc = editPreviewAccFromQuote(q);
      if (proposedAcc == null) {
        calculation_warnings.push('Quote returned no accommodation line items.');
        return {
          proposedAcc: null,
          proposedQuoteLines: q.line_items,
          requires_reprice: true,
          package_required_for_long_stay: false,
          calculation_warnings,
        };
      }
      return {
        proposedAcc,
        proposedQuoteLines: q.line_items,
        requires_reprice: false,
        package_required_for_long_stay: false,
        calculation_warnings,
      };
    }
    const blockers = (q && Array.isArray(q.blockers)) ? q.blockers.map(String) : [];
    if (q && q.error) calculation_warnings.push(String(q.error));
    else if (blockers.length) calculation_warnings.push(...blockers);
    else calculation_warnings.push('Quote calculation blocked or incomplete.');
    return {
      proposedAcc: null,
      proposedQuoteLines: null,
      requires_reprice: true,
      package_required_for_long_stay: false,
      calculation_warnings,
    };
  }

  let proposedAcc = editWriteShortStayAccFromQuoteSnapshot(quoteSnap, nights, guestCount);
  if (proposedAcc != null) {
    calculation_warnings.push('Short stay repriced from quote_snapshot nightly rate (no package).');
    return {
      proposedAcc,
      proposedQuoteLines: null,
      requires_reprice: false,
      package_required_for_long_stay: false,
      calculation_warnings,
    };
  }

  proposedAcc = editWriteScaleAccommodationCents(curAcc, curNights, nights, curGuests, guestCount);
  if (proposedAcc != null) {
    calculation_warnings.push('Short stay accommodation scaled from current booking rate (no package).');
    return {
      proposedAcc,
      proposedQuoteLines: null,
      requires_reprice: false,
      package_required_for_long_stay: false,
      calculation_warnings,
    };
  }

  if (curAcc != null) {
    calculation_warnings.push(
      'Exact short-stay reprice unavailable; preserving current accommodation total on write.'
    );
    return {
      proposedAcc: curAcc,
      proposedQuoteLines: null,
      requires_reprice: false,
      package_required_for_long_stay: false,
      calculation_warnings,
    };
  }

  calculation_warnings.push('Accommodation total could not be derived for short stay without package.');
  return {
    proposedAcc: null,
    proposedQuoteLines: null,
    requires_reprice: true,
    package_required_for_long_stay: false,
    calculation_warnings,
  };
}

function editWriteShouldBlockPricingWrite(invoicePreview, pricingAffects, repriceErrorCode) {
  if (!pricingAffects) return { block: false };
  if (invoicePreview.package_required_for_long_stay) {
    return { block: true, error: 'package_required_for_long_stay' };
  }
  const proposed = (invoicePreview && invoicePreview.proposed) || {};
  if (proposed.total_amount_cents != null) return { block: false };
  if (invoicePreview && invoicePreview.requires_reprice) {
    return { block: true, error: repriceErrorCode };
  }
  return { block: false };
}

function editPreviewBuildInvoicePreview(bookingRow, svcRows, proposedFields, pricingAffects) {
  const metadata = bookingRow.metadata || {};
  const quoteSnap = (metadata && typeof metadata === 'object' && metadata.quote_snapshot) || null;
  const paidCents = bookingRow.amount_paid_cents != null ? Number(bookingRow.amount_paid_cents) : null;
  const curAcc = editPreviewAccommodationCents(bookingRow, svcRows, quoteSnap);
  const current = editPreviewInvoiceSide(curAcc, svcRows, paidCents, null);

  const resolved = editWriteResolveProposedAccommodation(bookingRow, svcRows, proposedFields, pricingAffects);
  const proposed = editPreviewInvoiceSide(
    resolved.proposedAcc,
    svcRows,
    paidCents,
    resolved.proposedQuoteLines
  );
  const delta_amount_cents = (current.total_amount_cents != null && proposed.total_amount_cents != null)
    ? proposed.total_amount_cents - current.total_amount_cents
    : null;

  const invoice = {
    current,
    proposed,
    delta_amount_cents,
    payment_mutation: false,
    stripe_mutation: false,
    note: 'Preview only. No booking, bed, payment, service, or Stripe changes were made.',
  };
  if (resolved.requires_reprice) invoice.requires_reprice = true;
  if (resolved.package_required_for_long_stay) invoice.package_required_for_long_stay = true;
  if (resolved.calculation_warnings.length) invoice.calculation_warnings = resolved.calculation_warnings;
  return invoice;
}

function editPreviewGuestBedRelease(sourceBeds, currentGuests, newGuestCount) {
  const ordered = (sourceBeds || []).slice();
  const cur = Math.max(1, Number(currentGuests) || 1);
  const next = Number(newGuestCount);
  if (next > cur) {
    return { blocked: true, reason: 'guest_increase_not_supported' };
  }
  if (next < 1 || !Number.isFinite(next)) {
    return { blocked: true, reason: 'invalid_guest_count' };
  }
  if (next === cur) {
    return {
      changed: false,
      from: cur,
      to: next,
      release_booking_bed_ids: [],
      released_beds: [],
      remaining_beds: ordered.map((r) => r.bed_code),
    };
  }
  const nRelease = cur - next;
  if (ordered.length < nRelease) {
    return { requires_manual_review: true, reason: 'insufficient_assignment_rows', from: cur, to: next };
  }
  const releaseRows = ordered.slice(-nRelease);
  const remainRows = ordered.slice(0, ordered.length - nRelease);
  return {
    changed: true,
    from: cur,
    to: next,
    release_count: nRelease,
    release_booking_bed_ids: releaseRows.map((r) => r.booking_bed_id),
    released_beds: releaseRows.map((r) => r.bed_code),
    remaining_beds: remainRows.map((r) => r.bed_code),
  };
}

async function editWriteDatesEvaluateAvailability(pg, clientSlug, bookingRow, sourceBeds, checkIn, checkOut) {
  if (!sourceBeds.length) {
    return {
      conflicts: [],
      requires_manual_review: true,
      reason: 'no_active_assignments',
    };
  }
  const assignRes = await pg.query(MOVE_TARGETS_RANGE_ASSIGNMENTS_SQL, [clientSlug, checkIn, checkOut]);
  let bedNotSellable = false;
  for (const bed of sourceBeds) {
    const bedRes = await pg.query(MOVE_PREVIEW_BED_BY_ID_SQL, [clientSlug, bed.bed_id]);
    const bedRow = bedRes.rows[0];
    if (bedRow && (bedRow.active === false || bedRow.sellable === false)) {
      bedNotSellable = true;
    }
  }
  const conflicts = editPreviewDatesBuildConflicts(
    assignRes.rows,
    bookingRow.booking_id,
    checkIn,
    checkOut,
    sourceBeds
  );
  return {
    conflicts,
    requires_manual_review: bedNotSellable,
    reason: bedNotSellable ? 'bed_not_sellable' : null,
  };
}

function editWriteDatesSnapshot(row) {
  return {
    check_in:  row.check_in || null,
    check_out: row.check_out || null,
    nights:    movePreviewNights(row.check_in, row.check_out),
    total_amount_cents: row.total_amount_cents != null ? Number(row.total_amount_cents) : null,
    balance_due_cents:  row.balance_due_cents != null ? Number(row.balance_due_cents) : null,
  };
}

function editWriteDatesFieldsMatch(before, checkIn, checkOut) {
  return String(before.check_in || '') === String(checkIn || '')
    && String(before.check_out || '') === String(checkOut || '');
}

function editPreviewDatesBuildConflicts(assignmentRows, sourceBookingId, checkIn, checkOut, sourceBeds) {
  const bedById = {};
  for (const b of sourceBeds) bedById[b.bed_id] = b;
  return assignmentRows
    .filter((row) => sourceBeds.some((b) => b.bed_id === row.bed_id))
    .filter((row) => row.booking_id !== sourceBookingId)
    .filter(movePreviewIsBlockingAssignment)
    .filter((row) => movePreviewHalfOpenOverlaps(row.check_in, row.check_out, checkIn, checkOut))
    .map((row) => ({
      booking_bed_id: row.booking_bed_id,
      booking_id:   row.booking_id,
      booking_code: row.booking_code,
      guest_name:   row.guest_name,
      check_in:     row.check_in,
      check_out:    row.check_out,
      bed_id:       row.bed_id,
      bed_code:     row.bed_code || (bedById[row.bed_id] && bedById[row.bed_id].bed_code),
    }));
}

async function handleBookingEditPreview(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug   = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId    = String(body.booking_id   || '').trim();
  const bookingCode  = String(body.booking_code || '').trim();
  const editType     = String(body.edit_type || '').trim().toLowerCase();
  const reason       = String(body.reason || '').trim().slice(0, 500) || null;

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (!EDIT_PREVIEW_VALID_TYPES.includes(editType)) {
    return send400(res, 'edit_type must be one of: contact, dates, package, guests');
  }

  const actorId   = user ? user.staff_user_id : 'dev-edit-preview-local';
  const actorRole = user ? user.role          : 'operator';

  const auditBase = {
    ts:            new Date().toISOString(),
    intent:        'api:booking_edit_preview',
    category:      'booking_edit_preview',
    preview_only:  true,
    would_mutate:  false,
    client_slug:   clientSlug,
    booking_id:    bookingId || null,
    booking_code:  bookingCode || null,
    edit_type:     editType,
    reason,
    staff_user_id: actorId,
    staff_role:    actorRole,
  };

  let bookingRow, sourceBeds, svcRows;
  try {
    const result = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      const booking = bookingRes.rows[0] || null;
      if (!booking) return { bookingRow: null, sourceBeds: [], svcRows: [] };
      const bedsRes = await pg.query(MOVE_WRITE_SOURCE_BEDS_SQL, [clientSlug, booking.booking_id]);
      const svc = await loadBookingServiceRecords(pg, clientSlug, booking.booking_code);
      return { bookingRow: booking, sourceBeds: bedsRes.rows, svcRows: svc.rows };
    });
    bookingRow = result.bookingRow;
    sourceBeds = result.sourceBeds;
    svcRows    = result.svcRows;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'edit preview query failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, {
      success: false,
      error: 'booking not found',
      preview_only: true,
      would_mutate: false,
    });
  }

  bookingRow._client_slug = clientSlug;
  const currentGuests = Math.max(1, Number(bookingRow.guest_count) || 1);
  const baseResp = {
    preview_only: true,
    would_mutate: false,
    payment_mutation: false,
    stripe_mutation: false,
    edit_type: editType,
    booking: editPreviewBookingSummary(bookingRow),
  };

  if (editType === 'contact') {
    const guestName = body.guest_name != null ? String(body.guest_name).trim() : bookingRow.guest_name;
    const phone     = body.phone != null ? String(body.phone).trim() : (bookingRow.phone || '');
    const email     = body.email != null ? String(body.email).trim() : (bookingRow.email || '');
    if (!editPreviewLightNameOk(guestName)) return send400(res, 'guest_name is too long');
    if (!editPreviewLightPhoneOk(phone)) return send400(res, 'phone is too long');
    if (!editPreviewLightEmailOk(email)) return send400(res, 'email format is invalid');

    const current = {
      guest_name: bookingRow.guest_name,
      phone: bookingRow.phone || null,
      email: bookingRow.email || null,
    };
    const proposed = { guest_name: guestName, phone: phone || null, email: email || null };
    const invoice_preview = editPreviewBuildInvoicePreview(bookingRow, svcRows, {}, false);
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, can_apply: true, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      ...baseResp,
      success: true,
      can_apply: true,
      current,
      proposed,
      pricing_impact: { payment_mutation: false, stripe_mutation: false, no_pricing_change: true },
      invoice_preview,
      message: 'Edit preview calculated. No changes were saved.',
      elapsed_ms: elapsed,
    });
  }

  if (editType === 'dates') {
    const checkIn  = String(body.check_in  || '').trim();
    const checkOut = String(body.check_out || '').trim();
    if (!checkIn || !checkOut) return send400(res, 'check_in and check_out are required (YYYY-MM-DD)');
    if (!DATE_RE.test(checkIn) || !DATE_RE.test(checkOut)) return send400(res, 'check_in and check_out must be YYYY-MM-DD');
    if (!parseCalendarDate(checkIn) || !parseCalendarDate(checkOut)) return send400(res, 'check_in and check_out must be valid dates');
    if (checkOut <= checkIn) return send400(res, 'check_out must be after check_in');

    const currentNights  = movePreviewNights(bookingRow.check_in, bookingRow.check_out);
    const proposedNights = movePreviewNights(checkIn, checkOut);
    const current = {
      check_in: bookingRow.check_in,
      check_out: bookingRow.check_out,
      nights: currentNights,
      assigned_beds: sourceBeds.map((b) => b.bed_code),
    };
    const proposed = {
      check_in: checkIn,
      check_out: checkOut,
      nights: proposedNights,
      nights_delta: proposedNights != null && currentNights != null ? proposedNights - currentNights : null,
      assigned_beds: sourceBeds.map((b) => b.bed_code),
    };

    let conflicts = [];
    let requires_manual_review = false;
    let reviewReason = null;

    if (sourceBeds.length === 0) {
      requires_manual_review = true;
      reviewReason = 'no_active_assignments';
    } else {
      try {
        const avail = await withPgClient(async (pg) => {
          const assignRes = await pg.query(MOVE_TARGETS_RANGE_ASSIGNMENTS_SQL, [clientSlug, checkIn, checkOut]);
          let bedNotSellable = false;
          for (const bed of sourceBeds) {
            const bedRes = await pg.query(MOVE_PREVIEW_BED_BY_ID_SQL, [clientSlug, bed.bed_id]);
            const bedRow = bedRes.rows[0];
            if (bedRow && (bedRow.active === false || bedRow.sellable === false)) {
              bedNotSellable = true;
            }
          }
          return { assignmentRows: assignRes.rows, bedNotSellable };
        });
        conflicts = editPreviewDatesBuildConflicts(
          avail.assignmentRows,
          bookingRow.booking_id,
          checkIn,
          checkOut,
          sourceBeds
        );
        if (avail.bedNotSellable) {
          requires_manual_review = true;
          reviewReason = reviewReason || 'bed_not_sellable';
        }
      } catch (err) {
        appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
        return sendJSON(res, 500, { success: false, error: 'availability check failed', detail: err.message });
      }
    }

    const can_apply = conflicts.length === 0 && !requires_manual_review;
    const pricingAffects = proposed.nights_delta !== 0;
    const invoice_preview = editPreviewBuildInvoicePreview(
      bookingRow,
      svcRows,
      { check_in: checkIn, check_out: checkOut },
      pricingAffects
    );
    if (pricingAffects && invoice_preview.requires_reprice) {
      invoice_preview.nights_delta = proposed.nights_delta;
    }

    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      can_apply,
      conflict_count: conflicts.length,
      elapsed_ms: elapsed,
    });

    return sendJSON(res, 200, {
      ...baseResp,
      success: true,
      can_apply,
      requires_manual_review,
      reason: reviewReason,
      current,
      proposed,
      conflicts,
      pricing_impact: {
        requires_reprice: pricingAffects,
        nights_delta: proposed.nights_delta,
        payment_mutation: false,
        stripe_mutation: false,
      },
      invoice_preview,
      message: can_apply
        ? 'Edit preview calculated. No changes were saved.'
        : (conflicts.length
          ? 'Proposed dates conflict with other assignments. No changes were saved.'
          : 'Manual review required for proposed dates. No changes were saved.'),
      elapsed_ms: elapsed,
    });
  }

  if (editType === 'package') {
    const packageCodeRaw = body.package_code != null ? String(body.package_code).trim().toLowerCase() : '';
    if (!packageCodeRaw) return send400(res, 'package_code is required');
    if (!editPreviewIsValidPackage(packageCodeRaw, bookingRow.package_code)) {
      return send400(res, 'package_code is not a recognized package');
    }
    const storedPackage = editPreviewPackageStorageCode(packageCodeRaw);

    const current = { package_code: bookingRow.package_code || null };
    const proposed = { package_code: storedPackage };
    const pricingAffects = editPreviewPackageStorageCode(bookingRow.package_code) !== storedPackage;
    const invoice_preview = editPreviewBuildInvoicePreview(
      bookingRow,
      svcRows,
      { package_code: storedPackage },
      pricingAffects
    );

    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, can_apply: true, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      ...baseResp,
      success: true,
      can_apply: true,
      current,
      proposed,
      pricing_impact: {
        package_changed: pricingAffects,
        payment_mutation: false,
        stripe_mutation: false,
      },
      invoice_preview,
      message: 'Edit preview calculated. No changes were saved.',
      elapsed_ms: elapsed,
    });
  }

  // edit_type === 'guests'
  const guestCountRaw = body.guest_count;
  if (guestCountRaw == null || guestCountRaw === '') return send400(res, 'guest_count is required');
  const guestCount = Number(guestCountRaw);
  if (!Number.isFinite(guestCount) || guestCount < 1) return send400(res, 'guest_count must be at least 1');
  if (guestCount > currentGuests) {
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, can_apply: false, reason: 'guest_increase_not_supported', elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      ...baseResp,
      success: true,
      can_apply: false,
      reason: 'guest_increase_not_supported',
      current: { guest_count: currentGuests },
      proposed: { guest_count: guestCount },
      message: 'Guest count increases are not supported in preview. No changes were saved.',
      elapsed_ms: elapsed,
    });
  }

  const release = editPreviewGuestBedRelease(sourceBeds, currentGuests, guestCount);
  if (release.blocked) {
    return send400(res, release.reason || 'invalid guest_count');
  }

  const current = { guest_count: currentGuests, assigned_beds: sourceBeds.map((b) => b.bed_code) };
  const proposed = {
    guest_count: guestCount,
    release_booking_bed_ids: release.release_booking_bed_ids || [],
    released_beds: release.released_beds || [],
    remaining_beds: release.remaining_beds || [],
  };

  if (release.requires_manual_review) {
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, can_apply: false, requires_manual_review: true, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      ...baseResp,
      success: true,
      can_apply: false,
      requires_manual_review: true,
      reason: release.reason,
      current,
      proposed,
      message: 'Not enough assignment rows to release beds cleanly. Manual review required. No changes were saved.',
      elapsed_ms: elapsed,
    });
  }

  const pricingAffects = guestCount !== currentGuests;
  const invoice_preview = editPreviewBuildInvoicePreview(
    bookingRow,
    svcRows,
    { guest_count: guestCount },
    pricingAffects
  );

  const elapsed = Date.now() - started;
  appendAuditLog({ ...auditBase, success: true, can_apply: true, elapsed_ms: elapsed });
  return sendJSON(res, 200, {
    ...baseResp,
    success: true,
    can_apply: true,
    current,
    proposed,
    bed_release: release.changed ? {
      from: release.from,
      to: release.to,
      release_count: release.release_count,
      release_booking_bed_ids: release.release_booking_bed_ids,
      released_beds: release.released_beds,
      remaining_beds: release.remaining_beds,
    } : null,
    pricing_impact: {
      guest_count_delta: guestCount - currentGuests,
      payment_mutation: false,
      stripe_mutation: false,
    },
    invoice_preview,
    message: 'Edit preview calculated. No changes were saved.',
    elapsed_ms: elapsed,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 10.5b–10.5e — Booking field edit write (contact, package, dates, guest decrease; no env gate)
//
// POST /staff/bookings/edit
//
// contact: guest_name/phone/email. package/dates: repriced expected invoice.
// guests: decrease guest_count + DELETE last N booking_beds rows only.
// No guest increase, payments, service records, Stripe, n8n, or WhatsApp.
// ─────────────────────────────────────────────────────────────────────────────

async function handleBookingEditWritePackage(
  res, body, auditBase, started, actorLabel, clientSlug, bookingId, bookingCode
) {
  const packageCodeRaw = body.package_code != null ? String(body.package_code).trim().toLowerCase() : '';
  if (!packageCodeRaw) return send400(res, 'package_code is required');
  const storedPackage = editPreviewPackageStorageCode(packageCodeRaw);

  const auditResponse = {
    actor: actorLabel,
    reason: auditBase.reason,
    idempotency_key: auditBase.idempotency_key,
  };

  let bookingRow, svcRows;
  try {
    const loaded = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      const booking = bookingRes.rows[0] || null;
      if (!booking) return { bookingRow: null, svcRows: [] };
      const svc = await loadBookingServiceRecords(pg, clientSlug, booking.booking_code);
      return { bookingRow: booking, svcRows: svc.rows };
    });
    bookingRow = loaded.bookingRow;
    svcRows = loaded.svcRows;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'edit write query failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found', updated: false, would_mutate: false });
  }

  if (!editPreviewIsValidPackage(packageCodeRaw, bookingRow.package_code)) {
    return send400(res, 'package_code is not a recognized package');
  }

  bookingRow._client_slug = clientSlug;
  const currentPkg = editPreviewPackageStorageCode(bookingRow.package_code);
  const before = editWritePackageSnapshot(bookingRow);

  if (currentPkg === storedPackage) {
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, updated: false, idempotent: true, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      success: true,
      updated: false,
      idempotent: true,
      edit_type: 'package',
      booking: editWritePackageBookingSummary(bookingRow),
      before,
      after: before,
      invoice_impact: editWriteInvoiceImpactFromPreview(null, false),
      audit: auditResponse,
      message: 'Booking package already matches the requested package_code.',
      elapsed_ms: elapsed,
    });
  }

  const pricingAffects = true;
  const invoice_preview = editPreviewBuildInvoicePreview(
    bookingRow,
    svcRows,
    { package_code: storedPackage },
    pricingAffects
  );
  const invoice_impact = editWriteInvoiceImpactFromPreview(invoice_preview, true);

  if (invoice_preview.requires_reprice &&
      (invoice_preview.proposed == null || invoice_preview.proposed.total_amount_cents == null)) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: false,
      error: 'package_reprice_calculation_unavailable',
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 400, {
      success: false,
      error: 'package_reprice_calculation_unavailable',
      edit_type: 'package',
      updated: false,
      would_mutate: false,
      before: { package_code: bookingRow.package_code || null },
      proposed: { package_code: storedPackage },
      invoice_impact,
      invoice_preview,
      message: 'Package change could not be calculated. No changes were made.',
      elapsed_ms: elapsed,
    });
  }

  const proposedTotals = invoice_preview.proposed || {};
  const totalCents = proposedTotals.total_amount_cents;
  const balanceDue = proposedTotals.balance_due_cents != null ? proposedTotals.balance_due_cents : 0;

  const quote = editPreviewTryQuote(
    clientSlug,
    bookingRow.check_in,
    bookingRow.check_out,
    Number(bookingRow.guest_count) || 1,
    storedPackage
  );
  const metadataPatch = (quote && quote.success)
    ? JSON.stringify({ quote_snapshot: quote })
    : '{}';

  try {
    const updatedRow = await withPgClient(async (pg) => {
      await pg.query('BEGIN');
      try {
        const upd = await pg.query(EDIT_WRITE_PACKAGE_UPDATE_SQL, [
          clientSlug,
          bookingRow.booking_id,
          storedPackage,
          totalCents,
          balanceDue,
          metadataPatch,
        ]);
        if (!upd.rows[0]) {
          await pg.query('ROLLBACK');
          return null;
        }
        await pg.query('COMMIT');
        return upd.rows[0];
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });

    if (!updatedRow) {
      appendAuditLog({ ...auditBase, success: false, error: 'update_failed', elapsed_ms: Date.now() - started });
      return sendJSON(res, 500, { success: false, error: 'package update failed', updated: false });
    }

    const after = editWritePackageSnapshot(updatedRow);
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      updated: true,
      before,
      after,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      updated: true,
      edit_type: 'package',
      booking: editWritePackageBookingSummary(updatedRow),
      before,
      after,
      invoice_impact,
      invoice_preview,
      audit: auditResponse,
      message: 'Booking package updated. Expected invoice amounts recalculated. No payment, bed, service, Stripe, n8n, or WhatsApp changes were made.',
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'package update failed', detail: err.message, updated: false });
  }
}

async function handleBookingEditWriteDates(
  res, body, auditBase, started, actorLabel, clientSlug, bookingId, bookingCode
) {
  const checkIn  = String(body.check_in  || '').trim();
  const checkOut = String(body.check_out || '').trim();
  if (!checkIn || !checkOut) return send400(res, 'check_in and check_out are required (YYYY-MM-DD)');
  if (!DATE_RE.test(checkIn) || !DATE_RE.test(checkOut)) return send400(res, 'check_in and check_out must be YYYY-MM-DD');
  if (!parseCalendarDate(checkIn) || !parseCalendarDate(checkOut)) return send400(res, 'check_in and check_out must be valid dates');
  if (checkOut <= checkIn) return send400(res, 'check_out must be after check_in');

  const auditResponse = {
    actor: actorLabel,
    reason: auditBase.reason,
    idempotency_key: auditBase.idempotency_key,
  };

  let bookingRow, sourceBeds, svcRows;
  try {
    const loaded = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      const booking = bookingRes.rows[0] || null;
      if (!booking) return { bookingRow: null, sourceBeds: [], svcRows: [] };
      const bedsRes = await pg.query(MOVE_WRITE_SOURCE_BEDS_SQL, [clientSlug, booking.booking_id]);
      const svc = await loadBookingServiceRecords(pg, clientSlug, booking.booking_code);
      return { bookingRow: booking, sourceBeds: bedsRes.rows, svcRows: svc.rows };
    });
    bookingRow = loaded.bookingRow;
    sourceBeds = loaded.sourceBeds;
    svcRows = loaded.svcRows;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'edit write query failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found', updated: false, would_mutate: false });
  }

  bookingRow._client_slug = clientSlug;
  const before = editWriteDatesSnapshot(bookingRow);
  const currentNights = before.nights;
  const proposedNights = movePreviewNights(checkIn, checkOut);
  const currentView = {
    check_in: bookingRow.check_in,
    check_out: bookingRow.check_out,
    nights: currentNights,
    assigned_beds: sourceBeds.map((b) => b.bed_code),
  };
  const proposedView = {
    check_in: checkIn,
    check_out: checkOut,
    nights: proposedNights,
    nights_delta: proposedNights != null && currentNights != null ? proposedNights - currentNights : null,
    assigned_beds: sourceBeds.map((b) => b.bed_code),
  };

  if (editWriteDatesFieldsMatch(before, checkIn, checkOut)) {
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, updated: false, idempotent: true, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      success: true,
      updated: false,
      idempotent: true,
      edit_type: 'dates',
      booking: editPreviewBookingSummary(bookingRow),
      before: currentView,
      after: currentView,
      invoice_impact: editWriteInvoiceImpactFromPreview(null, false),
      audit: auditResponse,
      message: 'Booking dates already match the requested check-in and check-out.',
      elapsed_ms: elapsed,
    });
  }

  let avail;
  try {
    avail = await withPgClient(async (pg) =>
      editWriteDatesEvaluateAvailability(pg, clientSlug, bookingRow, sourceBeds, checkIn, checkOut)
    );
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'availability check failed', detail: err.message });
  }

  const can_apply = avail.conflicts.length === 0 && !avail.requires_manual_review;
  const pricingAffects = proposedView.nights_delta !== 0;
  const invoice_preview = editPreviewBuildInvoicePreview(
    bookingRow,
    svcRows,
    { check_in: checkIn, check_out: checkOut },
    pricingAffects
  );
  const invoice_impact = editWriteInvoiceImpactFromPreview(invoice_preview, pricingAffects);

  if (!can_apply) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      can_apply: false,
      conflict_count: avail.conflicts.length,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      can_apply: false,
      updated: false,
      would_mutate: false,
      edit_type: 'dates',
      requires_manual_review: !!avail.requires_manual_review,
      reason: avail.reason,
      before: currentView,
      proposed: proposedView,
      conflicts: avail.conflicts,
      invoice_impact,
      invoice_preview,
      audit: auditResponse,
      message: avail.conflicts.length
        ? 'Proposed dates conflict with other assignments. No changes were made.'
        : 'Manual review required for proposed dates. No changes were made.',
      elapsed_ms: elapsed,
    });
  }

  const pricingBlock = editWriteShouldBlockPricingWrite(
    invoice_preview,
    pricingAffects,
    'dates_reprice_calculation_unavailable'
  );
  if (pricingBlock.block) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: false,
      error: pricingBlock.error,
      elapsed_ms: elapsed,
    });
    const blockMsg = pricingBlock.error === 'package_required_for_long_stay'
      ? 'Stays of 6 nights or longer require a package before dates can be saved.'
      : 'Date change could not be calculated. No changes were made.';
    return sendJSON(res, 400, {
      success: false,
      error: pricingBlock.error,
      edit_type: 'dates',
      updated: false,
      would_mutate: false,
      before: currentView,
      proposed: proposedView,
      invoice_impact,
      invoice_preview,
      message: blockMsg,
      elapsed_ms: elapsed,
    });
  }

  const proposedTotals = invoice_preview.proposed || {};
  const totalCents = proposedTotals.total_amount_cents;
  const balanceDue = proposedTotals.balance_due_cents != null ? proposedTotals.balance_due_cents : 0;
  const pkgForQuote = bookingRow.package_code
    ? String(bookingRow.package_code).trim().toLowerCase()
    : null;
  const quote = pkgForQuote
    ? editPreviewTryQuote(
      clientSlug,
      checkIn,
      checkOut,
      Number(bookingRow.guest_count) || 1,
      pkgForQuote
    )
    : null;
  const metadataPatch = (quote && quote.success)
    ? JSON.stringify({ quote_snapshot: quote })
    : '{}';

  try {
    const updated = await withPgClient(async (pg) => {
      await pg.query('BEGIN');
      try {
        const bookingUpd = await pg.query(EDIT_WRITE_DATES_UPDATE_BOOKING_SQL, [
          clientSlug,
          bookingRow.booking_id,
          checkIn,
          checkOut,
          totalCents,
          balanceDue,
          metadataPatch,
        ]);
        if (!bookingUpd.rows[0]) {
          await pg.query('ROLLBACK');
          return null;
        }
        const bedsUpd = await pg.query(EDIT_WRITE_DATES_UPDATE_BEDS_SQL, [
          clientSlug,
          bookingRow.booking_id,
          checkIn,
          checkOut,
        ]);
        await pg.query('COMMIT');
        return { booking: bookingUpd.rows[0], beds: bedsUpd.rows };
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });

    if (!updated) {
      appendAuditLog({ ...auditBase, success: false, error: 'update_failed', elapsed_ms: Date.now() - started });
      return sendJSON(res, 500, { success: false, error: 'dates update failed', updated: false });
    }

    const afterView = {
      check_in: updated.booking.check_in,
      check_out: updated.booking.check_out,
      nights: movePreviewNights(updated.booking.check_in, updated.booking.check_out),
      assigned_beds: updated.beds.map((b) => b.bed_code),
      booking_beds: updated.beds,
    };
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      updated: true,
      before,
      after: afterView,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      updated: true,
      can_apply: true,
      edit_type: 'dates',
      booking: editPreviewBookingSummary(updated.booking),
      before: currentView,
      after: afterView,
      invoice_impact,
      invoice_preview,
      audit: auditResponse,
      message: 'Booking dates updated. Bed assignments and expected invoice amounts recalculated. No payment, service, Stripe, n8n, or WhatsApp changes were made.',
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'dates update failed', detail: err.message, updated: false });
  }
}

async function handleBookingEditWriteGuests(
  res, body, auditBase, started, actorLabel, clientSlug, bookingId, bookingCode
) {
  const guestCountRaw = body.guest_count;
  if (guestCountRaw == null || guestCountRaw === '') return send400(res, 'guest_count is required');
  const guestCount = Number(guestCountRaw);
  if (!Number.isFinite(guestCount) || Math.floor(guestCount) !== guestCount) {
    return send400(res, 'guest_count must be an integer');
  }
  if (guestCount < 1) return send400(res, 'guest_count must be at least 1');

  const auditResponse = {
    actor: actorLabel,
    reason: auditBase.reason,
    idempotency_key: auditBase.idempotency_key,
  };

  let bookingRow, sourceBeds, svcRows;
  try {
    const loaded = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      const booking = bookingRes.rows[0] || null;
      if (!booking) return { bookingRow: null, sourceBeds: [], svcRows: [] };
      const bedsRes = await pg.query(MOVE_WRITE_SOURCE_BEDS_SQL, [clientSlug, booking.booking_id]);
      const svc = await loadBookingServiceRecords(pg, clientSlug, booking.booking_code);
      return { bookingRow: booking, sourceBeds: bedsRes.rows, svcRows: svc.rows };
    });
    bookingRow = loaded.bookingRow;
    sourceBeds = loaded.sourceBeds;
    svcRows = loaded.svcRows;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'edit write query failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found', updated: false, would_mutate: false });
  }

  const currentGuests = Math.max(1, Number(bookingRow.guest_count) || 1);
  if (guestCount > currentGuests) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: false,
      error: 'guest_increase_not_supported',
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 400, {
      success: false,
      error: 'guest_increase_not_supported',
      edit_type: 'guests',
      updated: false,
      would_mutate: false,
      current: { guest_count: currentGuests },
      proposed: { guest_count: guestCount },
      message: 'Guest count increases are not supported.',
      elapsed_ms: elapsed,
    });
  }

  bookingRow._client_slug = clientSlug;
  const release = editPreviewGuestBedRelease(sourceBeds, currentGuests, guestCount);
  if (release.blocked) {
    return send400(res, release.reason || 'invalid guest_count');
  }

  const currentView = {
    guest_count: currentGuests,
    assigned_beds: sourceBeds.map((b) => b.bed_code),
  };

  if (!release.changed) {
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, updated: false, idempotent: true, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      success: true,
      updated: false,
      idempotent: true,
      edit_type: 'guests',
      booking: editPreviewBookingSummary(bookingRow),
      before: currentView,
      after: currentView,
      invoice_impact: editWriteInvoiceImpactFromPreview(null, false),
      audit: auditResponse,
      message: 'Booking guest count already matches the requested guest_count.',
      elapsed_ms: elapsed,
    });
  }

  if (release.requires_manual_review) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      can_apply: false,
      requires_manual_review: true,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      can_apply: false,
      updated: false,
      would_mutate: false,
      requires_manual_review: true,
      reason: release.reason,
      edit_type: 'guests',
      before: currentView,
      proposed: {
        guest_count: guestCount,
        release_booking_bed_ids: [],
        released_beds: [],
        remaining_beds: sourceBeds.map((b) => b.bed_code),
      },
      audit: auditResponse,
      message: 'Not enough assignment rows to release beds cleanly. No changes were made.',
      elapsed_ms: elapsed,
    });
  }

  const pricingAffects = true;
  const invoice_preview = editPreviewBuildInvoicePreview(
    bookingRow,
    svcRows,
    { guest_count: guestCount },
    pricingAffects
  );
  const invoice_impact = editWriteInvoiceImpactFromPreview(invoice_preview, true);
  const needs_refund = invoice_impact.needs_refund === true;
  const refund_review_needed = invoice_impact.refund_review_needed === true;

  const pricingBlock = editWriteShouldBlockPricingWrite(
    invoice_preview,
    true,
    'guests_reprice_calculation_unavailable'
  );
  if (pricingBlock.block) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: false,
      error: pricingBlock.error,
      elapsed_ms: elapsed,
    });
    const blockMsg = pricingBlock.error === 'package_required_for_long_stay'
      ? 'Stays of 6 nights or longer require a package before guest count can be saved.'
      : 'Guest reduction could not be calculated. No changes were made.';
    return sendJSON(res, 400, {
      success: false,
      error: pricingBlock.error,
      edit_type: 'guests',
      updated: false,
      would_mutate: false,
      before: currentView,
      proposed: { guest_count: guestCount },
      invoice_impact,
      invoice_preview,
      message: blockMsg,
      elapsed_ms: elapsed,
    });
  }

  const proposedTotals = invoice_preview.proposed || {};
  const totalCents = proposedTotals.total_amount_cents;
  const balanceDue = proposedTotals.balance_due_cents != null ? proposedTotals.balance_due_cents : 0;
  const releaseIds = release.release_booking_bed_ids || [];

  const pkgForQuote = bookingRow.package_code
    ? String(bookingRow.package_code).trim().toLowerCase()
    : null;
  const quote = pkgForQuote
    ? editPreviewTryQuote(
      clientSlug,
      bookingRow.check_in,
      bookingRow.check_out,
      guestCount,
      pkgForQuote
    )
    : null;
  const metadataPatch = (quote && quote.success)
    ? JSON.stringify({ quote_snapshot: quote })
    : '{}';

  try {
    const updated = await withPgClient(async (pg) => {
      await pg.query('BEGIN');
      try {
        const bookingUpd = await pg.query(EDIT_WRITE_GUESTS_UPDATE_BOOKING_SQL, [
          clientSlug,
          bookingRow.booking_id,
          guestCount,
          totalCents,
          balanceDue,
          metadataPatch,
        ]);
        if (!bookingUpd.rows[0]) {
          await pg.query('ROLLBACK');
          return null;
        }
        const bedsDel = await pg.query(EDIT_WRITE_GUESTS_DELETE_BEDS_SQL, [
          clientSlug,
          bookingRow.booking_id,
          releaseIds,
        ]);
        if (bedsDel.rowCount !== releaseIds.length) {
          await pg.query('ROLLBACK');
          return { mismatch: true };
        }
        await pg.query('COMMIT');
        return { booking: bookingUpd.rows[0], released: bedsDel.rows };
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });

    if (updated && updated.mismatch) {
      appendAuditLog({ ...auditBase, success: false, error: 'bed_release_mismatch', elapsed_ms: Date.now() - started });
      return sendJSON(res, 500, {
        success: false,
        error: 'bed_release_mismatch',
        updated: false,
        message: 'Bed release did not complete as expected. No changes were made.',
      });
    }

    if (!updated) {
      appendAuditLog({ ...auditBase, success: false, error: 'update_failed', elapsed_ms: Date.now() - started });
      return sendJSON(res, 500, { success: false, error: 'guests update failed', updated: false });
    }

    const remainRes = await withPgClient(async (pg) => {
      const bedsRes = await pg.query(MOVE_WRITE_SOURCE_BEDS_SQL, [clientSlug, bookingRow.booking_id]);
      return bedsRes.rows;
    });
    const afterView = {
      guest_count: Number(updated.booking.guest_count),
      assigned_beds: remainRes.map((b) => b.bed_code),
      released_beds: (updated.released || []).map((b) => b.bed_code),
      remaining_beds: remainRes.map((b) => b.bed_code),
    };
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      updated: true,
      release_count: release.release_count,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      updated: true,
      can_apply: true,
      edit_type: 'guests',
      booking: editPreviewBookingSummary(updated.booking),
      before: currentView,
      after: afterView,
      bed_release: {
        from: release.from,
        to: release.to,
        release_count: release.release_count,
        release_booking_bed_ids: releaseIds,
        released_beds: release.released_beds,
        remaining_beds: release.remaining_beds,
      },
      invoice_impact,
      invoice_preview,
      needs_refund,
      refund_review_needed,
      audit: auditResponse,
      message: needs_refund
        ? 'Guest count reduced and beds released. Expected invoice recalculated; refund or credit review may be required. No payment, service, Stripe, n8n, or WhatsApp changes were made.'
        : 'Guest count reduced and beds released. Expected invoice amounts recalculated. No payment, service, Stripe, n8n, or WhatsApp changes were made.',
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'guests update failed', detail: err.message, updated: false });
  }
}

async function handleBookingEditWrite(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug     = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId      = String(body.booking_id   || '').trim();
  const bookingCode    = String(body.booking_code || '').trim();
  const editType       = String(body.edit_type || '').trim().toLowerCase();
  const idempotencyKey = String(body.idempotency_key || '').trim();
  const reason         = String(body.reason || '').trim().slice(0, 500) || null;

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (!editType) return send400(res, 'edit_type is required');
  if (!idempotencyKey) return send400(res, 'idempotency_key is required');

  const actorId    = user ? user.staff_user_id : 'dev-edit-write-local';
  const actorRole  = user ? user.role          : 'operator';
  const actorLabel = user ? (user.email || user.staff_user_id) : actorId;

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'api:booking_edit',
    category:        'booking_edit_write',
    preview_only:    false,
    would_mutate:    true,
    client_slug:     clientSlug,
    booking_id:      bookingId || null,
    booking_code:    bookingCode || null,
    edit_type:       editType,
    idempotency_key: idempotencyKey,
    staff_user_id:   actorId,
    staff_role:      actorRole,
    reason,
  };

  if (!EDIT_WRITE_SUPPORTED_TYPES.includes(editType)) {
    appendAuditLog({
      ...auditBase,
      success: false,
      error: 'edit_type_not_supported',
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 400, {
      success: false,
      error: 'edit_type_not_supported',
      edit_type: editType,
      updated: false,
      would_mutate: false,
    });
  }

  if (editType === 'package') {
    return handleBookingEditWritePackage(
      res, body, auditBase, started, actorLabel, clientSlug, bookingId, bookingCode
    );
  }

  if (editType === 'dates') {
    return handleBookingEditWriteDates(
      res, body, auditBase, started, actorLabel, clientSlug, bookingId, bookingCode
    );
  }

  if (editType === 'guests') {
    return handleBookingEditWriteGuests(
      res, body, auditBase, started, actorLabel, clientSlug, bookingId, bookingCode
    );
  }

  const contactPatch = editWriteParseContactPatch(body);
  if (contactPatch.guest_name === null) {
    return send400(res, 'guest_name cannot be null');
  }
  const patchKeys = Object.keys(contactPatch);
  if (patchKeys.length === 0) {
    return send400(res, 'at least one of guest_name, phone, or email is required');
  }
  if (contactPatch.guest_name !== undefined) {
    if (!contactPatch.guest_name) return send400(res, 'guest_name must not be empty');
    if (!editPreviewLightNameOk(contactPatch.guest_name)) return send400(res, 'guest_name is too long');
  }
  if (contactPatch.phone !== undefined && contactPatch.phone !== null) {
    if (!editPreviewLightPhoneOk(contactPatch.phone)) return send400(res, 'phone is too long');
  }
  if (contactPatch.email !== undefined && contactPatch.email !== null) {
    if (!editPreviewLightEmailOk(contactPatch.email)) return send400(res, 'email format is invalid');
  }

  let bookingRow;
  try {
    bookingRow = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      return bookingRes.rows[0] || null;
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'edit write query failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found', updated: false, would_mutate: false });
  }

  const before = editWriteContactSnapshot(bookingRow);
  const after  = editWriteMergeContactFields(bookingRow, contactPatch);
  const auditResponse = {
    actor: actorLabel,
    reason,
    idempotency_key: idempotencyKey,
  };
  const invoiceImpact = {
    requires_reprice: false,
    payment_mutation: false,
    stripe_mutation: false,
  };

  if (editWriteContactFieldsMatch(before, after)) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      updated: false,
      idempotent: true,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      updated: false,
      idempotent: true,
      edit_type: 'contact',
      booking: editWriteContactBookingSummary(bookingRow),
      before,
      after,
      invoice_impact: invoiceImpact,
      audit: auditResponse,
      message: 'Booking contact details already match the requested values.',
      elapsed_ms: elapsed,
    });
  }

  try {
    const updatedRow = await withPgClient(async (pg) => {
      await pg.query('BEGIN');
      try {
        const upd = await pg.query(EDIT_WRITE_CONTACT_UPDATE_SQL, [
          clientSlug,
          bookingRow.booking_id,
          after.guest_name,
          after.phone,
          after.email,
        ]);
        if (!upd.rows[0]) {
          await pg.query('ROLLBACK');
          return null;
        }
        await pg.query('COMMIT');
        return upd.rows[0];
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });

    if (!updatedRow) {
      appendAuditLog({ ...auditBase, success: false, error: 'update_failed', elapsed_ms: Date.now() - started });
      return sendJSON(res, 500, { success: false, error: 'contact update failed', updated: false });
    }

    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      updated: true,
      before,
      after: editWriteContactSnapshot(updatedRow),
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      updated: true,
      edit_type: 'contact',
      booking: editWriteContactBookingSummary(updatedRow),
      before,
      after: editWriteContactSnapshot(updatedRow),
      invoice_impact: invoiceImpact,
      audit: auditResponse,
      message: 'Booking contact details updated. No payment, bed, service, Stripe, n8n, or WhatsApp changes were made.',
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'contact update failed', detail: err.message, updated: false });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 10.5f — Booking cancel (Staff Portal internal write only)
//
// POST /staff/bookings/cancel
//
// Sets booking status cancelled and DELETEs booking_beds for client/booking.
// No payment paid-truth mutation, no booking_service_records, no Stripe/WhatsApp/n8n.
// ─────────────────────────────────────────────────────────────────────────────

const BOOKING_CANCEL_UPDATE_STATUS_SQL = `
UPDATE bookings b
SET status = 'cancelled'::booking_status
FROM clients c
WHERE b.client_id = c.id
  AND c.slug = $1
  AND b.id::text = $2
RETURNING
  b.id::text        AS booking_id,
  b.booking_code,
  b.status::text    AS status,
  b.guest_name,
  b.check_in::text   AS check_in,
  b.check_out::text  AS check_out
`;

const BOOKING_CANCEL_DELETE_BEDS_SQL = `
DELETE FROM booking_beds bb
USING clients c, bookings b
WHERE bb.client_id = c.id
  AND b.client_id = c.id
  AND bb.booking_id = b.id
  AND c.slug = $1
  AND b.id::text = $2
`;

const BOOKING_CANCEL_COUNT_BEDS_SQL = `
SELECT COUNT(*)::int AS c
FROM booking_beds bb
INNER JOIN bookings b ON b.id = bb.booking_id
INNER JOIN clients c ON c.id = b.client_id
WHERE c.slug = $1
  AND b.id::text = $2
`;

function bookingStatusIsCancelled(status) {
  const s = String(status || '').toLowerCase();
  return s === 'cancelled' || s === 'canceled' || s === 'expired';
}

function bookingCancelSnapshot(row) {
  return {
    booking_id:   row.booking_id,
    booking_code: row.booking_code,
    status:       row.status,
    guest_name:   row.guest_name,
    check_in:     row.check_in,
    check_out:    row.check_out,
  };
}

async function handleBookingCancel(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug     = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId      = String(body.booking_id   || '').trim();
  const bookingCode    = String(body.booking_code || '').trim();
  const idempotencyKey = String(body.idempotency_key || '').trim();
  const reason         = String(body.reason || '').trim().slice(0, 500) || 'Cancelled from Staff Portal';

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (!idempotencyKey) return send400(res, 'idempotency_key is required');

  const actorId    = user ? user.staff_user_id : 'dev-cancel-local';
  const actorRole  = user ? user.role          : 'operator';
  const actorLabel = user ? (user.email || user.staff_user_id) : actorId;

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'api:booking_cancel',
    category:        'booking_cancel_write',
    preview_only:    false,
    would_mutate:    true,
    client_slug:     clientSlug,
    booking_id:      bookingId || null,
    booking_code:    bookingCode || null,
    idempotency_key: idempotencyKey,
    staff_user_id:   actorId,
    staff_role:      actorRole,
    reason,
  };

  const auditResponse = {
    actor: actorLabel,
    reason,
    idempotency_key: idempotencyKey,
  };

  let bookingRow;
  try {
    bookingRow = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      return bookingRes.rows[0] || null;
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'cancel query failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found', cancelled: false, would_mutate: false });
  }

  const before = bookingCancelSnapshot(bookingRow);

  if (bookingStatusIsCancelled(bookingRow.status)) {
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, cancelled: false, idempotent: true, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      success: true,
      cancelled: false,
      idempotent: true,
      booking: bookingCancelSnapshot(bookingRow),
      before,
      after: before,
      beds_released_count: 0,
      audit: auditResponse,
      message: 'Booking is already cancelled. No changes were made.',
      elapsed_ms: elapsed,
    });
  }

  try {
    const result = await withPgClient(async (pg) => {
      await pg.query('BEGIN');
      try {
        const countRes = await pg.query(BOOKING_CANCEL_COUNT_BEDS_SQL, [
          clientSlug,
          bookingRow.booking_id,
        ]);
        const bedsBefore = countRes.rows[0] ? Number(countRes.rows[0].c) : 0;

        const delRes = await pg.query(BOOKING_CANCEL_DELETE_BEDS_SQL, [
          clientSlug,
          bookingRow.booking_id,
        ]);
        const bedsReleased = delRes.rowCount != null ? delRes.rowCount : bedsBefore;

        const upd = await pg.query(BOOKING_CANCEL_UPDATE_STATUS_SQL, [
          clientSlug,
          bookingRow.booking_id,
        ]);
        if (!upd.rows[0]) {
          await pg.query('ROLLBACK');
          return null;
        }
        await pg.query('COMMIT');
        return { updatedRow: upd.rows[0], bedsReleased };
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });

    if (!result) {
      appendAuditLog({ ...auditBase, success: false, error: 'update_failed', elapsed_ms: Date.now() - started });
      return sendJSON(res, 500, { success: false, error: 'cancel update failed', cancelled: false });
    }

    const after = bookingCancelSnapshot(result.updatedRow);
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      cancelled: true,
      beds_released_count: result.bedsReleased,
      before,
      after,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      cancelled: true,
      idempotent: false,
      booking: after,
      before,
      after,
      beds_released_count: result.bedsReleased,
      audit: auditResponse,
      message: 'Booking cancelled and assigned beds released. No refund, Stripe, WhatsApp, or n8n action was taken.',
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'cancel failed', detail: err.message, cancelled: false });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// ─────────────────────────────────────────────────────────────────────────────
// Phase 10.6h — Create internal conversation linked to booking (no message send)
//
// POST /staff/bookings/create-conversation
// ─────────────────────────────────────────────────────────────────────────────

const BOOKING_LINKED_CONVERSATION_SQL = `
SELECT conv.id::text AS conversation_id
FROM conversations conv
INNER JOIN clients c ON c.id = conv.client_id
WHERE c.slug = $1
  AND (
    conv.current_hold_booking_id = $2::uuid
    OR (
      $3::text IS NOT NULL
      AND btrim($3::text) <> ''
      AND conv.phone = $3::text
      AND conv.client_id = c.id
    )
  )
ORDER BY
  CASE WHEN conv.current_hold_booking_id = $2::uuid THEN 0 ELSE 1 END,
  conv.updated_at DESC
LIMIT 1
`;

function staffManualConversationPhone(bookingRow) {
  const phone = String(bookingRow.phone || '').trim();
  if (phone) return phone;
  return `staff:booking:${bookingRow.booking_id}`;
}

async function handleBookingCreateConversation(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug     = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId      = String(body.booking_id   || '').trim();
  const bookingCode    = String(body.booking_code || '').trim();
  const idempotencyKey = String(body.idempotency_key || '').trim();
  const reason         = body.reason != null ? String(body.reason).trim().slice(0, 500) : 'Created from booking drawer';

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (!idempotencyKey) return send400(res, 'idempotency_key is required');

  const actorId = user ? user.staff_user_id : 'dev-booking-conv-local';
  const auditBase = {
    ts:               new Date().toISOString(),
    intent:           'api:booking_create_conversation',
    category:         'booking_conversation_write',
    client_slug:      clientSlug,
    booking_id:       bookingId || null,
    booking_code:     bookingCode || null,
    idempotency_key:  idempotencyKey,
    staff_user_id:    actorId,
  };

  let bookingRow;
  let existingConvId = null;
  let convCreated = false;
  try {
    const loaded = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode],
      );
      if (bookingRes.rows.length === 0) return { booking: null };

      const bk = bookingRes.rows[0];
      const phone = staffManualConversationPhone(bk);
      const existing = await pg.query(BOOKING_LINKED_CONVERSATION_SQL, [
        clientSlug,
        bk.booking_id,
        phone,
      ]);
      if (existing.rows.length > 0) {
        const convId = existing.rows[0].conversation_id;
        await pg.query(
          `UPDATE conversations
              SET current_hold_booking_id = COALESCE(current_hold_booking_id, $2::uuid),
                  updated_at = NOW()
            WHERE id = $1::uuid`,
          [convId, bk.booking_id],
        );
        return { booking: bk, existingConvId: convId };
      }

      const clientRes = await pg.query(
        'SELECT id FROM clients WHERE slug = $1 LIMIT 1',
        [clientSlug],
      );
      if (clientRes.rows.length === 0) return { booking: bk, clientMissing: true };

      const metadata = {
        source:           'staff_manual',
        channel:          'manual',
        idempotency_key:  idempotencyKey,
        reason,
        created_from:     'booking_drawer',
      };
      const sessionState = {
        source:                'staff_manual',
        channel:               'manual',
        current_hold_booking_code: bk.booking_code,
      };

      const ins = await pg.query(
        `INSERT INTO conversations (
           client_id,
           phone,
           display_name,
           status,
           bot_mode,
           current_hold_booking_id,
           conversation_stage,
           metadata,
           session_state
         ) VALUES (
           $1, $2, $3, 'open'::conversation_status, 'staff'::bot_mode, $4::uuid,
           'staff_manual', $5::jsonb, $6::jsonb
         )
         ON CONFLICT (client_id, phone) DO UPDATE SET
           current_hold_booking_id = COALESCE(conversations.current_hold_booking_id, EXCLUDED.current_hold_booking_id),
           display_name = COALESCE(EXCLUDED.display_name, conversations.display_name),
           metadata = conversations.metadata || EXCLUDED.metadata,
           updated_at = NOW()
         RETURNING id::text AS conversation_id`,
        [
          clientRes.rows[0].id,
          phone,
          bk.guest_name || null,
          bk.booking_id,
          JSON.stringify(metadata),
          JSON.stringify(sessionState),
        ],
      );

      return { booking: bk, conversationId: ins.rows[0].conversation_id, created: true };
    });

    bookingRow = loaded.booking;
    if (!bookingRow) {
      appendAuditLog({ ...auditBase, success: false, error: 'not_found', elapsed_ms: Date.now() - started });
      return sendJSON(res, 404, { success: false, error: 'booking not found' });
    }
    if (loaded.clientMissing) {
      appendAuditLog({ ...auditBase, success: false, error: 'client_not_found', elapsed_ms: Date.now() - started });
      return sendJSON(res, 404, { success: false, error: 'client not found' });
    }

    if (loaded.existingConvId) {
      existingConvId = loaded.existingConvId;
      convCreated = false;
    } else {
      existingConvId = loaded.conversationId;
      convCreated = !!loaded.created;
    }
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'conversation create failed', detail: err.message });
  }

  const idempotent = !convCreated;
  const elapsed = Date.now() - started;
  appendAuditLog({
    ...auditBase,
    success:          true,
    conversation_id:  existingConvId,
    idempotent,
    created:          convCreated,
    elapsed_ms:       elapsed,
  });

  return sendJSON(res, 200, {
    success:          true,
    conversation_id:  existingConvId,
    booking_code:     bookingRow.booking_code,
    idempotent,
    existing:         idempotent,
    created:          convCreated,
    no_message_sent:  true,
    no_whatsapp:      true,
    n8n_called:       false,
    send_mutation:    false,
  });
}

// Phase 10.6b — Record cash payment (payments INSERT only; no Stripe/link/WA/n8n)
//
// POST /staff/bookings/record-cash-payment
// ─────────────────────────────────────────────────────────────────────────────

async function handleBookingRecordCashPayment(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug     = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId      = String(body.booking_id   || '').trim();
  const bookingCode    = String(body.booking_code || '').trim();
  const idempotencyKey = String(body.idempotency_key || '').trim();
  const note           = body.note != null ? String(body.note).trim().slice(0, 500) : null;
  const paymentDateIn  = String(body.payment_date || '').trim();
  const amountCents    = Math.floor(Number(body.amount_cents));

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (!idempotencyKey) return send400(res, 'idempotency_key is required');
  if (!amountCents || amountCents <= 0) return send400(res, 'amount_cents must be greater than zero');

  let paymentDate = paymentDateIn;
  if (!paymentDate || !DATE_RE.test(paymentDate) || !parseCalendarDate(paymentDate)) {
    paymentDate = new Date().toISOString().slice(0, 10);
  }

  const actorId    = user ? user.staff_user_id : 'dev-cash-pay-local';
  const actorRole  = user ? user.role          : 'operator';
  const actorLabel = user ? (user.email || user.staff_user_id) : actorId;

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'api:booking_record_cash_payment',
    category:        'booking_cash_payment_write',
    client_slug:     clientSlug,
    booking_id:      bookingId || null,
    booking_code:    bookingCode || null,
    amount_cents:    amountCents,
    idempotency_key: idempotencyKey,
    staff_user_id:   actorId,
    staff_role:      actorRole,
  };

  let bookingRow;
  try {
    bookingRow = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      return bookingRes.rows[0] || null;
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'booking lookup failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found' });
  }

  if (bookingStatusIsCancelled(bookingRow.status)) {
    return sendJSON(res, 400, {
      success: false,
      error: 'booking_not_active',
      message: 'Cannot record cash payment on a cancelled or expired booking.',
    });
  }

  const pmMeta = {
    source: 'staff_cash',
    method: 'cash',
    idempotency_key: idempotencyKey,
    note: note,
    payment_date: paymentDate,
    recorded_by: actorLabel,
    staff_portal: true,
  };

  try {
    const result = await withPgClient(async (pg) => {
      const idem = await pg.query(
        `SELECT p.id::text AS payment_id, p.status::text AS payment_status,
                p.amount_due_cents, p.amount_paid_cents, p.paid_at, p.metadata
           FROM payments p
          WHERE p.booking_id = $1::uuid
            AND p.metadata->>'idempotency_key' = $2
          LIMIT 1`,
        [bookingRow.booking_id, idempotencyKey]
      );
      if (idem.rows[0]) {
        const sumIdem = await pg.query(
          `SELECT COALESCE(SUM(amount_paid_cents), 0)::int AS total
             FROM payments
            WHERE booking_id = $1::uuid AND status = 'paid'::payment_record_status`,
          [bookingRow.booking_id]
        );
        const paidTotal = Number(sumIdem.rows[0].total || 0);
        const bkTotal = Number(bookingRow.total_amount_cents || 0);
        return {
          idempotent: true,
          payment: idem.rows[0],
          booking_paid_cents: paidTotal,
          balance_due_cents: bkTotal > 0 ? Math.max(bkTotal - paidTotal, 0) : 0,
        };
      }

      const clientRes = await pg.query(
        'SELECT id FROM clients WHERE slug = $1 LIMIT 1',
        [clientSlug]
      );
      const clientId = clientRes.rows[0] && clientRes.rows[0].id;
      if (!clientId) throw new Error('client not found');

      await pg.query('BEGIN');
      try {
        const paidAt = paymentDate + 'T12:00:00.000Z';
        const ins = await pg.query(
          `INSERT INTO payments (
             client_id, booking_id, status, payment_kind, currency,
             amount_due_cents, amount_paid_cents, paid_at, metadata
           ) VALUES (
             $1, $2::uuid, 'paid'::payment_record_status, 'full_amount'::payment_kind, 'EUR',
             $3, $3, $4::timestamptz, $5::jsonb
           )
           RETURNING id::text AS payment_id, status::text AS payment_status,
                     amount_due_cents, amount_paid_cents, paid_at`,
          [clientId, bookingRow.booking_id, amountCents, paidAt, JSON.stringify(pmMeta)]
        );
        const payment = ins.rows[0];

        const sumRes = await pg.query(
          `SELECT COALESCE(SUM(amount_paid_cents), 0)::int AS total
             FROM payments
            WHERE booking_id = $1::uuid
              AND status = 'paid'::payment_record_status`,
          [bookingRow.booking_id]
        );
        const newBkPaid = Number(sumRes.rows[0].total || 0);
        const bkTotal = Number(bookingRow.total_amount_cents || 0);
        const newBalance = bkTotal > 0 ? Math.max(bkTotal - newBkPaid, 0) : 0;
        let newBkPayStatus = bookingRow.payment_status;
        if (bkTotal > 0 && newBalance === 0) newBkPayStatus = 'paid';
        else if (newBkPaid > 0 && newBkPayStatus === 'not_requested') newBkPayStatus = 'deposit_paid';

        await pg.query(
          `UPDATE bookings
              SET amount_paid_cents = $1,
                  balance_due_cents = $2,
                  payment_status = $3::payment_status
            WHERE id = $4::uuid`,
          [newBkPaid, newBalance, newBkPayStatus, bookingRow.booking_id]
        );

        await pg.query('COMMIT');
        return { idempotent: false, payment: payment, booking_paid_cents: newBkPaid, balance_due_cents: newBalance };
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });

    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      idempotent: !!result.idempotent,
      payment_id: result.payment && result.payment.payment_id,
      elapsed_ms: elapsed,
    });

    return sendJSON(res, 200, {
      success: true,
      idempotent: !!result.idempotent,
      payment: result.payment,
      booking_paid_cents: result.booking_paid_cents,
      balance_due_cents: result.balance_due_cents,
      message: result.idempotent
        ? 'Cash payment already recorded (idempotent).'
        : 'Cash payment recorded. No Stripe, payment link, WhatsApp, or n8n action was taken.',
      no_stripe: true,
      no_whatsapp: true,
      no_n8n: true,
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'cash payment failed', detail: err.message });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 10.6c — Generate Stripe payment link for booking balance (no send)
//
// POST /staff/bookings/generate-payment-link
//
// Creates checkout_created payment row + Stripe Checkout Session for current
// invoice total minus paid ledger total. No paid-truth, no WhatsApp, no n8n.
// ─────────────────────────────────────────────────────────────────────────────

async function handleBookingGeneratePaymentLink(req, res, user) {
  const started = Date.now();

  if (!STAFF_ACTIONS_ENABLED) {
    return sendJSON(res, 403, {
      success: false,
      error: 'Staff write actions are disabled. Set STAFF_ACTIONS_ENABLED=true to enable.',
      staff_actions_enabled: false,
    });
  }
  if (!STRIPE_LINKS_ENABLED) {
    return sendJSON(res, 403, {
      success: false,
      error: 'Stripe link creation is disabled. Set STRIPE_LINKS_ENABLED=true to enable.',
      stripe_links_enabled: false,
    });
  }
  if (!STRIPE_SECRET_KEY) {
    return sendJSON(res, 503, {
      success: false,
      error: 'STRIPE_SECRET_KEY not configured.',
      no_db_write: true,
    });
  }
  if (!stripeCheckoutRedirectUrlsConfigured()) {
    return sendJSON(res, 503, {
      success: false,
      error: 'STRIPE_CHECKOUT_SUCCESS_URL and STRIPE_CHECKOUT_CANCEL_URL must be set in env.',
      no_db_write: true,
    });
  }

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug     = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId      = String(body.booking_id   || '').trim();
  const bookingCode    = String(body.booking_code || '').trim();
  const idempotencyKey = String(body.idempotency_key || '').trim();
  const reason         = body.reason != null ? String(body.reason).trim().slice(0, 500) : null;

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (!idempotencyKey) return send400(res, 'idempotency_key is required');

  const actorId = user ? user.staff_user_id : 'dev-pay-link-local';
  const auditBase = {
    ts: new Date().toISOString(),
    intent: 'api:booking_generate_payment_link',
    category: 'booking_payment_link_write',
    client_slug: clientSlug,
    booking_id: bookingId || null,
    booking_code: bookingCode || null,
    idempotency_key: idempotencyKey,
    staff_user_id: actorId,
  };

  let bookingRow;
  let svcRows = [];
  let paymentRows = [];
  let transferRows = [];
  try {
    const loaded = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode],
      );
      const bk = bookingRes.rows[0] || null;
      if (!bk) return { booking: null, svc: [], payments: [], transfers: [] };
      const svc = await loadBookingServiceRecords(pg, clientSlug, bk.booking_code);
      const pm = await pg.query(BOOKING_PAYMENTS_LEDGER_SQL, [clientSlug, bk.booking_code]);
      const transfers = await listBookingTransfersForBooking(pg, {
        client_slug: clientSlug,
        booking_id: bk.booking_id,
      });
      return { booking: bk, svc: svc.rows, payments: pm.rows, transfers };
    });
    bookingRow = loaded.booking;
    svcRows = loaded.svc;
    paymentRows = loaded.payments;
    transferRows = loaded.transfers || [];
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'booking lookup failed', detail: err.message });
  }

  if (!bookingRow) {
    return sendJSON(res, 404, { success: false, error: 'booking not found' });
  }

  if (bookingStatusIsCancelled(bookingRow.status)) {
    return sendJSON(res, 400, {
      success: false,
      error: 'booking_not_active',
      message: 'Cannot create a payment link on a cancelled or expired booking.',
    });
  }

  const ledger = bookingLedgerBalanceFromRows(bookingRow, svcRows, paymentRows, transferRows);
  const amountDueCents = ledger.balance_due_cents;

  if (ledger.needs_refund) {
    return sendJSON(res, 409, {
      success: false,
      error: 'refund_review_needed',
      message: 'Refund / credit review needed before creating a payment link.',
    });
  }

  if (amountDueCents == null || amountDueCents <= 0) {
    return sendJSON(res, 200, {
      success: true,
      created: false,
      idempotent: false,
      error: 'no_payment_due',
      booking_code: bookingRow.booking_code,
      amount_due_cents: 0,
      message: 'No outstanding balance due.',
    });
  }

  const existingByKey = paymentRows.find((pr) => {
    const md = pr.metadata;
    let parsed = md;
    if (typeof md === 'string') {
      try { parsed = JSON.parse(md); } catch (_) { parsed = {}; }
    }
    return parsed && parsed.idempotency_key === idempotencyKey && pr.checkout_url;
  });
  if (existingByKey) {
    return sendJSON(res, 200, {
      success: true,
      created: false,
      idempotent: true,
      booking_code: bookingRow.booking_code,
      amount_due_cents: Number(existingByKey.amount_due_cents || amountDueCents),
      payment_status: 'payment_link_created',
      payment_link_url: existingByKey.checkout_url,
      checkout_url: existingByKey.checkout_url,
      stripe_mutation: false,
      send_mutation: false,
      message: 'Payment link already created (idempotent). Nothing was sent to the guest.',
      elapsed_ms: Date.now() - started,
    });
  }

  const activeLink = ledgerActivePaymentLinkRow(paymentRows, ledger);
  if (activeLink && activeLink.checkout_url) {
    return sendJSON(res, 200, {
      success: true,
      created: false,
      idempotent: true,
      booking_code: bookingRow.booking_code,
      amount_due_cents: amountDueCents,
      payment_status: 'payment_link_created',
      payment_link_url: activeLink.checkout_url,
      checkout_url: activeLink.checkout_url,
      payment_id: activeLink.payment_id,
      stripe_mutation: false,
      send_mutation: false,
      message: 'Payment link already exists for this balance. Nothing was sent to the guest.',
      elapsed_ms: Date.now() - started,
    });
  }

  let stripe;
  try {
    stripe = require('stripe')(STRIPE_SECRET_KEY);
  } catch (e) {
    return sendJSON(res, 500, { success: false, error: 'Failed to load Stripe SDK: ' + e.message, no_db_write: true });
  }

  const pmMeta = {
    source: 'staff_payment_link',
    method: 'payment_link',
    idempotency_key: idempotencyKey,
    booking_code: bookingRow.booking_code,
    amount_due_cents: amountDueCents,
    reason: reason,
    created_by: actorId,
    staff_portal: true,
    phase: '10.6c',
  };

  let paymentId;
  try {
    paymentId = await withPgClient(async (pg) => {
      const idem = await pg.query(
        `SELECT p.id::text AS payment_id, p.status::text AS payment_status,
                p.amount_due_cents, p.checkout_url, p.metadata
           FROM payments p
          WHERE p.booking_id = $1::uuid
            AND p.metadata->>'idempotency_key' = $2
          LIMIT 1`,
        [bookingRow.booking_id, idempotencyKey],
      );
      if (idem.rows[0] && idem.rows[0].checkout_url) {
        return { reuse: true, row: idem.rows[0] };
      }

      const clientRes = await pg.query('SELECT id FROM clients WHERE slug = $1 LIMIT 1', [clientSlug]);
      const clientId = clientRes.rows[0] && clientRes.rows[0].id;
      if (!clientId) throw new Error('client not found');

      const ins = await pg.query(
        `INSERT INTO payments (
           client_id, booking_id, status, payment_kind, currency,
           amount_due_cents, amount_paid_cents, metadata
         ) VALUES (
           $1, $2::uuid, 'draft'::payment_record_status, 'full_amount'::payment_kind, 'EUR',
           $3, 0, $4::jsonb
         )
         RETURNING id::text AS payment_id`,
        [clientId, bookingRow.booking_id, amountDueCents, JSON.stringify(pmMeta)],
      );
      return { reuse: false, payment_id: ins.rows[0].payment_id };
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'payment draft insert failed', detail: err.message });
  }

  if (paymentId.reuse) {
    return sendJSON(res, 200, {
      success: true,
      created: false,
      idempotent: true,
      booking_code: bookingRow.booking_code,
      amount_due_cents: Number(paymentId.row.amount_due_cents || amountDueCents),
      payment_status: 'payment_link_created',
      payment_link_url: paymentId.row.checkout_url,
      checkout_url: paymentId.row.checkout_url,
      stripe_mutation: false,
      send_mutation: false,
      message: 'Payment link already created (idempotent). Nothing was sent to the guest.',
      elapsed_ms: Date.now() - started,
    });
  }

  const newPaymentId = paymentId.payment_id;
  const productName = `Booking ${bookingRow.booking_code || newPaymentId} \u2014 ${bookingRow.guest_name || 'Guest'}`;
  const productDesc = `Outstanding balance | ${bookingRow.check_in || ''} \u2013 ${bookingRow.check_out || ''} | ${clientSlug}`;

  let session;
  try {
    session = await stripe.checkout.sessions.create({
      mode: 'payment',
      currency: 'eur',
      line_items: [{
        price_data: {
          currency: 'eur',
          product_data: { name: productName, description: productDesc },
          unit_amount: amountDueCents,
        },
        quantity: 1,
      }],
      metadata: {
        client_slug: clientSlug,
        booking_id: bookingRow.booking_id,
        booking_code: bookingRow.booking_code || '',
        payment_id: newPaymentId,
        payment_kind: 'full_amount',
        source: 'staff_payment_link',
        idempotency_key: idempotencyKey,
      },
      success_url: stripeCheckoutSessionSuccessUrl(),
      cancel_url: stripeCheckoutSessionCancelUrl(),
    });
  } catch (stripeErr) {
    return sendJSON(res, 500, {
      success: false,
      error: 'Stripe session creation failed: ' + stripeErr.message,
      no_db_write: true,
    });
  }

  const expiresAt = session.expires_at
    ? new Date(session.expires_at * 1000).toISOString()
    : null;

  try {
    await withPgClient(async (pg) => {
      await pg.query(
        `UPDATE payments
            SET status                     = 'checkout_created'::payment_record_status,
                stripe_checkout_session_id = $1,
                checkout_url               = $2,
                expires_at                 = $3,
                metadata                   = metadata || $4::jsonb
          WHERE id = $5`,
        [
          session.id,
          session.url,
          expiresAt,
          JSON.stringify({
            stripe_session_id: session.id,
            stripe_livemode: session.livemode,
            stripe_payment_status: session.payment_status,
            payment_link_url: session.url,
          }),
          newPaymentId,
        ],
      );
    });
  } catch (dbErr) {
    appendAuditLog({
      ...auditBase,
      success: false,
      error: 'stripe_session_created_but_db_update_failed: ' + dbErr.message,
      payment_id: newPaymentId,
      session_id: session.id,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 500, {
      success: false,
      error: 'Stripe session created but DB update failed: ' + dbErr.message,
      checkout_url: session.url,
    });
  }

  const elapsed = Date.now() - started;
  appendAuditLog({
    ...auditBase,
    success: true,
    payment_id: newPaymentId,
    amount_due_cents: amountDueCents,
    stripe_session_id: session.id,
    elapsed_ms: elapsed,
    stripe_called: true,
    whatsapp_called: false,
    n8n_called: false,
    send_mutation: false,
  });

  return sendJSON(res, 200, {
    success: true,
    created: true,
    idempotent: false,
    booking_code: bookingRow.booking_code,
    amount_due_cents: amountDueCents,
    payment_status: 'payment_link_created',
    payment_link_url: session.url,
    checkout_url: session.url,
    payment_id: newPaymentId,
    stripe_checkout_session_id: session.id,
    stripe_mutation: true,
    send_mutation: false,
    no_payment_truth_recorded: true,
    no_whatsapp: true,
    no_n8n: true,
    message: 'Payment link created. Nothing was sent to the guest.',
    elapsed_ms: elapsed,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 10.6f — Cancel unpaid payment link (payments status only; no paid truth)
//
// POST /staff/bookings/cancel-payment-link
// ─────────────────────────────────────────────────────────────────────────────

async function handleBookingCancelPaymentLink(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug     = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId      = String(body.booking_id   || '').trim();
  const bookingCode    = String(body.booking_code || '').trim();
  const paymentId      = String(body.payment_id   || '').trim();
  const idempotencyKey = String(body.idempotency_key || '').trim();
  const reason         = body.reason != null ? String(body.reason).trim().slice(0, 500) : 'Cancelled from Staff Portal';

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!paymentId) return send400(res, 'payment_id is required');
  if (!UUID_VALIDATE_RE.test(paymentId)) return send400(res, 'payment_id must be a valid UUID');
  if (!idempotencyKey) return send400(res, 'idempotency_key is required');

  const actorId    = user ? user.staff_user_id : 'dev-cancel-link-local';
  const actorRole  = user ? user.role          : 'operator';
  const actorLabel = user ? (user.email || user.staff_user_id) : actorId;

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'api:booking_cancel_payment_link',
    category:        'booking_payment_link_cancel',
    client_slug:     clientSlug,
    booking_id:      bookingId || null,
    booking_code:    bookingCode || null,
    payment_id:      paymentId,
    idempotency_key: idempotencyKey,
    staff_user_id:   actorId,
    staff_role:      actorRole,
  };

  try {
    const result = await withPgClient(async (pg) => {
      const payRes = await pg.query(
        `SELECT p.id::text AS payment_id, p.status::text AS payment_status,
                p.amount_due_cents, p.amount_paid_cents, p.checkout_url, p.metadata,
                p.booking_id::text AS row_booking_id,
                b.booking_code
           FROM payments p
          INNER JOIN bookings b ON b.id = p.booking_id
          INNER JOIN clients c ON c.id = b.client_id
          WHERE p.id = $1::uuid
            AND c.slug = $2
          LIMIT 1`,
        [paymentId, clientSlug]
      );
      const row = payRes.rows[0];
      if (!row) return { error: 'payment_not_found' };

      if (bookingId && row.row_booking_id !== bookingId) return { error: 'payment_booking_mismatch' };
      if (bookingCode) {
        const codeRes = await pg.query(
          `SELECT b.id::text AS booking_id, b.booking_code
             FROM bookings b
            INNER JOIN clients c ON c.id = b.client_id
            WHERE c.slug = $1 AND b.booking_code = $2
            LIMIT 1`,
          [clientSlug, bookingCode]
        );
        const bk = codeRes.rows[0];
        if (!bk) return { error: 'booking_not_found' };
        if (bk.booking_id !== row.row_booking_id) return { error: 'payment_booking_mismatch' };
      }

      const st = String(row.payment_status || '').toLowerCase();
      if (st === 'cancelled' || st === 'canceled') {
        return { idempotent: true, payment: row, cancelled: true };
      }

      if (paymentLedgerIsPaidStatus(st) || Number(row.amount_paid_cents || 0) > 0) {
        return { error: 'payment_already_paid' };
      }
      if (!paymentLedgerCanCancelLinkRow(row)) {
        return { error: 'payment_not_cancellable' };
      }

      const cancelMeta = {
        cancel_idempotency_key: idempotencyKey,
        cancelled_at: new Date().toISOString(),
        cancelled_by: actorLabel,
        cancel_reason: reason,
        staff_portal: true,
        phase: '10.6f',
      };

      const upd = await pg.query(
        `UPDATE payments
            SET status = 'cancelled'::payment_record_status,
                metadata = COALESCE(metadata, '{}'::jsonb) || $2::jsonb
          WHERE id = $1::uuid
          RETURNING id::text AS payment_id, status::text AS payment_status,
                    amount_due_cents, amount_paid_cents, checkout_url, metadata`,
        [paymentId, JSON.stringify(cancelMeta)]
      );
      return { idempotent: false, payment: upd.rows[0], cancelled: true };
    });

    if (result.error === 'payment_not_found') {
      return sendJSON(res, 404, { success: false, error: 'payment not found' });
    }
    if (result.error === 'booking_not_found') {
      return sendJSON(res, 404, { success: false, error: 'booking not found' });
    }
    if (result.error === 'payment_booking_mismatch') {
      return sendJSON(res, 400, { success: false, error: 'payment does not belong to this booking' });
    }
    if (result.error === 'payment_already_paid') {
      return sendJSON(res, 400, {
        success: false,
        error: 'payment_already_paid',
        message: 'Cannot cancel a paid payment row.',
      });
    }
    if (result.error === 'payment_not_cancellable') {
      return sendJSON(res, 400, {
        success: false,
        error: 'payment_not_cancellable',
        message: 'Only unpaid checkout/payment-link rows can be cancelled.',
      });
    }

    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      idempotent: !!result.idempotent,
      elapsed_ms: elapsed,
    });

    return sendJSON(res, 200, {
      success: true,
      idempotent: !!result.idempotent,
      cancelled: true,
      payment: result.payment,
      message: result.idempotent
        ? 'Payment link already cancelled (idempotent).'
        : 'Payment link cancelled. Row preserved for audit. No refund, paid totals, Stripe expire, WhatsApp, or n8n action was taken.',
      no_stripe: true,
      no_whatsapp: true,
      no_n8n: true,
      no_paid_truth_mutation: true,
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'cancel payment link failed', detail: err.message });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 10.6a — Staff add service record (booking_service_records INSERT only)
//
// POST /staff/bookings/add-service
//
// No Stripe link, no payments paid-truth mutation, no booking_beds, no WhatsApp/n8n.
// ─────────────────────────────────────────────────────────────────────────────

const STAFF_ADDON_UI_SERVICE_TYPES = new Set([
  'wetsuit', 'soft_board', 'hard_board', 'surf_lesson', 'yoga', 'meals',
]);

const STAFF_ADDON_PRICING_CONFIG_PATH = path.join(
  __dirname, '..', 'config', 'clients', 'wolfhouse-somo.pricing.json'
);

function staffAddonLoadPricingConfig() {
  return JSON.parse(fs.readFileSync(STAFF_ADDON_PRICING_CONFIG_PATH, 'utf8'));
}

function staffAddonUiTypeLabel(uiType) {
  const m = {
    wetsuit: 'Wetsuit',
    soft_board: 'Soft board',
    hard_board: 'Hard board',
    surf_lesson: 'Surf lesson',
    yoga: 'Yoga',
    meals: 'Meal',
    meal: 'Meal',
  };
  return m[uiType] || uiType;
}

function staffAddonResolvePricing(uiServiceType, quantity, clientSlug) {
  const qty = Math.max(1, Math.floor(Number(quantity) || 1));
  if (!STAFF_ADDON_UI_SERVICE_TYPES.has(uiServiceType)) {
    return { ok: false, error: 'invalid service_type' };
  }
  if (clientSlug !== 'wolfhouse-somo') {
    return { ok: false, error: 'pricing not configured for client' };
  }

  let config;
  try {
    config = staffAddonLoadPricingConfig();
  } catch (err) {
    return { ok: false, error: 'pricing config unavailable', detail: err.message };
  }
  const addOns = config.add_ons || {};
  const warnings = [];

  if (uiServiceType === 'wetsuit') {
    const cfg = addOns.wetsuit_rental;
    const unit = cfg && cfg.price_cents ? Number(cfg.price_cents) : 500;
    return {
      ok: true,
      db_service_type: 'wetsuit',
      amount_due_cents: unit * qty,
      quantity: qty,
      pricing_addon_code: 'wetsuit_rental',
      unit_cents: unit,
      pricing_unit: 'per_day',
      metadata_extra: { rental_days: qty, staff_ui_service_type: uiServiceType },
      warnings,
    };
  }

  if (uiServiceType === 'soft_board') {
    const cfg = addOns.soft_top_rental;
    const unit = cfg && cfg.price_cents ? Number(cfg.price_cents) : 1500;
    return {
      ok: true,
      db_service_type: 'surfboard',
      amount_due_cents: unit * qty,
      quantity: qty,
      pricing_addon_code: 'soft_top_rental',
      unit_cents: unit,
      pricing_unit: 'per_day',
      metadata_extra: { rental_days: qty, board_variant: 'soft', staff_ui_service_type: uiServiceType },
      warnings: ['Recorded as surfboard with soft-top pricing.'],
    };
  }

  if (uiServiceType === 'hard_board') {
    const cfg = addOns.hard_board_rental;
    const unit = cfg && cfg.price_cents ? Number(cfg.price_cents) : 2000;
    return {
      ok: true,
      db_service_type: 'surfboard',
      amount_due_cents: unit * qty,
      quantity: qty,
      pricing_addon_code: 'hard_board_rental',
      unit_cents: unit,
      pricing_unit: 'per_day',
      metadata_extra: { rental_days: qty, board_variant: 'hard', staff_ui_service_type: uiServiceType },
      warnings: ['Recorded as surfboard with hard-board pricing.'],
    };
  }

  if (uiServiceType === 'surf_lesson') {
    if (qty === 1) {
      const cfg = addOns.surf_lesson_single;
      const unit = cfg && cfg.price_cents ? Number(cfg.price_cents) : 3500;
      return {
        ok: true,
        db_service_type: 'surf_lesson',
        amount_due_cents: unit,
        quantity: 1,
        pricing_addon_code: 'surf_lesson_single',
        unit_cents: unit,
        pricing_unit: 'per_lesson',
        metadata_extra: { staff_ui_service_type: uiServiceType },
        warnings,
      };
    }
    const cfg = addOns.surf_lesson_multi;
    const unit = cfg && cfg.price_cents_each ? Number(cfg.price_cents_each) : 3000;
    return {
      ok: true,
      db_service_type: 'surf_lesson',
      amount_due_cents: unit * qty,
      quantity: qty,
      pricing_addon_code: 'surf_lesson_multi',
      unit_cents: unit,
      pricing_unit: 'per_lesson',
      metadata_extra: { staff_ui_service_type: uiServiceType },
      warnings,
    };
  }

  if (uiServiceType === 'yoga') {
    const cfg = addOns.yoga_class;
    const unit = cfg && cfg.price_cents ? Number(cfg.price_cents) : 1500;
    return {
      ok: true,
      db_service_type: 'yoga',
      amount_due_cents: unit * qty,
      quantity: qty,
      pricing_addon_code: 'yoga_class',
      unit_cents: unit,
      pricing_unit: 'per_class',
      metadata_extra: { staff_ui_service_type: uiServiceType },
      warnings,
    };
  }

  if (uiServiceType === 'meals') {
    const cfg = addOns.meals || addOns.dinner_meal || addOns.meal;
    let unit = null;
    if (cfg && cfg.price_cents != null) unit = Number(cfg.price_cents);
    else if (cfg && cfg.price_eur != null) unit = Math.round(Number(cfg.price_eur) * 100);
    if (unit == null || !Number.isFinite(unit) || unit <= 0) {
      return {
        ok: false,
        error: 'Meals pricing is not configured in wolfhouse pricing config (add_ons.meals, add_ons.dinner_meal, or add_ons.meal with price_cents)',
      };
    }
    return {
      ok: true,
      db_service_type: 'meal',
      amount_due_cents: unit * qty,
      quantity: qty,
      pricing_addon_code: (cfg && cfg.code) || 'meals',
      unit_cents: unit,
      pricing_unit: 'per_meal',
      metadata_extra: { staff_ui_service_type: uiServiceType },
      warnings,
    };
  }

  return { ok: false, error: 'unsupported service_type' };
}

async function handleBookingAddService(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug     = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId      = String(body.booking_id   || '').trim();
  const bookingCode    = String(body.booking_code || '').trim();
  const uiServiceType  = String(body.service_type || '').trim().toLowerCase();
  const idempotencyKey = String(body.idempotency_key || '').trim();
  const note           = body.note != null ? String(body.note).trim().slice(0, 500) : null;
  const scheduleMode = String(body.schedule_mode || 'specific_date').trim().toLowerCase();
  const VALID_SCHEDULE_MODES = new Set(['specific_date', 'schedule_later', 'span_across_booking']);
  if (!VALID_SCHEDULE_MODES.has(scheduleMode)) {
    return send400(res, 'schedule_mode must be specific_date, schedule_later, or span_across_booking');
  }
  const serviceDateIn  = body.service_date != null && body.service_date !== ''
    ? String(body.service_date).trim()
    : '';

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (!uiServiceType) return send400(res, 'service_type is required');
  if (!idempotencyKey) return send400(res, 'idempotency_key is required');
  if (!STAFF_ADDON_UI_SERVICE_TYPES.has(uiServiceType)) {
    return send400(res, 'service_type must be one of: wetsuit, soft_board, hard_board, surf_lesson, yoga, meals');
  }

  const pricing = staffAddonResolvePricing(uiServiceType, body.quantity, clientSlug);
  if (!pricing.ok) {
    return send400(res, pricing.error || 'pricing failed', { detail: pricing.detail });
  }

  const actorId    = user ? user.staff_user_id : 'dev-add-service-local';
  const actorRole  = user ? user.role          : 'operator';
  const actorLabel = user ? (user.email || user.staff_user_id) : actorId;

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'api:booking_add_service',
    category:        'booking_add_service_write',
    client_slug:     clientSlug,
    booking_id:      bookingId || null,
    booking_code:    bookingCode || null,
    service_type:    uiServiceType,
    idempotency_key: idempotencyKey,
    staff_user_id:   actorId,
    staff_role:      actorRole,
  };

  let bookingRow;
  try {
    bookingRow = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      return bookingRes.rows[0] || null;
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'add service lookup failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found', created: false });
  }

  if (bookingStatusIsCancelled(bookingRow.status)) {
    return sendJSON(res, 400, {
      success: false,
      error: 'booking_not_active',
      message: 'Cannot add services to a cancelled or expired booking.',
      created: false,
    });
  }

  let unitDates;
  const unitQty = Math.max(1, Number(pricing.quantity) || 1);

  if (scheduleMode === 'schedule_later') {
    unitDates = Array(unitQty).fill(null);
  } else if (scheduleMode === 'span_across_booking') {
    const startDate = serviceDateIn || bookingRow.check_in || null;
    const dist = distributeSpanScheduleDates({
      quantity: unitQty,
      guestCount: Number(bookingRow.guest_count) || 1,
      checkIn: bookingRow.check_in,
      checkOut: bookingRow.check_out,
      startDate,
    });
    if (dist.error) {
      return send400(res, dist.error);
    }
    if (!dist.dates || dist.dates.length !== unitQty) {
      return send400(res, 'Could not distribute services across stay dates.');
    }
    unitDates = dist.dates;
  } else {
    let serviceDate = serviceDateIn;
    if (!serviceDate || !DATE_RE.test(serviceDate) || !parseCalendarDate(serviceDate)) {
      serviceDate = bookingRow.check_in || null;
    }
    if (!serviceDate) return send400(res, 'service_date is required (YYYY-MM-DD) or booking must have check_in');
    unitDates = Array(unitQty).fill(serviceDate);
  }

  const serviceMeta = {
    staff_portal: true,
    staff_ui_service_type: uiServiceType,
    schedule_mode: scheduleMode,
    pricing_addon_code: pricing.pricing_addon_code,
    pricing_unit: pricing.pricing_unit,
    unit_cents: pricing.unit_cents,
    idempotency_key: idempotencyKey,
    created_by: actorLabel,
    ...(pricing.metadata_extra || {}),
  };

  try {
    const result = await withPgClient(async (pg) => {
      const idem = await pg.query(
        `SELECT id::text AS id, service_type, quantity, amount_due_cents, service_date::text AS service_date
         FROM booking_service_records
         WHERE booking_id = $1::uuid
           AND (metadata->>'idempotency_key' = $2
                OR metadata->>'idempotency_key' LIKE $3)
         ORDER BY metadata->>'idempotency_key'`,
        [bookingRow.booking_id, idempotencyKey, `${idempotencyKey}-unit-%`]
      );
      if (idem.rows.length > 0) {
        return { idempotent: true, row: idem.rows[0], rows: idem.rows };
      }

      const unitQty = Math.max(1, Number(pricing.quantity) || 1);
      const unitCents = pricing.unit_cents;

      await pg.query('BEGIN');
      try {
        const insertedRows = [];
        for (let u = 0; u < unitQty; u++) {
          const unitKey = unitQty === 1 ? idempotencyKey : `${idempotencyKey}-unit-${u + 1}`;
          const unitMeta = {
            ...serviceMeta,
            idempotency_key: unitKey,
            unit_index: u + 1,
            unit_total: unitQty,
          };
          const unitServiceDate = unitDates[u];
          const ins = await pg.query(
            `INSERT INTO booking_service_records (
               client_slug, booking_id, booking_code, guest_name,
               service_type, service_date, quantity, status,
               amount_due_cents, amount_paid_cents, payment_status,
               source, notes, metadata
             ) VALUES (
               $1, $2::uuid, $3, $4,
               $5, $6::date, 1, 'requested',
               $7, 0, 'not_requested',
               'staff_manual', $8, $9::jsonb
             )
             RETURNING
               id::text AS service_record_id,
               service_type,
               service_date::text AS service_date,
               quantity,
               status,
               payment_status,
               amount_due_cents,
               amount_paid_cents,
               notes,
               metadata`,
            [
              clientSlug,
              bookingRow.booking_id,
              bookingRow.booking_code,
              bookingRow.guest_name,
              pricing.db_service_type,
              unitServiceDate,
              unitCents,
              note,
              JSON.stringify(unitMeta),
            ]
          );
          insertedRows.push(ins.rows[0]);
        }
        await pg.query('COMMIT');
        return { idempotent: false, row: insertedRows[0], rows: insertedRows };
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });

    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      created: !result.idempotent,
      idempotent: result.idempotent,
      service_record_id: result.row.service_record_id || result.row.id,
      elapsed_ms: elapsed,
    });

    const scheduleMsg = scheduleMode === 'schedule_later'
      ? ' Added as unscheduled service units.'
      : (scheduleMode === 'span_across_booking'
        ? ' Spread across stay dates as schedulable units.'
        : '');

    return sendJSON(res, 200, {
      success: true,
      created: !result.idempotent,
      idempotent: result.idempotent,
      service_record: result.row,
      service_records: result.rows || [result.row],
      units_created: result.idempotent ? (result.rows || [result.row]).length : (result.rows || []).length,
      schedule_mode: scheduleMode,
      pricing: {
        service_type: uiServiceType,
        db_service_type: pricing.db_service_type,
        quantity: pricing.quantity,
        amount_due_cents: pricing.amount_due_cents,
        unit_cents: pricing.unit_cents,
        pricing_unit: pricing.pricing_unit,
        warnings: pricing.warnings,
      },
      audit: { actor: actorLabel, idempotency_key: idempotencyKey },
      message: result.idempotent
        ? 'Service record already exists for this idempotency key.'
        : (pricing.quantity > 1
          ? `${pricing.quantity} schedulable service units added.${scheduleMsg} Running invoice will include the new add-ons. No Stripe link or payment was created.`
          : `Service record added.${scheduleMsg} Running invoice will include the new add-on. No Stripe link or payment was created.`),
      elapsed_ms: elapsed,
    });
  } catch (err) {
    if (isMissingBookingServiceRecordsTable(err)) {
      return sendJSON(res, 503, {
        success: false,
        error: 'booking_service_records table not available',
        created: false,
      });
    }
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'add service failed', detail: err.message, created: false });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// POST /staff/bookings/remove-service
//
// DELETE one booking_service_records row. No payments, Stripe, WhatsApp, n8n.
// ─────────────────────────────────────────────────────────────────────────────

async function handleBookingRemoveService(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug     = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId      = String(body.booking_id   || '').trim();
  const bookingCode    = String(body.booking_code || '').trim();
  const recordId       = String(body.booking_service_record_id || '').trim();
  let recordIds = [];
  if (Array.isArray(body.booking_service_record_ids)) {
    recordIds = body.booking_service_record_ids.map((id) => String(id || '').trim()).filter(Boolean);
  } else if (recordId) {
    recordIds = [recordId];
  }
  const idempotencyKey = String(body.idempotency_key || '').trim();
  const reason         = body.reason != null ? String(body.reason).trim().slice(0, 500) : null;

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (recordIds.length === 0) {
    return send400(res, 'booking_service_record_id or booking_service_record_ids is required');
  }
  for (const rid of recordIds) {
    if (!UUID_VALIDATE_RE.test(rid)) {
      return send400(res, 'each booking_service_record_id must be a valid UUID');
    }
  }
  if (!idempotencyKey) return send400(res, 'idempotency_key is required');

  const actorId    = user ? user.staff_user_id : 'dev-remove-service-local';
  const actorRole  = user ? user.role          : 'operator';
  const actorLabel = user ? (user.email || user.staff_user_id) : actorId;

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'api:booking_remove_service',
    category:        'booking_remove_service_write',
    client_slug:     clientSlug,
    booking_id:      bookingId || null,
    booking_code:    bookingCode || null,
    service_record_id: recordId,
    idempotency_key: idempotencyKey,
    staff_user_id:   actorId,
    staff_role:      actorRole,
  };

  let bookingRow;
  try {
    bookingRow = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? EDIT_PREVIEW_BOOKING_BY_ID_SQL : EDIT_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      return bookingRes.rows[0] || null;
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'remove add-on lookup failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found', removed: false });
  }

  if (bookingStatusIsCancelled(bookingRow.status)) {
    return sendJSON(res, 400, {
      success: false,
      error: 'booking_not_active',
      message: 'Cannot remove add-ons from a cancelled or expired booking.',
      removed: false,
    });
  }

  try {
    const result = await withPgClient(async (pg) => {
      const removedRows = [];
      let anyRemoved = false;
      for (const rid of recordIds) {
        const existing = await pg.query(
          `SELECT sr.id::text AS id, sr.booking_id::text AS booking_id, sr.service_type,
                  sr.quantity, sr.amount_due_cents
           FROM booking_service_records sr
           WHERE sr.id = $1::uuid AND sr.client_slug = $2
           LIMIT 1`,
          [rid, clientSlug],
        );
        const row = existing.rows[0];
        if (!row) continue;
        if (row.booking_id !== bookingRow.booking_id) {
          return { not_owned: true };
        }
        const del = await pg.query(
          `DELETE FROM booking_service_records
           WHERE id = $1::uuid AND client_slug = $2 AND booking_id = $3::uuid
           RETURNING id::text AS service_record_id, service_type, quantity, amount_due_cents`,
          [rid, clientSlug, bookingRow.booking_id],
        );
        if (del.rows.length > 0) {
          anyRemoved = true;
          removedRows.push(del.rows[0]);
        }
      }
      return {
        idempotent: !anyRemoved,
        removed: anyRemoved,
        removed_rows: removedRows,
        removed_count: removedRows.length,
        reason,
      };
    });

    if (result.not_owned) {
      appendAuditLog({ ...auditBase, success: false, error: 'record_not_on_booking', elapsed_ms: Date.now() - started });
      return sendJSON(res, 404, {
        success: false,
        error: 'add-on record not found on this booking',
        removed: false,
      });
    }

    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      removed: result.removed,
      removed_count: result.removed_count,
      idempotent: result.idempotent,
      elapsed_ms: elapsed,
    });

    return sendJSON(res, 200, {
      success: true,
      removed: result.removed,
      removed_count: result.removed_count || 0,
      idempotent: result.idempotent,
      service_record_ids: recordIds,
      removed_records: result.removed_rows || [],
      audit: { actor: actorLabel, idempotency_key: idempotencyKey, reason: reason || null },
      message: result.idempotent
        ? 'Selected service records were already removed.'
        : (result.removed_count > 1
          ? `${result.removed_count} services removed. Running invoice updated. No payment or Stripe changes were made.`
          : 'Add-on removed. Running invoice will no longer include this line. No payment or Stripe changes were made.'),
      elapsed_ms: elapsed,
    });
  } catch (err) {
    if (isMissingBookingServiceRecordsTable(err)) {
      return sendJSON(res, 503, {
        success: false,
        error: 'booking_service_records table not available',
        removed: false,
      });
    }
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'remove add-on failed', detail: err.message, removed: false });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Route: POST /staff/quote-preview  (Stage 8.4.4 — pure quote preview, no DB)
//
// Calls calculateWolfhouseQuote() with the request body. No DB reads or writes.
// No Stripe. No WhatsApp. No n8n.
// Does NOT require STAFF_ACTIONS_ENABLED or MANUAL_BOOKING_ENABLED.
// Requires auth (viewer+ when STAFF_AUTH_REQUIRED=true).
// ─────────────────────────────────────────────────────────────────────────────

async function handleQuotePreview(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug    = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const checkIn       = String(body.check_in    || '').trim();
  const checkOut      = String(body.check_out   || '').trim();
  const guestCount    = body.guest_count;
  const packageCode   = body.package_code   != null ? String(body.package_code).trim()  : undefined;
  const roomType      = String(body.room_type      || 'shared').trim();
  const paymentChoiceRaw = String(body.payment_choice || 'stripe_deposit').trim();
  const staffNorm = normalizeManualBookingStaffPaymentChoice(paymentChoiceRaw);
  const paymentChoice = staffNorm
    ? manualBookingQuotePaymentChoice(staffNorm)
    : paymentChoiceRaw;
  const addOns        = Array.isArray(body.add_ons) ? body.add_ons : [];
  const manualPricePerNightCents = body.manual_price_per_night_cents != null
    ? Math.round(Number(body.manual_price_per_night_cents))
    : (body.manual_price_per_night_euros != null
      ? Math.round(Number(body.manual_price_per_night_euros) * 100)
      : null);

  if (!checkIn || !checkOut) {
    return send400(res, 'check_in and check_out are required (YYYY-MM-DD)');
  }
  if (!/^\d{4}-\d{2}-\d{2}$/.test(checkIn) || !/^\d{4}-\d{2}-\d{2}$/.test(checkOut)) {
    return send400(res, 'check_in and check_out must be YYYY-MM-DD');
  }

  const actorId   = user ? user.staff_user_id : 'dev-quote-preview-local';
  const actorRole = user ? user.role          : 'viewer';

  if (packageCode !== undefined) {
    const packageNightCheck = validateStaffPackageNightRule(checkIn, checkOut, packageCode);
    if (!packageNightCheck.ok) {
      appendAuditLog({
        ts: new Date().toISOString(),
        intent: 'api:quote_preview',
        preview_only: true,
        no_write_performed: true,
        success: false,
        error: 'package_min_nights_violation',
        client_slug: clientSlug,
        check_in: checkIn,
        check_out: checkOut,
        package_code: packageCode,
        nights: packageNightCheck.nights,
        staff_user_id: actorId,
        staff_role: actorRole,
        elapsed_ms: Date.now() - started,
      });
      return send400(res, packageNightCheck.error);
    }
  }

  let quote;
  try {
    quote = calculateWolfhouseQuote({
      client_slug:    clientSlug,
      check_in:       checkIn,
      check_out:      checkOut,
      guest_count:    guestCount,
      package_code:   packageCode,
      room_type:      roomType,
      payment_choice: paymentChoice,
      add_ons:        addOns,
      manual_price_per_night_cents: manualPricePerNightCents,
    });
  } catch (err) {
    appendAuditLog({
      ts:            new Date().toISOString(),
      intent:        'api:quote_preview',
      preview_only:  true,
      no_write_performed: true,
      success:       false,
      error:         err.message,
      elapsed_ms:    Date.now() - started,
      staff_user_id: actorId,
      staff_role:    actorRole,
    });
    return sendJSON(res, 500, { success: false, error: 'quote calculation failed' });
  }

  const elapsed = Date.now() - started;
  appendAuditLog({
    ts:                 new Date().toISOString(),
    intent:             'api:quote_preview',
    preview_only:       true,
    no_write_performed: true,
    creates_booking:    false,
    creates_payment:    false,
    creates_stripe_link: false,
    success:            true,
    client_slug:        clientSlug,
    check_in:           checkIn,
    check_out:          checkOut,
    package_code:       packageCode || null,
    quote_success:      quote.success,
    total_cents:        quote.total_cents,
    elapsed_ms:         elapsed,
    staff_user_id:      actorId,
    staff_role:         actorRole,
  });

  return sendJSON(res, 200, {
    success:             true,
    preview_only:        true,
    no_write_performed:  true,
    creates_booking:     false,
    creates_payment:     false,
    creates_stripe_link: false,
    quote,
    guest_packages:      guestPackages,
    elapsed_ms:          elapsed,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Route: POST /staff/bot/availability-check  (Stage 8.5.8 — Luna bot bed availability)
//
// Read-only endpoint for Luna/n8n to discover available bed_codes before calling
// /staff/bot/bookings/create.  Closes the Stage 8.5.7 selected_bed_codes gap.
//
// Behavior:
//   1. Validates check_in / check_out / guest_count.
//   2. Loads all active/sellable beds for the client from Postgres.
//   3. Loads overlapping booking_beds rows using the standard half-open interval:
//        assignment_start_date < check_out  AND  assignment_end_date > check_in
//      Rows with booking status cancelled/expired are excluded by query.
//   4. Optionally filters by room_type if rooms metadata provides it.
//   5. Returns first-fit selected_bed_codes[] for guest_count, has_enough_beds,
//      available_beds[], blockers[], warnings[].
//
// Safety:
//   preview_only: true
//   no_write_performed: true
//   creates_booking: false
//   creates_payment: false
//   creates_stripe_link: false
//   sends_whatsapp: false
//
// Auth: requireBotAuth() — bot token or staff session.
// ─────────────────────────────────────────────────────────────────────────────

async function handleBotAvailabilityCheck(req, res, user, authMode) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug    = String(body.client_slug  || DEFAULT_CLIENT).trim();
  const checkIn       = String(body.check_in     || '').trim();
  const checkOut      = String(body.check_out    || '').trim();
  const guestCount    = parseInt(body.guest_count || '1', 10);
  const roomType      = String(body.room_type    || 'shared').trim().toLowerCase();
  const genderPref    = body.gender_preference ? String(body.gender_preference).trim() : null;

  // ── Input validation ────────────────────────────────────────────────────────
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!checkIn)    return send400(res, 'check_in is required');
  if (!checkOut)   return send400(res, 'check_out is required');
  if (!guestCount || guestCount < 1) return send400(res, 'guest_count must be >= 1');

  const ciDate = new Date(checkIn + 'T00:00:00Z');
  const coDate = new Date(checkOut + 'T00:00:00Z');
  if (isNaN(ciDate.getTime()) || isNaN(coDate.getTime())) return send400(res, 'invalid date format — use YYYY-MM-DD');
  if (coDate <= ciDate) return send400(res, 'check_out must be after check_in');

  // ── DB queries (SELECT only — no writes) ────────────────────────────────────
  const warnings  = [];
  const blockers  = [];

  let bedRows, blockRows;
  try {
    await withPgClient(async (pg) => {
      // Query A: all active/sellable beds for client
      const bedsRes = await pg.query(getBedCalendarRoomsQuery(), [clientSlug]);
      bedRows = bedsRes.rows;

      // Query B: overlapping booking_beds blocks (half-open, excludes cancelled/expired)
      const blocksRes = await pg.query(getBedCalendarBlocksQuery(), [clientSlug, checkIn, checkOut]);
      blockRows = blocksRes.rows;
    });
  } catch (err) {
    console.error('[bot/availability-check] DB error:', err.message);
    sendJSON(res, 500, { success: false, error: 'db_error', detail: err.message });
    return;
  }

  bedRows = resolveBedCalendarRoomRows(clientSlug, bedRows);
  blockRows = filterDemoCalendarBlocks(blockRows);

  // ── Build bed metadata list (active + sellable only) ───────────────────────
  const allBeds = bedRows
    .filter(r => r.bed_code && r.bed_active !== false && r.bed_sellable !== false)
    .map(r => ({
      bed_code:  r.bed_code,
      room_code: r.room_code,
      room_type: r.room_type || null,
      bed_label: r.bed_label || r.bed_code,
      active:    r.bed_active !== false,
      sellable:  r.bed_sellable !== false,
    }));

  // ── Room-type filter ────────────────────────────────────────────────────────
  // "shared" → prefer beds in shared/non-private rooms.
  // "private" / "double" → prefer private/double rooms.
  // If room_type metadata is absent or ambiguous, return all and add warning.
  const hasRoomTypeMeta = allBeds.some(b => b.room_type !== null);
  let filteredBeds = allBeds;
  if (hasRoomTypeMeta && roomType && roomType !== 'any') {
    const privateTypes = ['private', 'double', 'matrimonial'];
    const sharedTypes  = ['shared', 'dorm'];
    if (roomType === 'shared') {
      const sharedBeds = allBeds.filter(b => b.room_type && sharedTypes.includes(String(b.room_type).toLowerCase()));
      filteredBeds = sharedBeds.length > 0 ? sharedBeds : allBeds;
      if (sharedBeds.length === 0) warnings.push('room_type_filter_not_strict');
    } else if (privateTypes.includes(roomType)) {
      const privateBeds = allBeds.filter(b => b.room_type && privateTypes.includes(String(b.room_type).toLowerCase()));
      filteredBeds = privateBeds.length > 0 ? privateBeds : allBeds;
      if (privateBeds.length === 0) warnings.push('room_type_filter_not_strict');
    } else {
      warnings.push('room_type_filter_not_strict');
    }
  } else if (!hasRoomTypeMeta && roomType && roomType !== 'any') {
    warnings.push('room_type_filter_not_strict');
  }

  // ── Find occupied bed codes for the date range ─────────────────────────────
  // getBedCalendarBlocksQuery already excludes cancelled/expired booking statuses.
  const occupiedBedCodes = new Set(blockRows.map(r => r.bed_code).filter(Boolean));

  // ── Available beds ─────────────────────────────────────────────────────────
  const availableBeds = filteredBeds.filter(b => !occupiedBedCodes.has(b.bed_code));

  const availableCount = availableBeds.length;
  const hasEnoughBeds  = availableCount >= guestCount;

  // ── Room-fit selection ─────────────────────────────────────────────────────
  // Prefer keeping a group together in one room when enough beds are free there.
  // Fall back to global first-fit only when no single room can hold the group.
  let selectedBedCodes = [];
  let selectedRoomCode = null;
  if (hasEnoughBeds) {
    const byRoom = new Map();
    for (const bed of availableBeds) {
      const room = bed.room_code || '__unknown_room__';
      if (!byRoom.has(room)) byRoom.set(room, []);
      byRoom.get(room).push(bed);
    }
    const roomFit = [...byRoom.entries()]
      .filter(([, beds]) => beds.length >= guestCount)
      .sort((a, b) => a[1].length - b[1].length || String(a[0]).localeCompare(String(b[0])))[0];
    if (roomFit) {
      selectedRoomCode = roomFit[0] === '__unknown_room__' ? null : roomFit[0];
      selectedBedCodes = roomFit[1].slice(0, guestCount).map(b => b.bed_code);
    } else {
      warnings.push('group_split_across_rooms_required');
      selectedBedCodes = availableBeds.slice(0, guestCount).map(b => b.bed_code);
    }
  }

  if (!hasEnoughBeds) {
    blockers.push('not_enough_available_beds');
  }

  const nextAction = hasEnoughBeds ? 'ready_for_bot_create' : 'ask_staff_or_alternate_dates';

  const elapsed = Date.now() - started;

  sendJSON(res, 200, {
    success:             true,
    preview_only:        true,
    no_write_performed:  true,
    creates_booking:     false,
    creates_payment:     false,
    creates_stripe_link: false,
    sends_whatsapp:      false,
    auth_mode:           authMode,
    client_slug:         clientSlug,
    check_in:            checkIn,
    check_out:           checkOut,
    guest_count:         guestCount,
    room_type:           roomType,
    selected_bed_codes:  selectedBedCodes,
    selected_room_code:  selectedRoomCode,
    has_enough_beds:     hasEnoughBeds,
    available_count:     availableCount,
    available_beds:      availableBeds.map(b => ({ bed_code: b.bed_code, room_code: b.room_code, room_type: b.room_type })),
    occupied_count:      occupiedBedCodes.size,
    warnings,
    blockers,
    next_action:         nextAction,
    elapsed_ms:          elapsed,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Route: POST /staff/bot/addon-request-preview  (Stage 8.8.25 — Luna guest add-on dry-run)
//
// Parses structured mid-stay add-on request fields, validates booking/service/date/qty,
// and returns what would be created. Read-only booking lookup; no service rows,
// payments, Stripe links, WhatsApp, or n8n.
//
// Auth: requireBotAuth() — same as other /staff/bot/* endpoints.
// ─────────────────────────────────────────────────────────────────────────────

const BOT_ADDON_SERVICE_TYPES = new Set(['yoga', 'meal', 'surf_lesson', 'wetsuit', 'surfboard']);

async function lookupBotAddonBooking(bookingCode, clientSlug) {
  return withPgClient(async (pg) => {
    const r = await pg.query(
      `SELECT b.id AS booking_id, b.booking_code, b.guest_name, b.check_in, b.check_out,
              b.status AS booking_status, b.client_id, cl.slug AS client_slug
         FROM bookings b
         JOIN clients cl ON cl.id = b.client_id
        WHERE b.booking_code = $1 AND cl.slug = $2`,
      [bookingCode, clientSlug],
    );
    return r.rows[0] || null;
  });
}

function buildBotAddonDryRunFlags(extra = {}) {
  return {
    preview_only: true,
    no_write_performed: true,
    creates_service_record: false,
    creates_payment: false,
    creates_stripe_link: false,
    sends_whatsapp: false,
    ...extra,
  };
}

async function resolveBotAddonRequestContext(body) {
  const clientSlug    = String(body.client_slug || DEFAULT_CLIENT).trim();
  const bookingCode   = String(body.booking_code || '').trim();
  const guestPhone    = body.guest_phone != null ? String(body.guest_phone).trim() : null;
  const serviceType   = String(body.service_type || '').trim().toLowerCase();
  let serviceDate     = body.service_date != null ? String(body.service_date).trim() : '';
  const paymentChoice = String(body.payment_choice || 'pay_now').trim().toLowerCase();
  const source        = String(body.source || 'luna_whatsapp').trim().slice(0, 50);
  const rawQuantity   = body.quantity;

  if (!serviceType || !BOT_ADDON_SERVICE_TYPES.has(serviceType)) {
    return {
      kind: 'handoff_to_staff',
      status: 422,
      payload: buildBotAddonDryRunFlags({
        success: false,
        next_action: 'handoff_to_staff',
        reply_draft: "I'll have the team help with that add-on request.",
        error: `service_type must be one of: ${[...BOT_ADDON_SERVICE_TYPES].join(', ')}`,
      }),
    };
  }

  if (!bookingCode) {
    return {
      kind: 'booking_not_found',
      status: 200,
      payload: buildBotAddonDryRunFlags({
        success: true,
        next_action: 'booking_not_found',
        reply_draft: "I couldn't find that booking — could you share your booking code?",
        booking_code: null,
        source,
      }),
    };
  }

  if (serviceDate && (!/^\d{4}-\d{2}-\d{2}$/.test(serviceDate) || isNaN(new Date(serviceDate + 'T00:00:00Z').getTime()))) {
    return {
      kind: 'ask_service_date',
      status: 200,
      payload: buildBotAddonDryRunFlags({
        success: true,
        next_action: 'ask_service_date',
        reply_draft: 'Please send the date in YYYY-MM-DD format (for example 2026-09-01).',
        booking_code: bookingCode,
        service_type: serviceType,
        source,
      }),
    };
  }

  if (rawQuantity == null || rawQuantity === '' || Number(rawQuantity) <= 0 || !Number.isFinite(Number(rawQuantity))) {
    return {
      kind: 'ask_quantity',
      status: 200,
      payload: buildBotAddonDryRunFlags({
        success: true,
        next_action: 'ask_quantity',
        reply_draft: serviceType === 'meal'
          ? 'How many meals would you like?'
          : (serviceType === 'wetsuit' || serviceType === 'surfboard'
            ? 'How many days do you need that for?'
            : 'How many would you like?'),
        booking_code: bookingCode,
        service_type: serviceType,
        service_date: serviceDate,
        source,
      }),
    };
  }

  const quantity = Math.max(1, parseInt(rawQuantity, 10) || 1);
  let boardType = body.board_type != null ? String(body.board_type).trim().toLowerCase() : '';
  if (serviceType === 'surfboard') {
    if (boardType !== 'soft' && boardType !== 'hard') {
      return {
        kind: 'ask_board_type',
        status: 200,
        payload: buildBotAddonDryRunFlags({
          success: true,
          next_action: 'ask_board_type',
          reply_draft: 'Soft top or hard board?',
          booking_code: bookingCode,
          service_type: serviceType,
          service_date: serviceDate,
          quantity,
          source,
        }),
      };
    }
  } else {
    boardType = null;
  }
  const scheduleMode = serviceDate ? 'specific_date' : 'schedule_later';
  if (!serviceDate) serviceDate = null;
  const svcDate = serviceDate ? new Date(serviceDate + 'T00:00:00Z') : null;

  let booking;
  try {
    booking = await lookupBotAddonBooking(bookingCode, clientSlug);
  } catch (err) {
    return { kind: 'db_error', status: 500, payload: { success: false, error: 'DB lookup failed: ' + err.message } };
  }

  if (!booking) {
    return {
      kind: 'booking_not_found',
      status: 200,
      payload: buildBotAddonDryRunFlags({
        success: true,
        next_action: 'booking_not_found',
        reply_draft: "I couldn't find a booking with that code — I'll ask the team to help.",
        booking_code: bookingCode,
        client_slug: clientSlug,
        source,
      }),
    };
  }

  if (booking.booking_status === 'cancelled' || booking.booking_status === 'expired') {
    return {
      kind: 'handoff_to_staff',
      status: 200,
      payload: buildBotAddonDryRunFlags({
        success: true,
        next_action: 'handoff_to_staff',
        reply_draft: "That booking isn't active anymore — I'll have the team take a look.",
        booking_code: bookingCode,
        booking_id: booking.booking_id,
        source,
      }),
    };
  }

  const pricing = previewGuestAddonPricing(serviceType, quantity, clientSlug, {
    board_type: boardType || undefined,
  });
  const warnings = [...(pricing.warnings || [])];
  const ci = booking.check_in ? new Date(booking.check_in) : null;
  const co = booking.check_out ? new Date(booking.check_out) : null;
  if (svcDate && ci && co && (svcDate < ci || svcDate >= co)) {
    warnings.push('service_date is outside the booking stay window — staff may need to confirm.');
  }

  const isRecordOnly = paymentChoice === 'record_only';
  const canPay = !isRecordOnly && pricing.payment_required && pricing.amount_due_cents != null && pricing.amount_due_cents > 0;

  let nextAction;
  if (!canPay && pricing.amount_due_cents == null) {
    nextAction = 'handoff_to_staff';
  } else if (canPay) {
    nextAction = 'ready_for_addon_create_dry_run';
  } else {
    nextAction = 'ready_for_record_only';
  }

  return {
    kind: 'ready',
    clientSlug,
    bookingCode,
    guestPhone,
    serviceType,
    serviceDate,
    scheduleMode,
    paymentChoice,
    source,
    quantity,
    boardType,
    svcDate,
    booking,
    pricing,
    warnings,
    isRecordOnly,
    canPay,
    nextAction,
  };
}

function buildBotAddonServiceMetadata(ctx, idempotencyKey) {
  const meta = {
    source: ctx.source,
    pricing_addon_code: ctx.pricing.pricing_addon_code,
    payment_choice: ctx.paymentChoice,
    schedule_mode: ctx.scheduleMode || (ctx.serviceDate ? 'specific_date' : 'schedule_later'),
    unscheduled: !ctx.serviceDate,
    needs_scheduling: !ctx.serviceDate || ctx.serviceType === 'yoga' || ctx.serviceType === 'surf_lesson',
  };
  if (ctx.guestPhone) meta.guest_phone = ctx.guestPhone;
  if (idempotencyKey) meta.idempotency_key = idempotencyKey;
  if (ctx.serviceType === 'wetsuit' || ctx.serviceType === 'surfboard') {
    meta.rental_days = ctx.quantity;
  }
  if (ctx.serviceType === 'surfboard' && ctx.boardType) {
    meta.board_variant = ctx.boardType;
    meta.staff_ui_service_type = ctx.boardType === 'hard' ? 'hard_board' : 'soft_board';
  }
  if (ctx.comboReason) meta.combo_reason = ctx.comboReason;
  return meta;
}

async function findBotAddonIdempotentMatch(clientSlug, bookingId, idempotencyKey) {
  return withPgClient(async (pg) => {
    const svc = await pg.query(
      `SELECT id, booking_id, booking_code, service_type, service_date, quantity,
              status, amount_due_cents, amount_paid_cents, payment_status, payment_id
         FROM booking_service_records
        WHERE client_slug = $1
          AND booking_id = $2::uuid
          AND source = 'luna_guest'
          AND metadata->>'idempotency_key' = $3
        LIMIT 1`,
      [clientSlug, bookingId, idempotencyKey],
    );
    if (!svc.rows[0]) return null;
    const serviceRow = svc.rows[0];
    let payment = null;
    if (serviceRow.payment_id) {
      const pm = await pg.query(
        `SELECT id, status, payment_kind, checkout_url, stripe_checkout_session_id, amount_due_cents
           FROM payments
          WHERE id = $1`,
        [serviceRow.payment_id],
      );
      payment = pm.rows[0] || null;
    }
    return { serviceRow, payment };
  });
}

async function loadBotAddonExistingServiceRecords(clientSlug, bookingId) {
  return withPgClient(async (pg) => {
    const r = await pg.query(
      `SELECT id, service_type, quantity, amount_due_cents, amount_paid_cents,
              payment_status, payment_id, status, metadata
         FROM booking_service_records
        WHERE client_slug = $1
          AND booking_id = $2::uuid
          AND status <> 'cancelled'`,
      [clientSlug, bookingId],
    );
    return r.rows;
  });
}

async function zeroOutUnpaidAddonServiceRecord(pg, serviceRecordId) {
  const svc = await pg.query(
    `SELECT id, payment_id, amount_due_cents, payment_status
       FROM booking_service_records
      WHERE id = $1
      FOR UPDATE`,
    [serviceRecordId],
  );
  const row = svc.rows[0];
  if (!row || Number(row.amount_due_cents || 0) <= 0) return null;
  if (String(row.payment_status || '').toLowerCase() === 'paid') return null;

  await pg.query(
    `UPDATE booking_service_records
        SET amount_due_cents = 0,
            payment_status = 'not_requested',
            payment_id = NULL,
            metadata = COALESCE(metadata, '{}'::jsonb) || $2::jsonb,
            updated_at = NOW()
      WHERE id = $1`,
    [
      serviceRecordId,
      JSON.stringify({ combo_waived: true, combo_reason: 'board_frees_unpaid_wetsuit' }),
    ],
  );

  if (row.payment_id) {
    await pg.query(
      `UPDATE payments
          SET status = 'cancelled'::payment_record_status,
              amount_due_cents = 0,
              checkout_url = NULL,
              metadata = COALESCE(metadata, '{}'::jsonb) || $2::jsonb
        WHERE id = $1
          AND status <> 'paid'::payment_record_status`,
      [
        row.payment_id,
        JSON.stringify({ cancelled_reason: 'combo_wetsuit_waived', source: 'luna_guest_addon_combo' }),
      ],
    );
  }
  return serviceRecordId;
}

function buildBotAddonCreateReplyDraft(ctx, { paymentUrl, dbAmountDueCents, servicePaymentStatus }) {
  const when = ctx.serviceDate || 'unscheduled';
  const label = ctx.serviceType.replace('_', ' ');
  if (servicePaymentStatus === 'paid') {
    const eur = (dbAmountDueCents / 100).toFixed(2);
    return `Your ${label} add-on for ${when} is already paid (€${eur}).`;
  }
  if (paymentUrl && dbAmountDueCents > 0) {
    const eur = (dbAmountDueCents / 100).toFixed(2);
    return `Your ${label} add-on for ${when} is €${eur}. Pay now here if you like: ${paymentUrl} — or we can settle it at checkout.`;
  }
  if (ctx.comboReason === 'wetsuit_free_with_board') {
    return ctx.serviceDate
      ? `Got it — wetsuit rental for ${ctx.quantity} day${ctx.quantity !== 1 ? 's' : ''} on ${ctx.serviceDate} is included free with your board rental.`
      : `Got it — wetsuit rental for ${ctx.quantity} day${ctx.quantity !== 1 ? 's' : ''} is included free with your board rental. We can pick a date when you're ready.`;
  }
  return ctx.serviceDate
    ? `I've noted your ${label} request for ${ctx.serviceDate}.`
    : `I've added your ${label} request as unscheduled. We can choose the date later.`;
}

async function handleBotAddonRequestPreview(req, res, user, authMode) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid JSON body');
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');
  const ctx = await resolveBotAddonRequestContext(body);

  if (ctx.kind !== 'ready') {
    return sendJSON(res, ctx.status, { ...ctx.payload, auth_mode: resolvedAuthMode });
  }

  let replyDraft;
  if (ctx.nextAction === 'handoff_to_staff') {
    replyDraft = "I'll have the team confirm that add-on and get back to you.";
  } else if (ctx.canPay) {
    const eur = (ctx.pricing.amount_due_cents / 100).toFixed(2);
    const when = ctx.serviceDate || 'unscheduled';
    replyDraft = `For ${ctx.serviceType.replace('_', ' ')} (${when}), the total would be €${eur}. I can send a payment link when you're ready — or you can pay at checkout.`;
  } else {
    replyDraft = ctx.serviceDate
      ? `I'll note your ${ctx.serviceType.replace('_', ' ')} request for ${ctx.serviceDate}.`
      : `I'll add your ${ctx.serviceType.replace('_', ' ')} request as unscheduled. We can choose the date later.`;
  }

  const serviceRecordPreview = {
    booking_id: ctx.booking.booking_id,
    booking_code: ctx.booking.booking_code,
    guest_name: ctx.booking.guest_name,
    guest_phone: ctx.guestPhone,
    service_type: ctx.serviceType,
    service_date: ctx.serviceDate,
    quantity: ctx.quantity,
    status: 'confirmed',
    payment_status: ctx.canPay ? 'pending' : 'not_requested',
    amount_due_cents: ctx.pricing.amount_due_cents ?? 0,
    source: ctx.source,
    metadata: buildBotAddonServiceMetadata(ctx),
  };

  let paymentPreview = null;
  if (ctx.canPay) {
    paymentPreview = {
      payment_kind: 'addon_service',
      currency: 'EUR',
      amount_due_cents: ctx.pricing.amount_due_cents,
      payment_required: true,
      would_create_payment: true,
      would_create_stripe_link: true,
      metadata_source: 'luna_guest_addon',
    };
  } else {
    paymentPreview = {
      payment_required: false,
      would_create_payment: false,
      would_create_stripe_link: false,
      ...(ctx.pricing.reason ? { reason: ctx.pricing.reason } : {}),
    };
  }

  const elapsed = Date.now() - started;
  appendAuditLog({
    ts: new Date().toISOString(),
    intent: 'api:bot_addon_request_preview',
    category: 'bot_addon_request_preview',
    preview_only: true,
    no_write_performed: true,
    creates_service_record: false,
    creates_payment: false,
    creates_stripe_link: false,
    sends_whatsapp: false,
    success: true,
    client_slug: ctx.clientSlug,
    booking_code: ctx.bookingCode,
    service_type: ctx.serviceType,
    service_date: ctx.serviceDate,
    quantity: ctx.quantity,
    next_action: ctx.nextAction,
    elapsed_ms: elapsed,
    auth_mode: resolvedAuthMode,
  });

  return sendJSON(res, 200, {
    success: true,
    preview_only: true,
    no_write_performed: true,
    creates_service_record: false,
    creates_payment: false,
    creates_stripe_link: false,
    sends_whatsapp: false,
    client_slug: ctx.clientSlug,
    booking_id: ctx.booking.booking_id,
    booking_code: ctx.booking.booking_code,
    guest_name: ctx.booking.guest_name,
    guest_phone: ctx.guestPhone,
    service_type: ctx.serviceType,
    service_date: ctx.serviceDate,
    quantity: ctx.quantity,
    payment_choice: ctx.paymentChoice,
    source: ctx.source,
    auth_mode: resolvedAuthMode,
    next_action: ctx.nextAction,
    reply_draft: replyDraft,
    service_record_preview: serviceRecordPreview,
    payment_preview: paymentPreview,
    pricing_addon_code: ctx.pricing.pricing_addon_code || null,
    unit_cents: ctx.pricing.unit_cents ?? null,
    amount_due_cents: ctx.pricing.amount_due_cents ?? null,
    warnings: ctx.warnings,
    elapsed_ms: elapsed,
  });
}

async function handleBotAddonRequestCreate(req, res, user, authMode) {
  const started = Date.now();
  const whatsappDryRun = process.env.WHATSAPP_DRY_RUN !== 'false';

  if (!BOT_ADDON_REQUESTS_ENABLED) {
    return sendJSON(res, 403, {
      success: false,
      error: 'Bot add-on request create is disabled. Set BOT_ADDON_REQUESTS_ENABLED=true to enable.',
      bot_addon_requests_enabled: false,
    });
  }

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid JSON body');
  }

  if (body.confirm !== true) {
    return sendJSON(res, 400, {
      success: false,
      error: 'confirm:true is required to create an add-on request. Call /staff/bot/addon-request-preview first.',
      next_action: 'call_preview_first',
    });
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');
  const ctx = await resolveBotAddonRequestContext(body);

  if (ctx.kind !== 'ready') {
    const status = ctx.kind === 'db_error' ? 500 : 422;
    return sendJSON(res, status, { success: false, write_performed: false, ...ctx.payload, auth_mode: resolvedAuthMode });
  }

  if (ctx.nextAction === 'handoff_to_staff') {
    return sendJSON(res, 422, {
      success: false,
      write_performed: false,
      next_action: 'handoff_to_staff',
      reply_draft: "I'll have the team confirm that add-on and get back to you.",
      warnings: ctx.warnings,
      auth_mode: resolvedAuthMode,
    });
  }

  const idempotencyKey = body.idempotency_key
    ? String(body.idempotency_key).trim().slice(0, 120)
    : null;
  const idempotencyKeyMissing = !idempotencyKey;

  if (idempotencyKey) {
    let existingMatch;
    try {
      existingMatch = await findBotAddonIdempotentMatch(
        ctx.clientSlug,
        ctx.booking.booking_id,
        idempotencyKey,
      );
    } catch (err) {
      if (isMissingBookingServiceRecordsTable(err)) {
        return sendJSON(res, 503, {
          success: false,
          error: 'booking_service_records table not available',
          service_records_available: false,
          write_performed: false,
        });
      }
      return sendJSON(res, 500, {
        success: false,
        error: 'Idempotency lookup failed: ' + err.message,
        write_performed: false,
      });
    }

    if (existingMatch) {
      const { serviceRow, payment } = existingMatch;
      const svcPaymentStatus = serviceRow.payment_status;
      const dbAmountDueCents = Number(serviceRow.amount_due_cents || 0);
      let checkoutUrl = null;
      let stripeSessionId = null;

      if (
        payment
        && payment.status === 'checkout_created'
        && payment.checkout_url
        && svcPaymentStatus !== 'paid'
      ) {
        checkoutUrl = payment.checkout_url;
        stripeSessionId = payment.stripe_checkout_session_id;
      }

      const linkObs = botAddonPaymentLinkObservability(ctx, checkoutUrl, stripeSessionId);
      const replyDraft = buildBotAddonCreateReplyDraft(ctx, {
        paymentUrl: (linkObs && linkObs.guest_payment_url) || checkoutUrl,
        dbAmountDueCents,
        servicePaymentStatus: svcPaymentStatus,
      });
      const elapsed = Date.now() - started;

      appendAuditLog({
        ts: new Date().toISOString(),
        intent: 'api:bot_addon_request_create',
        category: 'bot_addon_request_create',
        success: true,
        idempotent_duplicate: true,
        client_slug: ctx.clientSlug,
        booking_code: ctx.bookingCode,
        service_record_id: serviceRow.id,
        payment_id: payment?.id || null,
        service_type: ctx.serviceType,
        elapsed_ms: elapsed,
        auth_mode: resolvedAuthMode,
      });

      const idempotentResponse = {
        success: true,
        idempotent: true,
        write_performed: false,
        service_record_id: serviceRow.id,
        booking_id: ctx.booking.booking_id,
        booking_code: ctx.booking.booking_code,
        service_type: serviceRow.service_type,
        service_date: ctx.serviceDate,
        quantity: serviceRow.quantity,
        amount_due_cents: dbAmountDueCents,
        payment_status: svcPaymentStatus,
        no_payment_truth_recorded: true,
        sends_whatsapp: false,
        whatsapp_dry_run: whatsappDryRun,
        no_n8n: true,
        reply_draft: replyDraft,
        auth_mode: resolvedAuthMode,
        elapsed_ms: elapsed,
        message: svcPaymentStatus === 'paid'
          ? 'Add-on request already fulfilled (idempotent — already paid).'
          : 'Add-on request already exists for this idempotency key (idempotent).',
      };

      if (payment?.id) {
        idempotentResponse.payment_id = payment.id;
        idempotentResponse.payment_kind = payment.payment_kind || 'addon_service';
      }
      if (checkoutUrl) {
        applyBotAddonPaymentLinkFields(idempotentResponse, ctx, checkoutUrl, stripeSessionId);
      }

      return sendJSON(res, 200, idempotentResponse);
    }
  }

  let existingServiceRecords = [];
  try {
    existingServiceRecords = await loadBotAddonExistingServiceRecords(
      ctx.clientSlug,
      ctx.booking.booking_id,
    );
  } catch (err) {
    return sendJSON(res, 500, {
      success: false,
      error: 'Failed to load existing service records: ' + err.message,
      write_performed: false,
    });
  }

  const comboPricing = resolveGuestAddonComboPricing({
    serviceType: ctx.serviceType,
    quantity: ctx.quantity,
    boardType: ctx.boardType,
    pricing: ctx.pricing,
    existingRecords: existingServiceRecords,
  });
  ctx.comboReason = comboPricing.combo_reason || null;

  let amountDueCents = comboPricing.amount_due_cents ?? 0;
  let canPay = !ctx.isRecordOnly && comboPricing.payment_required && amountDueCents > 0;
  const paymentStatus = canPay ? 'pending' : 'not_requested';
  const serviceMeta = buildBotAddonServiceMetadata(ctx, idempotencyKey);

  if (canPay) {
    if (!STRIPE_LINKS_ENABLED) {
      return sendJSON(res, 403, {
        success: false,
        error: 'Stripe link creation is disabled. Set STRIPE_LINKS_ENABLED=true to enable.',
        stripe_links_enabled: false,
        write_performed: false,
      });
    }
    if (!STRIPE_SECRET_KEY) {
      return sendJSON(res, 503, { success: false, error: 'STRIPE_SECRET_KEY not configured.', write_performed: false });
    }
    if (!stripeCheckoutRedirectUrlsConfigured()) {
      return sendJSON(res, 503, {
        success: false,
        error: 'STRIPE_CHECKOUT_SUCCESS_URL and STRIPE_CHECKOUT_CANCEL_URL must be set in env.',
        write_performed: false,
      });
    }
  }

  let writeResult;
  try {
    writeResult = await withPgClient(async (pg) => {
      await pg.query('BEGIN');
      try {
        if (comboPricing.free_wetsuit_record_id) {
          await zeroOutUnpaidAddonServiceRecord(pg, comboPricing.free_wetsuit_record_id);
        }

        const ins = await pg.query(
          `INSERT INTO booking_service_records (
             client_slug, booking_id, booking_code, guest_name,
             service_type, service_date, quantity, status,
             amount_due_cents, amount_paid_cents, payment_status,
             source, notes, metadata
           ) VALUES (
             $1, $2::uuid, $3, $4,
             $5, $6::date, $7, 'confirmed',
             $8, 0, $9,
             'luna_guest', $10, $11::jsonb
           ) RETURNING id`,
          [
            ctx.clientSlug,
            ctx.booking.booking_id,
            ctx.booking.booking_code,
            ctx.booking.guest_name,
            ctx.serviceType,
            ctx.serviceDate,
            ctx.quantity,
            amountDueCents,
            paymentStatus,
            null,
            JSON.stringify(serviceMeta),
          ],
        );
        const svcId = ins.rows[0].id;

        if (canPay) {
          const pmMeta = {
            source: 'luna_guest_addon_request',
            service_record_ids: [svcId],
            booking_code: ctx.booking.booking_code,
            service_type: ctx.serviceType,
            service_date: ctx.serviceDate || null,
            quantity: ctx.quantity,
            service_record_allocation_cents: { [svcId]: amountDueCents },
          };
          if (idempotencyKey) pmMeta.idempotency_key = idempotencyKey;
          const pmIns = await pg.query(
            `INSERT INTO payments (
               client_id, booking_id, status, payment_kind, currency,
               amount_due_cents, amount_paid_cents, metadata
             ) VALUES (
               $1, $2, 'draft'::payment_record_status, 'addon_service'::payment_kind, 'EUR',
               $3, 0, $4::jsonb
             ) RETURNING id, amount_due_cents`,
            [ctx.booking.client_id, ctx.booking.booking_id, amountDueCents, JSON.stringify(pmMeta)],
          );
          const newPaymentId = pmIns.rows[0].id;
          await pg.query(
            `UPDATE booking_service_records
                SET payment_id = $1, payment_status = 'pending', updated_at = NOW()
              WHERE id = $2`,
            [newPaymentId, svcId],
          );
          await pg.query('COMMIT');
          return {
            serviceRecordId: svcId,
            paymentId: newPaymentId,
            amountDueCents: Number(pmIns.rows[0].amount_due_cents),
          };
        }

        await pg.query('COMMIT');
        return { serviceRecordId: svcId, paymentId: null, amountDueCents };
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });
  } catch (err) {
    if (isMissingBookingServiceRecordsTable(err)) {
      return sendJSON(res, 503, {
        success: false,
        error: 'booking_service_records table not available',
        service_records_available: false,
        write_performed: false,
      });
    }
    return sendJSON(res, 500, { success: false, error: 'Failed to create add-on service record: ' + err.message, write_performed: false });
  }

  const serviceRecordId = writeResult.serviceRecordId;
  const paymentId = writeResult.paymentId;
  const dbAmountDueCents = writeResult.amountDueCents;
  let checkoutUrl = null;
  let stripeSessionId = null;

  if (canPay && paymentId) {
    let stripe;
    try {
      stripe = require('stripe')(STRIPE_SECRET_KEY);
    } catch (e) {
      return sendJSON(res, 500, {
        success: false,
        error: 'Failed to load Stripe SDK: ' + e.message,
        service_record_id: serviceRecordId,
        payment_id: paymentId,
        write_performed: true,
      });
    }

    const productName = `Add-ons — ${ctx.booking.booking_code || ctx.booking.booking_id}`;
    const productDesc = `Luna guest add-on | ${ctx.serviceType} | ${ctx.booking.guest_name || 'Guest'}`;

    let session;
    try {
      session = await stripe.checkout.sessions.create({
        mode: 'payment',
        currency: 'eur',
        line_items: [{
          price_data: {
            currency: 'eur',
            product_data: { name: productName, description: productDesc },
            unit_amount: dbAmountDueCents,
          },
          quantity: 1,
        }],
        metadata: {
          client_slug: ctx.clientSlug,
          booking_id: ctx.booking.booking_id,
          booking_code: ctx.booking.booking_code || '',
          payment_id: paymentId,
          payment_kind: 'addon_service',
          service_record_ids: JSON.stringify([serviceRecordId]),
          source: 'luna_guest_addon_request',
        },
        success_url: stripeCheckoutSessionSuccessUrl(),
        cancel_url: stripeCheckoutSessionCancelUrl(),
      });
    } catch (stripeErr) {
      return sendJSON(res, 500, {
        success: false,
        error: 'Stripe session creation failed: ' + stripeErr.message,
        service_record_id: serviceRecordId,
        payment_id: paymentId,
        no_payment_truth_recorded: true,
        write_performed: true,
      });
    }

    checkoutUrl = session.url;
    stripeSessionId = session.id;
    const expiresAt = session.expires_at ? new Date(session.expires_at * 1000).toISOString() : null;

    try {
      await withPgClient(async (pg) => {
        await pg.query(
          `UPDATE payments
              SET status = 'checkout_created'::payment_record_status,
                  stripe_checkout_session_id = $1,
                  checkout_url = $2,
                  expires_at = $3,
                  metadata = metadata || $4::jsonb
            WHERE id = $5`,
          [
            session.id,
            session.url,
            expiresAt,
            JSON.stringify({ stripe_session_id: session.id, stripe_livemode: session.livemode, source: 'luna_guest_addon_request' }),
            paymentId,
          ],
        );
      });
    } catch (dbErr) {
      return sendJSON(res, 500, {
        success: false,
        error: 'Stripe session created but DB update failed: ' + dbErr.message,
        service_record_id: serviceRecordId,
        payment_id: paymentId,
        checkout_url: checkoutUrl,
        no_payment_truth_recorded: true,
        write_performed: true,
      });
    }
  }

  const linkObs = botAddonPaymentLinkObservability(ctx, checkoutUrl, stripeSessionId);
  let replyDraft = buildBotAddonCreateReplyDraft(ctx, {
    paymentUrl: (linkObs && linkObs.guest_payment_url) || checkoutUrl,
    dbAmountDueCents,
    servicePaymentStatus: paymentStatus,
  });

  const elapsed = Date.now() - started;
  appendAuditLog({
    ts: new Date().toISOString(),
    intent: 'api:bot_addon_request_create',
    category: 'bot_addon_request_create',
    success: true,
    client_slug: ctx.clientSlug,
    booking_code: ctx.bookingCode,
    service_record_id: serviceRecordId,
    payment_id: paymentId,
    service_type: ctx.serviceType,
    amount_due_cents: dbAmountDueCents,
    stripe_called: !!checkoutUrl,
    whatsapp_called: false,
    n8n_called: false,
    idempotency_key_missing: idempotencyKeyMissing,
    elapsed_ms: elapsed,
    auth_mode: resolvedAuthMode,
  });

  const response = {
    success: true,
    write_performed: true,
    service_record_id: serviceRecordId,
    booking_id: ctx.booking.booking_id,
    booking_code: ctx.booking.booking_code,
    service_type: ctx.serviceType,
    service_date: ctx.serviceDate,
    quantity: ctx.quantity,
    amount_due_cents: dbAmountDueCents,
    payment_status: paymentStatus,
    no_payment_truth_recorded: true,
    sends_whatsapp: false,
    whatsapp_dry_run: whatsappDryRun,
    no_n8n: true,
    reply_draft: replyDraft,
    auth_mode: resolvedAuthMode,
    elapsed_ms: elapsed,
  };

  if (idempotencyKeyMissing) {
    response.idempotency_key_missing = true;
  }

  if (paymentId) {
    response.payment_id = paymentId;
    response.payment_kind = 'addon_service';
  }
  if (checkoutUrl) {
    applyBotAddonPaymentLinkFields(response, ctx, checkoutUrl, stripeSessionId);
  }
  response.payment_required = canPay;
  if (comboPricing.combo_applied) {
    response.combo_applied = true;
    response.combo_reason = comboPricing.combo_reason;
  }

  return sendJSON(res, 201, response);
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 9.4b — Luna guest bot pause/resume (bot_pause_states source of truth)
// Does NOT mutate conversations.bot_mode, bookings, payments, or service records.
// ─────────────────────────────────────────────────────────────────────────────

function botPauseControlsDisabledResponse() {
  return {
    success:           false,
    enabled:           false,
    error:             'bot_pause_controls_disabled',
    paused:            false,
    bot_paused:        false,
    live_send_blocked: false,
  };
}

function buildDefaultActivePauseResponse(extra) {
  return Object.assign({
    success:           true,
    paused:            false,
    bot_paused:        false,
    live_send_blocked: false,
    source:            'default_active',
  }, extra || {});
}

function buildPausedStateResponse(pauseStateRow, extra) {
  const pauseState = formatPauseStateRow(pauseStateRow);
  return Object.assign({
    success:           true,
    paused:            true,
    bot_paused:        true,
    live_send_blocked: true,
    source:            'bot_pause_states',
    pause_state:       pauseState,
    client_slug:       pauseState ? pauseState.client_slug : undefined,
    guest_phone:       pauseState ? pauseState.guest_phone : undefined,
    conversation_id:   pauseState ? pauseState.conversation_id : undefined,
    booking_id:        pauseState ? pauseState.booking_id : undefined,
    booking_code:      pauseState ? pauseState.booking_code : undefined,
    pause_reason:      pauseState ? pauseState.pause_reason : undefined,
    paused_by:         pauseState ? pauseState.paused_by : undefined,
    paused_at:         pauseState ? pauseState.paused_at : undefined,
    resumed_by:        pauseState ? pauseState.resumed_by : undefined,
    resumed_at:        pauseState ? pauseState.resumed_at : undefined,
    updated_at:        pauseState ? pauseState.updated_at : undefined,
  }, extra || {});
}

function resolveStaffActorId(user, body, fallback) {
  if (user && user.staff_user_id) return user.staff_user_id;
  if (body && body.staff_user) return String(body.staff_user).trim().slice(0, 200);
  return fallback || 'unknown-staff';
}

// Phase 9.6 — reusable guest automation pause gate (bot_pause_states SoT; read-only)
async function checkGuestAutomationPauseState(pg, input) {
  const clientSlug = String(input.client_slug || DEFAULT_CLIENT).trim();
  const conversationId = input.conversation_id != null
    ? String(input.conversation_id).trim() || null
    : null;
  const guestPhone = input.guest_phone != null
    ? String(input.guest_phone).trim() || null
    : null;
  const bookingCode = input.booking_code != null
    ? String(input.booking_code).trim() || null
    : null;

  const result = await getPauseState(pg, {
    client_slug:     clientSlug,
    conversation_id: conversationId,
    guest_phone:     guestPhone,
    booking_code:    bookingCode,
  });

  if (result.row) {
    return {
      bot_paused:        true,
      live_send_blocked: true,
      source:            'bot_pause_states',
      pause_state:       formatPauseStateRow(result.row),
      table_missing:     !!result.table_missing,
    };
  }

  return {
    bot_paused:        false,
    live_send_blocked: false,
    source:            'default_active',
    pause_state:       null,
    table_missing:     !!result.table_missing,
  };
}

function buildGuestAutomationGateResponse(gate, body, extra) {
  const draftReply = body && body.draft_reply != null
    ? String(body.draft_reply)
    : null;
  const hasDraft = draftReply != null && draftReply.length > 0;
  const requestSource = body && body.source != null
    ? String(body.source).trim().slice(0, 100) || null
    : null;

  const base = Object.assign({
    success:                       true,
    bot_paused:                    gate.bot_paused,
    live_send_blocked:             gate.live_send_blocked,
    can_continue_guest_automation: !gate.bot_paused,
    source:                        gate.source,
    no_write_performed:            true,
    sends_whatsapp:                false,
    whatsapp_dry_run:              true,
  }, extra || {});

  if (gate.pause_state) base.pause_state = gate.pause_state;
  if (gate.table_missing) base.table_missing = true;
  if (hasDraft) {
    base.draft_reply = draftReply;
    base.draft_reply_preserved = true;
  }
  if (requestSource) base.request_source = requestSource;

  return base;
}

async function handleBotCheckGuestAutomationGate(req, res, user, authMode) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid JSON body');
  }

  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  const conversationId = body.conversation_id != null
    ? String(body.conversation_id).trim() || null
    : null;
  const guestPhone = body.guest_phone != null
    ? String(body.guest_phone).trim() || null
    : null;

  if (!clientSlug || SQL_INJECT_RE.test(clientSlug)) {
    return send400(res, 'client_slug is required');
  }
  if (!conversationId && !guestPhone) {
    return send400(res, 'conversation_id or guest_phone is required');
  }

  try {
    const gate = await withPgClient((pg) => checkGuestAutomationPauseState(pg, {
      client_slug:     clientSlug,
      conversation_id: conversationId,
      guest_phone:     guestPhone,
      booking_code:    body.booking_code,
    }));

    appendAuditLog(Object.assign({
      ts: new Date().toISOString(),
      intent: 'api:bot.check-guest-automation-gate',
      category: 'bot_pause_api',
      client_slug: clientSlug,
      conversation_id: conversationId,
      guest_phone: guestPhone,
      success: true,
      bot_paused: gate.bot_paused,
      can_continue_guest_automation: !gate.bot_paused,
      source: gate.source,
      auth_mode: authMode || null,
      no_write_performed: true,
      sends_whatsapp: false,
      whatsapp_dry_run: true,
      elapsed_ms: Date.now() - started,
    }, user ? { staff_user_id: user.staff_user_id } : {}));

    return sendJSON(res, 200, buildGuestAutomationGateResponse(gate, body, {
      client_slug: clientSlug,
      conversation_id: conversationId,
      guest_phone: guestPhone,
    }));
  } catch (err) {
    appendAuditLog(Object.assign({
      ts: new Date().toISOString(),
      intent: 'api:bot.check-guest-automation-gate',
      category: 'bot_pause_api',
      client_slug: clientSlug,
      success: false,
      error: err.message,
      elapsed_ms: Date.now() - started,
    }, user ? { staff_user_id: user.staff_user_id } : {}));

    return sendJSON(res, 200, buildGuestAutomationGateResponse({
      bot_paused: false,
      live_send_blocked: false,
      source: 'default_active',
      pause_state: null,
    }, body, {
      client_slug: clientSlug,
      conversation_id: conversationId,
      guest_phone: guestPhone,
      lookup_error: true,
    }));
  }
}

async function handleBotPauseStateGet(query, res, user) {
  const started = Date.now();
  const clientSlug = String(query.client_slug || query.client || DEFAULT_CLIENT).trim();
  const conversationId = query.conversation_id != null
    ? String(query.conversation_id).trim() || null
    : null;
  const guestPhone = query.guest_phone != null
    ? String(query.guest_phone).trim() || null
    : null;
  const bookingCode = query.booking_code != null
    ? String(query.booking_code).trim() || null
    : null;

  if (!clientSlug || SQL_INJECT_RE.test(clientSlug)) {
    return send400(res, 'client_slug is required');
  }
  if (!conversationId && !guestPhone && !bookingCode) {
    return send400(res, 'conversation_id, guest_phone, or booking_code is required');
  }

  try {
    const result = await withPgClient((pg) => getPauseState(pg, {
      client_slug:     clientSlug,
      conversation_id: conversationId,
      guest_phone:     guestPhone,
      booking_code:    bookingCode,
    }));

    appendAuditLog(Object.assign({
      ts: new Date().toISOString(),
      intent: 'api:bot.pause-state',
      category: 'bot_pause_api',
      client_slug: clientSlug,
      success: true,
      paused: !!result.row,
      source: result.row ? 'bot_pause_states' : 'default_active',
      table_missing: !!result.table_missing,
      elapsed_ms: Date.now() - started,
    }, user ? { staff_user_id: user.staff_user_id } : {}));

    if (result.row) {
      return sendJSON(res, 200, buildPausedStateResponse(result.row));
    }

    return sendJSON(res, 200, buildDefaultActivePauseResponse({
      client_slug: clientSlug,
      guest_phone: guestPhone,
      conversation_id: conversationId,
      booking_code: bookingCode,
      table_missing: result.table_missing || false,
    }));
  } catch (err) {
    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:bot.pause-state',
      category: 'bot_pause_api',
      client_slug: clientSlug,
      success: false,
      error: err.message,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 200, buildDefaultActivePauseResponse({
      client_slug: clientSlug,
      guest_phone: guestPhone,
      conversation_id: conversationId,
      booking_code: bookingCode,
      lookup_error: true,
    }));
  }
}

async function handleBotPausePost(req, res, user) {
  const started = Date.now();

  if (!BOT_PAUSE_CONTROLS_ENABLED) {
    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:bot.pause',
      category: 'bot_pause_api',
      success: false,
      error: 'bot_pause_controls_disabled',
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 403, botPauseControlsDisabledResponse());
  }

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid JSON body');
  }

  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  const conversationId = body.conversation_id != null
    ? String(body.conversation_id).trim() || null
    : null;
  const guestPhone = body.guest_phone != null
    ? String(body.guest_phone).trim() || null
    : null;

  if (!clientSlug || SQL_INJECT_RE.test(clientSlug)) {
    return send400(res, 'client_slug is required');
  }
  if (!conversationId && !guestPhone) {
    return send400(res, 'conversation_id or guest_phone is required');
  }

  const pausedBy = resolveStaffActorId(user, body, 'pause-local-dev');

  try {
    const result = await withPgClient((pg) => pauseConversation(pg, {
      client_slug:     clientSlug,
      conversation_id: conversationId,
      guest_phone:     guestPhone,
      booking_id:      body.booking_id,
      booking_code:    body.booking_code,
      pause_reason:    body.pause_reason,
      paused_by:       pausedBy,
    }));

    if (result.table_missing) {
      appendAuditLog({
        ts: new Date().toISOString(),
        intent: 'api:bot.pause',
        category: 'bot_pause_api',
        client_slug: clientSlug,
        success: false,
        error: 'bot_pause_states_table_missing',
        elapsed_ms: Date.now() - started,
      });
      return sendJSON(res, 503, {
        success: false,
        error: 'bot_pause_states_table_missing',
        paused: false,
        bot_paused: false,
        live_send_blocked: false,
      });
    }

    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:bot.pause',
      category: 'bot_pause_api',
      client_slug: clientSlug,
      staff_user_id: pausedBy,
      success: true,
      idempotent: !!result.idempotent,
      elapsed_ms: Date.now() - started,
    });

    return sendJSON(res, 200, buildPausedStateResponse(result.row, {
      idempotent: !!result.idempotent,
    }));
  } catch (err) {
    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:bot.pause',
      category: 'bot_pause_api',
      client_slug: clientSlug,
      success: false,
      error: err.message,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 500, { success: false, error: 'pause write failed' });
  }
}

