// Route: POST /staff/bot/booking-preview  (Stage 8.5.2 — Luna bot bridge)
//
// Receives parsed Luna/n8n booking details and returns a safe read-only preview:
//   - missing_fields list (required before booking create)
//   - quote preview from calculateWolfhouseQuote() if dates/guests/package present
//   - availability.status = "not_checked" (DB availability requires bed codes)
//   - next_action: ask_missing_fields | ready_for_create_dry_run |
//                  staff_review_required | show_quote
//   - reply_draft: suggested WhatsApp reply text (NOT sent by this endpoint)
//
// Safety: no DB write, no Stripe, no WhatsApp, no n8n, no booking creation.
//   preview_only: true
//   no_write_performed: true
//   creates_booking: false
//   creates_payment: false
//   creates_stripe_link: false
//   sends_whatsapp: false
//
// Auth: viewer+ (same as /staff/quote-preview).
//   STAFF_AUTH_REQUIRED=false (local/dev): open.
//   STAFF_AUTH_REQUIRED=true: requires session cookie with role >= viewer.
//   n8n auth gap: n8n will need a staff session token or a pre-shared internal
//   token. Auth model for n8n calls is documented in §7 of
//   STAGE-8.5.1-LUNA-BOT-SHARED-ENGINE-INTEGRATION-MAP.md and addressed later.
// ─────────────────────────────────────────────────────────────────────────────

// Required fields for a bot booking to proceed to create.
// Email is recommended (Stripe receipt) but not hard-blocked here.
const BOT_BOOKING_REQUIRED_FIELDS = [
  'check_in',
  'check_out',
  'guest_count',
  'package_code',
  'room_type',
  'guest_name',
  'payment_choice',
];

// Human-readable labels for missing-field messages
const BOT_FIELD_LABELS = {
  check_in:       'your check-in date',
  check_out:      'your check-out date',
  guest_count:    'how many guests',
  package_code:   'which package (Malibu, Uluwatu, or Waimea)',
  room_type:      'your room preference (shared or private)',
  guest_name:     'your name',
  phone:          'the WhatsApp sender number',
  payment_choice: 'whether you prefer to pay a deposit or the full amount',
};

function normalizeBotGuestPackagesForQuote(raw, guestCount, fallbackPackageCode) {
  if (!Array.isArray(raw) || raw.length === 0) return [];
  const normalized = normalizeGuestPackagesInput(raw, guestCount, fallbackPackageCode || 'malibu');
  if (normalized.error) return { error: normalized.error };
  return normalized.guest_packages;
}

function botGuestPackagesMajorityCode(guestPackages, fallback) {
  if (!Array.isArray(guestPackages) || guestPackages.length === 0) return fallback || null;
  const counts = new Map();
  guestPackages.forEach((gp) => {
    const code = String((gp && gp.package_code) || '').trim().toLowerCase();
    if (!code) return;
    counts.set(code, (counts.get(code) || 0) + 1);
  });
  let best = fallback || null;
  let bestCount = -1;
  counts.forEach((count, code) => {
    if (count > bestCount) { best = code; bestCount = count; }
  });
  return best;
}

async function handleBotBookingPreview(req, res, user, authMode) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  // ── Extract input fields ──────────────────────────────────────────────────
  const clientSlug    = String(body.client_slug || DEFAULT_CLIENT).trim();
  const phone         = String(body.phone        || '').trim();
  const guestName     = String(body.guest_name   || '').trim();
  const email         = String(body.email        || '').trim();
  const checkIn       = String(body.check_in     || '').trim();
  const checkOut      = String(body.check_out    || '').trim();
  const guestCount    = body.guest_count != null ? Number(body.guest_count) : null;
  const packageCode   = body.package_code != null
    ? String(body.package_code).trim().toLowerCase() : null;
  const guestPackagesNormalized = normalizeBotGuestPackagesForQuote(body.guest_packages, guestCount || 0, packageCode);
  if (guestPackagesNormalized && guestPackagesNormalized.error) {
    return send400(res, guestPackagesNormalized.error);
  }
  const guestPackages = Array.isArray(guestPackagesNormalized) ? guestPackagesNormalized : [];
  const pkgCtx = resolveBotBookingPackageContext({
    packageCode,
    guestPackages,
    checkIn,
    checkOut,
    guestCount: guestCount || 0,
  });
  const effectivePackageCode = pkgCtx.quotePackageCode;
  const guestPackagesForQuote = pkgCtx.guestPackagesForQuote;
  const roomType      = String(body.room_type     || 'shared').trim();
  const paymentChoiceRaw = String(body.payment_choice || '').trim();
  const paymentChoiceStaffNorm = normalizeManualBookingStaffPaymentChoice(paymentChoiceRaw);
  const paymentChoice = paymentChoiceStaffNorm
    ? manualBookingQuotePaymentChoice(paymentChoiceStaffNorm)
    : paymentChoiceRaw;
  const addOns        = Array.isArray(body.add_ons) ? body.add_ons : [];
  const language      = String(body.language || 'en').trim().slice(0, 10);
  const source        = String(body.source   || 'luna_whatsapp').trim().slice(0, 50);

  const actorId   = user ? user.staff_user_id : 'dev-bot-preview-local';
  const actorRole = user ? user.role          : 'viewer';
  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');

  // ── Detect missing required fields ────────────────────────────────────────
  const fieldValues = {
    check_in:       checkIn     || null,
    check_out:      checkOut    || null,
    guest_count:    (guestCount != null && guestCount > 0) ? guestCount : null,
    package_code:   effectivePackageCode || null,
    room_type:      roomType    || null,
    guest_name:     guestName   || null,
    phone:          phone       || null,
    payment_choice: paymentChoice || null,
  };

  const missingFields = BOT_BOOKING_REQUIRED_FIELDS.filter((f) => !fieldValues[f]);

  // ── Quote preview ─────────────────────────────────────────────────────────
  // Attempt if core quote fields are present: dates, guest count, package.
  // room_type defaults to 'shared' and payment_choice to 'deposit' if absent.
  const canQuote = !!(checkIn && checkOut && guestCount && guestCount > 0 && effectivePackageCode);
  let quote = null;
  let quoteError = null;
  let packageNightViolation = null;
  if (canQuote) {
    const packageNightCheck = validateStaffPackageNightRule(checkIn, checkOut, effectivePackageCode);
    if (!packageNightCheck.ok) {
      packageNightViolation = packageNightCheck;
      quote = {
        success: false,
        staff_review_required: false,
        blockers: [packageNightCheck.error],
        calculation_warnings: ['weekly_package_min_nights'],
        package_code: packageNightCheck.package_code,
        nights: packageNightCheck.nights,
        currency: 'EUR',
      };
    } else {
      try {
        quote = calculateWolfhouseQuote({
          client_slug:    clientSlug,
          check_in:       checkIn,
          check_out:      checkOut,
          guest_count:    guestCount,
          package_code:   effectivePackageCode,
          guest_packages: guestPackagesForQuote,
          room_type:      roomType || 'shared',
          payment_choice: paymentChoice || 'deposit',
          add_ons:        normalizeQuoteAddOnsForCombo(addOns),
        });
      } catch (err) {
        quoteError = err.message;
      }
    }
  }

  // ── next_action ───────────────────────────────────────────────────────────
  let nextAction;
  if (packageNightViolation) {
    nextAction = 'package_not_available_for_dates';
  } else if (quoteError) {
    nextAction = 'staff_review_required';
  } else if (quote && !quote.success) {
    nextAction = quote.staff_review_required ? 'staff_review_required' : 'ask_missing_fields';
  } else if (quote && quote.success) {
    nextAction = missingFields.length > 0 ? 'show_quote' : 'ready_for_create_dry_run';
  } else if (missingFields.length > 0) {
    nextAction = 'ask_missing_fields';
  } else {
    nextAction = 'show_quote';
  }

  // ── reply_draft ───────────────────────────────────────────────────────────
  let replyDraft;
  const hasAddOns = addOns.length > 0;
  const includedItems = (quote && quote.success)
    ? buildBotQuoteIncludedItems(quote, { isNoPackage: pkgCtx.isNoPackage, hasAddOns })
    : null;
  if (quote && quote.success) {
    if (includedItems && quote.line_items) {
      quote = { ...quote, included_items: includedItems };
    }
    replyDraft = buildBotQuoteReplyDraft(quote, pkgCtx, packageCode);
  } else if (nextAction === 'ask_missing_fields') {
    const readable = missingFields.map((f) => BOT_FIELD_LABELS[f] || f);
    const shown    = readable.slice(0, 3);
    const extra    = readable.length > 3 ? ` and ${readable.length - 3} more` : '';
    replyDraft = `Great, I can help you book. Could you also share: ${shown.join(', ')}${extra}?`;
  } else if (nextAction === 'package_not_available_for_dates') {
    replyDraft = 'Our Malibu, Uluwatu, and Waimea surf packs are for 7-night stays. For these dates, I can help with accommodation and add-ons like surf lessons or board/wetsuit rental instead.';
  } else if (nextAction === 'staff_review_required') {
    replyDraft = "I'm going to have the team check this and get back to you shortly.";
  } else {
    replyDraft = 'Let me check those dates and get back to you.';
  }

  // ── Audit log ─────────────────────────────────────────────────────────────
  const elapsed = Date.now() - started;
  appendAuditLog({
    ts:                  new Date().toISOString(),
    intent:              'api:bot_booking_preview',
    category:            'bot_booking_preview',
    preview_only:        true,
    no_write_performed:  true,
    creates_booking:     false,
    creates_payment:     false,
    creates_stripe_link: false,
    sends_whatsapp:      false,
    success:             true,
    client_slug:         clientSlug,
    source,
    check_in:            checkIn  || null,
    check_out:           checkOut || null,
    guest_count:         guestCount,
    package_code:        effectivePackageCode,
    guest_packages:      guestPackages,
    missing_fields:      missingFields,
    next_action:         nextAction,
    quote_success:       quote ? quote.success : null,
    elapsed_ms:          elapsed,
    staff_user_id:       actorId,
    staff_role:          actorRole,
  });

  return sendJSON(res, 200, {
    success:             true,
    preview_only:        true,
    no_write_performed:  true,
    creates_booking:     false,
    creates_payment:     false,
    creates_stripe_link: false,
    sends_whatsapp:      false,
    source,
    missing_fields:      missingFields,
    has_missing_fields:  missingFields.length > 0,
    next_action:         nextAction,
    reply_draft:         replyDraft,
    included_items:      includedItems,
    quote_total_cents:   quote && quote.success ? quote.total_cents : null,
    deposit_required_cents: quote && quote.success ? quote.deposit_required_cents : null,
    balance_due_cents:   quote && quote.success ? quote.balance_due_cents : null,
    currency:            quote && quote.success ? quote.currency : null,
    quote,
    quote_error:         quoteError || (packageNightViolation ? packageNightViolation.error : null),
    package_night_rule:  packageNightViolation || null,
    availability: {
      status:  'not_checked',
      message: 'Availability requires specific bed codes. Call /staff/manual-bookings/preview with selected_bed_codes for a full conflict check.',
    },
    email_recommended: !email,
    auth_mode:         resolvedAuthMode,
    elapsed_ms:        elapsed,
  });
}

// Route: POST /staff/bot/booking-dry-run  (Phase 12c — Luna guest booking dry-run plan)
//
// Chains gate + booking preview + availability + add-on preview via
// runLunaGuestBookingDryRun(). Read-only SELECT when pg is used; no writes.
// Auth: requireBotAuth (same as /staff/bot/booking-preview).
async function handleBotBookingDryRun(req, res, user, authMode) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');
  const actorId          = user ? user.staff_user_id : 'dev-bot-dry-run-local';

  try {
    const plan = await withPgClient((pg) => runLunaGuestBookingDryRun(body, { pg }));
    const elapsed = Date.now() - started;

    appendAuditLog({
      ts:                  new Date().toISOString(),
      intent:              'api:bot_booking_dry_run',
      category:            'bot_booking_dry_run',
      preview_only:        true,
      no_write_performed:  true,
      creates_booking:     false,
      creates_payment:     false,
      creates_stripe_link: false,
      sends_whatsapp:      false,
      calls_n8n:           false,
      success:             true,
      client_slug:         body.client_slug || DEFAULT_CLIENT,
      next_action:         plan.next_action || null,
      planned_actions:     plan.planned_actions || [],
      staff_user_id:       actorId,
      auth_mode:           resolvedAuthMode,
      elapsed_ms:          elapsed,
    });

    return sendJSON(res, 200, Object.assign({
      success:    true,
      auth_mode:  resolvedAuthMode,
      elapsed_ms: elapsed,
    }, plan));
  } catch (err) {
    const elapsed     = Date.now() - started;
    const isForbidden = /dry-run forbids/i.test(String(err.message || ''));

    appendAuditLog({
      ts:                 new Date().toISOString(),
      intent:             'api:bot_booking_dry_run',
      category:           'bot_booking_dry_run',
      preview_only:       true,
      no_write_performed: true,
      success:            false,
      error:              err.message,
      staff_user_id:      actorId,
      auth_mode:          resolvedAuthMode,
      elapsed_ms:         elapsed,
    });

    const errBody = Object.assign({
      success: false,
      error:   err.message,
    }, DRY_RUN_SAFETY_FLAGS, {
      preview_only:       true,
      no_write_performed: true,
    });

    return sendJSON(res, isForbidden ? 400 : 500, errBody);
  }
}

// Route: POST /staff/bot/booking-write-eligibility  (Phase 13c.4 — read-only)
//
// Chains dry-run → write eligibility. Never invokes write bridge or booking create.
// Auth: requireBotAuth (same as booking-dry-run / booking-create-from-plan).
async function handleBotBookingWriteEligibility(req, res, user, authMode) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');
  const actorId          = user ? user.staff_user_id : 'dev-bot-write-eligibility-local';

  try {
    const dryRunPlan = await withPgClient((pg) => runLunaGuestBookingDryRun(body, { pg }));
    const eligibility = evaluateLunaBookingWriteEligibility(dryRunPlan, body, process.env);
    const elapsed = Date.now() - started;

    appendAuditLog({
      ts:                  new Date().toISOString(),
      intent:              'api:bot_booking_write_eligibility',
      category:            'bot_booking_write_eligibility',
      preview_only:        true,
      no_write_performed:  true,
      write_performed:     false,
      creates_booking:     false,
      creates_payment:     false,
      creates_stripe_link: false,
      sends_whatsapp:      false,
      calls_n8n:           false,
      success:             true,
      write_ready:         eligibility.write_ready === true,
      client_slug:         body.client_slug || DEFAULT_CLIENT,
      blocked_reasons:     eligibility.blocked_reasons || [],
      required_approvals:  eligibility.required_approvals || [],
      safe_next_step:      eligibility.safe_next_step || null,
      staff_user_id:       actorId,
      auth_mode:           resolvedAuthMode,
      elapsed_ms:          elapsed,
    });

    return sendJSON(res, 200, {
      success:             true,
      dry_run:             true,
      preview_only:        true,
      no_write_performed:  true,
      write_performed:     false,
      creates_booking:     false,
      creates_payment:     false,
      creates_stripe_link: false,
      sends_whatsapp:      false,
      calls_n8n:           false,
      eligibility,
      write_ready:         eligibility.write_ready === true,
      blocked_reasons:     eligibility.blocked_reasons || [],
      required_approvals:  eligibility.required_approvals || [],
      would_call:          eligibility.would_call || [],
      safe_next_step:      eligibility.safe_next_step || 'keep_dry_run',
      dry_run_plan:        dryRunPlan,
      auth_mode:           resolvedAuthMode,
      elapsed_ms:          elapsed,
    });
  } catch (err) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ts:                 new Date().toISOString(),
      intent:             'api:bot_booking_write_eligibility',
      category:           'bot_booking_write_eligibility',
      preview_only:       true,
      no_write_performed: true,
      write_performed:    false,
      success:            false,
      error:              err.message,
      staff_user_id:      actorId,
      auth_mode:          resolvedAuthMode,
      elapsed_ms:         elapsed,
    });
    return sendJSON(res, 500, {
      success:             false,
      dry_run:             true,
      preview_only:        true,
      no_write_performed:  true,
      write_performed:     false,
      creates_booking:     false,
      creates_payment:     false,
      creates_stripe_link: false,
      sends_whatsapp:      false,
      calls_n8n:           false,
      error:               err.message,
      auth_mode:           resolvedAuthMode,
      elapsed_ms:          elapsed,
    });
  }
}

