// Route: POST /staff/bot/checkin-day-preview  (Phase 19c — read-only)
//
// Preview check-in day message plan (~10:00 local). No send, scheduler, or writes.
function buildBotCheckinDayPreviewInput(body) {
  return buildCheckinDayPreviewInputFromBody(body);
}

async function handleBotCheckinDayPreview(req, res, user, authMode) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');
  const actorId          = user ? user.staff_user_id : 'dev-bot-checkin-day-preview-local';

  const previewSafety = {
    preview_only:                 true,
    no_write_performed:           true,
    sends_whatsapp:               false,
    calls_n8n:                    false,
    creates_booking:              false,
    creates_payment:              false,
    creates_stripe_link:          false,
    updates_confirmation_sent_at: false,
  };

  try {
    const resolved = await withPgClient((pg) => resolveCheckinDayPreviewRequest(body, pg));

    if (!resolved.ok) {
      const elapsed = Date.now() - started;
      appendAuditLog({
        ts:                           new Date().toISOString(),
        intent:                       'api:bot_checkin_day_preview',
        category:                     'bot_checkin_day_preview',
        ...previewSafety,
        success:                      false,
        error:                        resolved.error,
        staff_user_id:                actorId,
        auth_mode:                    resolvedAuthMode,
        elapsed_ms:                   elapsed,
      });
      return sendJSON(res, resolved.status || 400, {
        success: false,
        error: resolved.error,
        ...previewSafety,
        auth_mode:  resolvedAuthMode,
        elapsed_ms: elapsed,
      });
    }

    const input = resolved.input;
    const plan = planLunaCheckinDayMessage(input, {}, process.env);
    const elapsed = Date.now() - started;
    const blocked = plan.blocked_reasons || [];
    const responseSuccess = plan.success === true && !blocked.includes('booking_not_confirmed');

    appendAuditLog({
      ts:                           new Date().toISOString(),
      intent:                       'api:bot_checkin_day_preview',
      category:                     'bot_checkin_day_preview',
      ...previewSafety,
      success:                      responseSuccess,
      booking_context_loaded:       resolved.booking_context_loaded === true,
      booking_id:                   resolved.booking_id || input.booking_id || null,
      booking_code:                 resolved.booking_code || input.booking_code || null,
      payment_link_included:        plan.payment_link_included === true,
      staff_user_id:                actorId,
      auth_mode:                    resolvedAuthMode,
      elapsed_ms:                   elapsed,
    });

    const status = plan.success === false ? 400 : 200;
    return sendJSON(res, status, {
      success:                      responseSuccess,
      booking_context_loaded:       resolved.booking_context_loaded === true,
      booking_id:                   resolved.booking_id || input.booking_id || null,
      booking_code:                 resolved.booking_code || input.booking_code || null,
      ...previewSafety,
      checkin_day_plan:             plan,
      message_preview:              plan.message_text || null,
      payment_link_log:             plan.payment_link_log || null,
      messaging_playbook:           plan.messaging_playbook || null,
      auth_mode:                    resolvedAuthMode,
      elapsed_ms:                   elapsed,
    });
  } catch (err) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ts:                           new Date().toISOString(),
      intent:                       'api:bot_checkin_day_preview',
      category:                     'bot_checkin_day_preview',
      preview_only:                 true,
      no_write_performed:           true,
      sends_whatsapp:               false,
      calls_n8n:                    false,
      success:                      false,
      error:                        err.message,
      staff_user_id:                actorId,
      auth_mode:                    resolvedAuthMode,
      elapsed_ms:                   elapsed,
    });
    return sendJSON(res, 500, {
      success:                      false,
      preview_only:                 true,
      no_write_performed:           true,
      sends_whatsapp:               false,
      calls_n8n:                    false,
      creates_booking:              false,
      creates_payment:              false,
      creates_stripe_link:          false,
      updates_confirmation_sent_at: false,
      error:                        err.message,
      auth_mode:                    resolvedAuthMode,
      elapsed_ms:                   elapsed,
    });
  }
}

// Route: POST /staff/bot/whatsapp-thread-mirror  (Hermes Luna → Staff Portal inbox)
async function handleBotHermesWhatsAppThreadMirror(req, res, user, authMode) {
  const started = Date.now();
  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const parsed = parseHermesWhatsAppThreadMirrorBody(body);
  if (!parsed.ok) {
    return sendJSON(res, parsed.status || 400, { success: false, error: parsed.error });
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');

  try {
    const out = await withPgClient((pg) => mirrorHermesWhatsAppThreadMessage(pg, parsed.input));
    const elapsed = Date.now() - started;
    const thread = out.thread || {};

    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:bot_whatsapp_thread_mirror',
      category: 'hermes_whatsapp_thread_mirror',
      direction: parsed.input.direction,
      guest_phone: parsed.input.guest_phone,
      conversation_id: out.conversation_id || null,
      thread_persisted: thread.persisted === true,
      thread_duplicate: thread.duplicate === true,
      success: out.ok === true,
      staff_user_id: user ? user.staff_user_id : null,
      auth_mode: resolvedAuthMode,
      elapsed_ms: elapsed,
    });

    return sendJSON(res, 200, {
      success: true,
      preview_only: true,
      no_booking_write: true,
      sends_whatsapp: false,
      conversation_id: out.conversation_id || null,
      direction: out.direction || parsed.input.direction,
      thread_message: {
        message_id: thread.message_id || null,
        persisted: thread.persisted === true,
        duplicate: thread.duplicate === true,
        whatsapp_message_id: thread.whatsapp_message_id || null,
      },
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:bot_whatsapp_thread_mirror',
      category: 'hermes_whatsapp_thread_mirror',
      success: false,
      error: err.message,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 500, { success: false, error: 'mirror failed', detail: err.message });
  }
}

