// ─────────────────────────────────────────────────────────────────────────────
// Phase 11b.1 — Surf forecast handler (read-only, Stormglass backend-only)
//
// GET /staff/surf-forecast?client=wolfhouse-somo&day=today|tomorrow
//   Returns staff-safe marine forecast. Key stays server-side only.
// ─────────────────────────────────────────────────────────────────────────────

async function handleSurfForecast(query, res, user) {
  const started = Date.now();
  const clientSlug = String(query.client || DEFAULT_CLIENT).trim();
  const day = String(query.day || 'today').trim().toLowerCase();

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (day !== 'today' && day !== 'tomorrow') {
    return send400(res, "day must be 'today' or 'tomorrow'");
  }

  const auditBase = {
    ts:            new Date().toISOString(),
    intent:        'api:surf_forecast',
    category:      'surf_forecast_api',
    client_slug:   clientSlug,
    day,
    staff_user_id: user ? user.staff_user_id : null,
  };

  if (!hasStormglassConfig()) {
    appendAuditLog({ ...auditBase, success: false, configured: false, elapsed_ms: Date.now() - started });
    return sendJSON(res, 503, {
      success:     false,
      configured:  false,
      error:       'STORMGLASS_API_KEY not configured',
      read_only:   true,
    });
  }

  try {
    const payload = await fetchSurfForecastForStaff({ clientSlug, day });
    appendAuditLog({ ...auditBase, success: true, elapsed_ms: Date.now() - started });
    return sendJSON(res, 200, payload);
  } catch (err) {
    const code = err && err.code;
    if (code === 'UNSUPPORTED_CLIENT') {
      return send400(res, err.message);
    }
    if (code === 'INVALID_DAY') {
      return send400(res, err.message);
    }
    appendAuditLog({
      ...auditBase,
      success: false,
      error: err.message,
      upstream: code === 'UPSTREAM_ERROR',
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 502, {
      success:   false,
      error:     'stormglass forecast unavailable',
      detail:    err.message,
      read_only: true,
    });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// POST /staff/bot/surf-report  (guest-facing surf report for Luna)
//   Returns a guest-safe, on-tone surf reply built from the same Stormglass
//   backend the staff forecast uses. Read-only. Bot-token auth. Never hard-fails:
//   when Stormglass isn't configured or errors, it returns the friendly fallback
//   copy (config.fallback) so Luna can still answer warmly.
// ─────────────────────────────────────────────────────────────────────────────
async function handleBotSurfReport(req, res, user, authMode) {
  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return sendJSON(res, 400, { success: false, error: 'invalid or missing JSON body' });
  }

  const clientSlug  = String(body.client_slug || DEFAULT_CLIENT).trim();
  const day         = String(body.day || 'today').trim().toLowerCase() === 'tomorrow' ? 'tomorrow' : 'today';
  const messageText = String(body.message_text || body.question || '').slice(0, 500);
  const lang        = body.lang ? String(body.lang).slice(0, 5) : null;

  const buildReply = (surfData) => buildGuestSurfReportReply({
    client_slug: clientSlug,
    message_text: messageText,
    lang,
    day,
    surf_data: surfData,
    preserve_booking_context: false,
  });

  try {
    const data   = await fetchGuestSurfReportData({ clientSlug, day });
    const result = buildReply(data);
    return sendJSON(res, 200, {
      success:        true,
      tool:           'get_surf_report',
      reply:          result.reply,
      day:            result.day,
      unavailable:    !!result.unavailable,
      configured:     hasStormglassConfig(),
      no_payment_write: true,
      no_whatsapp:    true,
      no_n8n:         true,
    });
  } catch (err) {
    // Degrade gracefully — a surf question must never dead-end the guest.
    const fb = buildReply({ unavailable: true });
    return sendJSON(res, 200, {
      success:     true,
      tool:        'get_surf_report',
      reply:       fb.reply,
      day,
      unavailable: true,
      configured:  false,
      detail:      err.message,
      no_payment_write: true,
      no_whatsapp: true,
      no_n8n:      true,
    });
  }
}

