// ─────────────────────────────────────────────────────────────────────────────
// POST /staff/bot/bookings/update-contact  (Luna: update guest name/email)
//   Name/email only — never package/dates/payment. Validated; audited; no payment,
//   WhatsApp, or n8n side effects.
// ─────────────────────────────────────────────────────────────────────────────
async function handleBotUpdateContact(req, res, user, authMode) {
  const started = Date.now();
  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return sendJSON(res, 400, { success: false, error: 'invalid or missing JSON body' });
  }
  const clientSlug  = String(body.client_slug || DEFAULT_CLIENT).trim();
  const bookingCode = String(body.booking_code || body.bookingCode || '').trim();
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!bookingCode || bookingCode.length > 64 || SQL_INJECT_RE.test(bookingCode)) {
    return sendJSON(res, 400, { success: false, error: 'valid booking_code is required' });
  }

  const patch = {};
  if (body.guest_name != null && String(body.guest_name).trim() !== '') {
    if (!editPreviewLightNameOk(body.guest_name)) return sendJSON(res, 400, { success: false, error: 'guest_name is too long' });
    patch.guest_name = String(body.guest_name).trim();
  }
  if (body.email != null && String(body.email).trim() !== '') {
    if (!editPreviewLightEmailOk(body.email)) return sendJSON(res, 400, { success: false, error: 'email format is invalid' });
    patch.email = String(body.email).trim();
  }
  if (patch.guest_name === undefined && patch.email === undefined) {
    return sendJSON(res, 400, { success: false, error: 'provide guest_name and/or email to update' });
  }

  try {
    const result = await withPgClient(async (pg) => {
      const bk = (await pg.query(EDIT_PREVIEW_BOOKING_BY_CODE_SQL, [clientSlug, bookingCode])).rows[0];
      if (!bk) return { notFound: true };
      const merged = editWriteMergeContactFields(bk, patch);
      const upd = await pg.query(EDIT_WRITE_CONTACT_UPDATE_SQL, [
        clientSlug, bk.booking_id, merged.guest_name, merged.phone, merged.email,
      ]);
      return { row: upd.rows[0] };
    });
    if (result.notFound) return sendJSON(res, 404, { success: false, error: `Booking not found: ${bookingCode}` });
    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:bot_update_contact',
      category: 'bot_booking_update_contact',
      client_slug: clientSlug,
      booking_code: bookingCode,
      updated_fields: Object.keys(patch),
      source: 'luna_guest',
      auth_mode: authMode || null,
      success: true,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 200, {
      success:        true,
      tool:           'update_booking_contact',
      updated_fields: Object.keys(patch),
      booking:        editWriteContactBookingSummary(result.row),
      write_performed: true,
      no_payment_write: true,
      no_whatsapp: true,
      no_n8n: true,
    });
  } catch (err) {
    return sendJSON(res, 500, { success: false, error: 'contact update failed', detail: err.message });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// POST /staff/bot/conversation/needs-human  (Luna flags a handoff for staff)
//   Sets conversations.needs_human = TRUE so the thread shows up in the portal's
//   "Needs Human" filter whenever Luna hands off / can't handle a request.
//   Finds the conversation by conversation_id or by the WhatsApp phone (last 9
//   digits). Read-only except the needs_human flag; no payment/WhatsApp/n8n.
// ─────────────────────────────────────────────────────────────────────────────
async function handleBotConversationNeedsHuman(req, res, user, authMode) {
  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return sendJSON(res, 400, { success: false, error: 'invalid or missing JSON body' });
  }
  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  const convId     = String(body.conversation_id || '').trim();
  const phone      = String(body.phone || body.guest_phone || '').trim();
  const reason     = String(body.reason || 'luna_safe_handoff').slice(0, 200);
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!convId && !phone) {
    return sendJSON(res, 400, { success: false, error: 'conversation_id or phone is required' });
  }

  try {
    const result = await withPgClient(async (pg) => {
      if (convId) {
        return markConversationNeedsHuman(pg, { conversation_id: convId, client_slug: clientSlug, reason });
      }
      const suffix = phone.replace(/\D/g, '').slice(-9);
      if (!suffix) return { ok: false, updated_count: 0 };
      const r = await pg.query(
        `UPDATE conversations conv
            SET needs_human = TRUE,
                updated_at = NOW(),
                metadata = COALESCE(conv.metadata, '{}'::jsonb)
                  || jsonb_build_object('luna_handoff_at', to_jsonb(NOW()),
                                        'luna_handoff_reason', to_jsonb($3::text))
           FROM clients c
          WHERE conv.client_id = c.id
            AND c.slug = $1
            AND regexp_replace(conv.phone, '\\D', '', 'g') LIKE $2
          RETURNING conv.id::text AS conversation_id, conv.needs_human`,
        [clientSlug, `%${suffix}`, reason],
      );
      return {
        ok: r.rowCount > 0,
        updated_count: r.rowCount,
        needs_human: r.rows[0] ? r.rows[0].needs_human === true : false,
        conversation_id: r.rows[0] ? r.rows[0].conversation_id : null,
      };
    });
    const ok = !!(result && (result.ok || result.updated_count > 0));
    return sendJSON(res, 200, {
      success:         ok,
      tool:            'flag_needs_human',
      needs_human:     !!(result && result.needs_human),
      conversation_id: (result && result.conversation_id) || null,
      no_payment_write: true,
      no_whatsapp:     true,
      no_n8n:          true,
    });
  } catch (err) {
    return sendJSON(res, 500, { success: false, error: 'needs_human update failed', detail: err.message });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Stage 7.7g — Bed calendar handler (read-only)
//
// GET /staff/bed-calendar?client=<slug>&start=YYYY-MM-DD&end=YYYY-MM-DD
//   Returns rooms/beds hierarchy + booking_beds blocks overlapping the range.
//   Date-span arithmetic (start_offset, span_days, is_arrival, is_departure)
//   and color_type classification are computed in JS after the DB read.
//
// Safety: SELECT-only. No mutations. Viewer auth minimum. Fully audited.
// ─────────────────────────────────────────────────────────────────────────────

const DATE_RE = /^\d{4}-\d{2}-\d{2}$/;
const MAX_CALENDAR_DAYS = 90;

function parseCalendarDate(str) {
  if (!str || !DATE_RE.test(str)) return null;
  const d = new Date(str + 'T00:00:00Z');
  if (isNaN(d.getTime())) return null;
  return d;
}

function generateCalendarDays(startDate, endDate) {
  const DAY_MS = 86400000;
  const DAY_LABELS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const days = [];
  let cur = new Date(startDate.getTime());
  while (cur < endDate) {
    const iso = cur.toISOString().slice(0, 10);
    days.push({ date: iso, label: DAY_LABELS[cur.getUTCDay()] + ' ' + String(cur.getUTCDate()).padStart(2, '0') });
    cur = new Date(cur.getTime() + DAY_MS);
  }
  return days;
}

function bedCalendarIsLunaBotSource(row) {
  const src = String(row.booking_source || '').toLowerCase();
  const metaSrc = String(row.metadata_source || row.source || '').toLowerCase();
  const botSrc = String(row.bot_source || '').toLowerCase();
  const createdBy = String(row.metadata_created_by || row.created_by || '').toLowerCase();
  const channel = String(row.channel || '').toLowerCase();
  const staffSrc = String(row.staff_source || '').toLowerCase();

  const hay = [src, metaSrc, botSrc, createdBy, channel, staffSrc].join('|');
  const lunaMarkers = [
    'luna', 'bot', 'whatsapp', 'guest_bot', 'n8n', 'bot_', 'luna_',
    'bot_booking', 'bot_stage', 'luna_guest', 'luna_whatsapp',
  ];
  if (lunaMarkers.some((m) => hay.includes(m))) return true;

  const staffSources = new Set([
    'manual_staff', 'manual', 'staff', 'staff_manual', 'operator', 'tour_operator',
  ]);
  if (staffSources.has(src) || src.includes('operator')) return false;

  return false;
}

function bedCalendarIsTourOperatorSource(row) {
  row = row || {};
  const src = String(row.booking_source || '').toLowerCase();
  if (src === 'operator' || src === 'tour_operator') return true;
  if (row.is_operator_block) return true;
  return false;
}

/** Main block color = booking source only (badges carry payment/status). */
function bedCalendarColorType(row) {
  if (bedCalendarIsLunaBotSource(row)) return 'payment_pending';
  if (bedCalendarIsTourOperatorSource(row)) return 'tour_operator';
  return 'confirmed';
}

function computeBlockSpan(row, startDate, endDate) {
  const DAY_MS = 86400000;
  const bStart = new Date(row.assignment_start_date + 'T00:00:00Z');
  const bEnd   = new Date(row.assignment_end_date   + 'T00:00:00Z');
  const clipStart = bStart < startDate ? startDate : bStart;
  const clipEnd   = bEnd   > endDate   ? endDate   : bEnd;
  return {
    start_offset: Math.round((clipStart - startDate) / DAY_MS),
    span_days:    Math.max(0, Math.round((clipEnd - clipStart) / DAY_MS)),
    is_arrival:   bStart >= startDate && bStart < endDate,
    is_departure: bEnd   >  startDate && bEnd   <= endDate,
  };
}

function buildRoomHierarchy(roomRows) {
  const rooms   = [];
  const roomMap = {};
  for (const row of roomRows) {
    if (!roomMap[row.room_code]) {
      roomMap[row.room_code] = {
        room_code:   row.room_code,
        room_name:   row.room_name  || row.room_code,
        house:       row.house      || null,
        room_type:   row.room_type  || null,
        capacity:    row.capacity   || 0,
        sort_order:  row.room_sort_order != null ? Number(row.room_sort_order)
          : (row.fill_priority != null ? Number(row.fill_priority) : 999),
        fill_priority: row.fill_priority != null ? Number(row.fill_priority) : null,
        gender_strategy: row.gender_strategy || null,
        beds: [],
      };
      rooms.push(roomMap[row.room_code]);
    }
    if (row.bed_code) {
      roomMap[row.room_code].beds.push({
        bed_id:    row.bed_id || null,
        bed_code:  row.bed_code,
        bed_label: row.bed_label || row.bed_code,
        sort_order: row.bed_number != null ? Number(row.bed_number) : 0,
      });
    }
  }
  return rooms;
}

/* Phase 10.6g — calendar payment badge state (ledger truth; separate from booking.status) */
function calendarBlockPaymentState(row) {
  const display = bookingCalendarPaymentDisplayState(
    {
      invoice_total_cents: row.invoice_total_cents,
      paid_total_cents: row.ledger_paid_cents,
      balance_due_cents: row.balance_due_cents,
      deposit_required_cents: row.deposit_required_cents,
    },
    row.has_active_payment_link,
  );
  if (!display) return null;
  return {
    kind: display.primary,
    amount_cents: display.amount_cents,
    show_deposit_paid: display.show_deposit_paid,
    has_active_payment_link: display.has_active_payment_link,
  };
}

const BED_CALENDAR_BOOKING_LEDGER_SQL = `
SELECT b.id::text AS booking_id,
       b.total_amount_cents,
       b.deposit_required_cents,
       b.metadata,
       COALESCE(paid.paid_cents, 0)::bigint AS ledger_paid_cents,
       COALESCE(svc.svc_due_cents, 0)::bigint AS svc_due_cents
  FROM bookings b
  LEFT JOIN (
    SELECT booking_id, SUM(amount_paid_cents)::bigint AS paid_cents
      FROM payments
     WHERE booking_id = ANY($1::uuid[])
       AND status = 'paid'::payment_record_status
     GROUP BY booking_id
  ) paid ON paid.booking_id = b.id
  LEFT JOIN (
    SELECT booking_id, SUM(amount_due_cents)::bigint AS svc_due_cents
      FROM booking_service_records
     WHERE booking_id = ANY($1::uuid[])
     GROUP BY booking_id
  ) svc ON svc.booking_id = b.id
 WHERE b.id = ANY($1::uuid[])
`;

const BED_CALENDAR_UNPAID_LINK_SQL = `
SELECT p.booking_id::text AS booking_id,
       p.id::text AS payment_id,
       p.status::text AS payment_status,
       p.payment_kind::text AS payment_kind,
       p.amount_due_cents,
       p.amount_paid_cents,
       p.checkout_url,
       p.metadata
  FROM payments p
 WHERE p.booking_id = ANY($1::uuid[])
   AND p.status IN ('checkout_created'::payment_record_status, 'draft'::payment_record_status, 'pending'::payment_record_status)
   AND COALESCE(p.amount_paid_cents, 0) = 0
   AND p.checkout_url IS NOT NULL
`;

const BED_CALENDAR_TRANSFER_CHARGES_SQL = `
SELECT booking_id::text AS booking_id,
       COALESCE(SUM(price_cents), 0)::bigint AS transfer_due_cents
  FROM booking_transfers
 WHERE booking_id = ANY($1::uuid[])
   AND status IN ('requested', 'confirmed')
   AND COALESCE(price_cents, 0) > 0
 GROUP BY booking_id
`;

function mergeBedCalendarPaymentSnapshots(blockRows, ledgerRows, linkRows, transferRows) {
  const ledgerById = {};
  for (const r of ledgerRows || []) ledgerById[r.booking_id] = r;
  const transferById = {};
  for (const r of transferRows || []) transferById[r.booking_id] = Number(r.transfer_due_cents || 0);
  const linksById = {};
  for (const pr of linkRows || []) {
    if (!linksById[pr.booking_id]) linksById[pr.booking_id] = [];
    linksById[pr.booking_id].push(pr);
  }
  for (const row of blockRows) {
    const snap = ledgerById[row.booking_id] || {};
    const bookingRow = {
      total_amount_cents: snap.total_amount_cents,
      deposit_required_cents: snap.deposit_required_cents,
      metadata: snap.metadata,
    };
    const totals = bookingLedgerInvoicePaidBalance(
      bookingRow,
      snap.svc_due_cents,
      snap.ledger_paid_cents,
      transferById[row.booking_id] || 0,
    );
    const ledgerCtx = {
      balance_due_cents: totals.balance_due_cents,
      deposit_required_cents: totals.deposit_required_cents,
      invoice_total_cents: totals.invoice_total_cents,
    };
    const links = linksById[row.booking_id] || [];
    const hasActiveLink = paymentLedgerHasActiveValidLink(links, ledgerCtx);
    row.invoice_total_cents = totals.invoice_total_cents;
    row.ledger_paid_cents = totals.paid_total_cents;
    row.balance_due_cents = totals.balance_due_cents;
    row.deposit_required_cents = totals.deposit_required_cents;
    row.amount_paid_cents = totals.paid_total_cents;
    row.total_amount_cents = totals.invoice_total_cents;
    row.has_active_payment_link = hasActiveLink;
  }
}

/** Guest-first calendar label; booking_code only when no human name is available. */
function pickCalendarGuestDisplayName(src) {
  src = src || {};
  const code = String(src.booking_code || '').trim();
  const norm = (v) => {
    const s = String(v || '').trim();
    if (!s || s === '\u2014') return '';
    if (code && s.toLowerCase() === code.toLowerCase()) return '';
    return s;
  };
  const bookingGuest = norm(src.guest_name);
  const bedGuest = norm(src.bed_guest_name);
  const planning = norm(src.planning_row_label || src.assignment_label);
  const resolved = bookingGuest || bedGuest || planning;
  if (resolved) return resolved;
  return code || '\u2014';
}

function calendarBlockDisplayLabel(row) {
  return pickCalendarGuestDisplayName(row);
}

function buildCalendarBlocks(blockRows, startDate, endDate) {
  return blockRows
    .filter(row => !bookingStatusIsCancelled(row.booking_status))
    .map(row => {
    const span = computeBlockSpan(row, startDate, endDate);
    const payState = calendarBlockPaymentState(row);
    const displayGuest = pickCalendarGuestDisplayName(row);
    const displayGuestOrNull = displayGuest && displayGuest !== '\u2014' ? displayGuest : null;
    return {
      booking_id:        row.booking_id,
      booking_code:      row.booking_code,
      guest_name:        displayGuestOrNull,
      bed_guest_name:    String(row.bed_guest_name || '').trim() || null,
      planning_row_label: row.planning_row_label || null,
      assignment_label:  row.assignment_label || null,
      phone:             row.phone || null,
      status:            row.booking_status,
      payment_status:    row.payment_status,
      assignment_status: row.assignment_status,
      booking_source:    row.booking_source || null,
      block_type:        row.block_type || null,
      is_operator_block: !!row.is_operator_block,
      room_code:         row.room_code,
      bed_code:          row.bed_code,
      start_date:        row.assignment_start_date,
      end_date:          row.assignment_end_date,
      start_offset:      span.start_offset,
      span_days:         span.span_days,
      label:             calendarBlockDisplayLabel(row),
      color_type:        bedCalendarColorType(row),
      needs_review:      !!(row.needs_rooming_review || (row.assignment_status || '').toLowerCase() === 'needs_review'),
      is_arrival:        span.is_arrival,
      is_departure:      span.is_departure,
      invoice_total_cents: row.invoice_total_cents != null ? Number(row.invoice_total_cents) : null,
      ledger_paid_cents: row.ledger_paid_cents != null ? Number(row.ledger_paid_cents) : null,
      deposit_required_cents: row.deposit_required_cents != null ? Number(row.deposit_required_cents) : null,
      total_amount_cents: row.invoice_total_cents != null ? Number(row.invoice_total_cents) : null,
      amount_paid_cents:  row.ledger_paid_cents != null ? Number(row.ledger_paid_cents) : null,
      balance_due_cents:  row.balance_due_cents != null ? Number(row.balance_due_cents) : null,
      has_active_payment_link: !!row.has_active_payment_link,
      calendar_payment_primary: payState ? payState.kind : null,
      calendar_payment_amount_cents: payState ? payState.amount_cents : null,
      calendar_show_deposit_paid: payState ? !!payState.show_deposit_paid : false,
      calendar_payment_state: payState ? payState.kind : null,
    };
  }).filter(b => b.span_days > 0);
}

async function handleBedCalendar(query, res, user) {
  const started    = Date.now();
  const clientSlug = (String(query.client || DEFAULT_CLIENT)).trim();
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');

  const startDate = parseCalendarDate(query.start);
  const endDate   = parseCalendarDate(query.end);
  if (!startDate) return send400(res, 'start is required and must be YYYY-MM-DD');
  if (!endDate)   return send400(res, 'end is required and must be YYYY-MM-DD');
  if (endDate <= startDate) return send400(res, 'end must be after start');

  const daysDiff = Math.round((endDate - startDate) / 86400000);
  if (daysDiff > MAX_CALENDAR_DAYS) {
    return send400(res, `date range too large (max ${MAX_CALENDAR_DAYS} days)`);
  }

  const startISO = query.start;
  const endISO   = query.end;

  const auditBase = {
    ts:            new Date().toISOString(),
    intent:        'api:bed_calendar',
    category:      'bed_calendar_api',
    client_slug:   clientSlug,
    params_start:  startISO,
    params_end:    endISO,
    staff_user_id: user ? user.staff_user_id : null,
  };

  let roomRows = [], blockRows = [], summaryRows = [], transferRows = [];
  try {
    [roomRows, blockRows, summaryRows, transferRows] = await withPgClient(async (pg) => {
      const [rr, br, sr, tr] = await Promise.all([
        pg.query(getBedCalendarRoomsQuery(),   [clientSlug]),
        pg.query(getBedCalendarBlocksQuery(),  [clientSlug, startISO, endISO]),
        pg.query(getBedCalendarSummaryQuery(), [clientSlug, startISO, endISO]),
        listBookingTransfersForCalendarRange(pg, {
          client_slug: clientSlug,
          start_date: startISO,
          end_date: endISO,
        }),
      ]);
      const rows = br.rows;
      const bookingIds = [...new Set(rows.map((r) => r.booking_id).filter(Boolean))];
      if (bookingIds.length > 0) {
        const [ledgerSnap, linkRows, transferSnap] = await Promise.all([
          pg.query(BED_CALENDAR_BOOKING_LEDGER_SQL, [bookingIds]),
          pg.query(BED_CALENDAR_UNPAID_LINK_SQL, [bookingIds]),
          pg.query(BED_CALENDAR_TRANSFER_CHARGES_SQL, [bookingIds]),
        ]);
        mergeBedCalendarPaymentSnapshots(rows, ledgerSnap.rows, linkRows.rows, transferSnap.rows);
        const srcRes = await pg.query(
          `SELECT id::text AS booking_id,
                  booking_source::text,
                  block_type::text,
                  metadata->>'source' AS metadata_source,
                  metadata->>'bot_source' AS bot_source,
                  metadata->>'created_by' AS metadata_created_by,
                  metadata->>'staff_source' AS staff_source
           FROM bookings WHERE id = ANY($1::uuid[])`,
          [bookingIds]
        );
        const srcMap = Object.fromEntries(srcRes.rows.map((r) => [r.booking_id, r]));
        for (const row of rows) {
          const extra = srcMap[row.booking_id];
          if (extra) {
            row.booking_source = extra.booking_source;
            row.block_type = extra.block_type;
            row.metadata_source = extra.metadata_source;
            row.bot_source = extra.bot_source;
            row.metadata_created_by = extra.metadata_created_by;
            row.staff_source = extra.staff_source;
            row.is_operator_block = extra.booking_source === 'operator' && extra.block_type === 'whole_room';
          }
        }
      }
      return [rr.rows, rows, sr.rows, tr];
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'query failed', detail: err.message });
  }

  roomRows = resolveBedCalendarRoomRows(clientSlug, roomRows);
  blockRows = filterDemoCalendarBlocks(blockRows);

  const rooms  = buildRoomHierarchy(roomRows);
  const days   = generateCalendarDays(startDate, endDate);
  const transfersByBookingId = buildTransferSummariesByBookingId(transferRows);
  const blocks = buildCalendarBlocks(blockRows, startDate, endDate).map((b) => ({
    ...b,
    transfer_summary: transfersByBookingId[b.booking_id] || emptyTransferSummary(),
  }));

  const elapsed = Date.now() - started;
  appendAuditLog({
    ...auditBase,
    success:     true,
    room_count:  rooms.length,
    day_count:   days.length,
    block_count: blocks.length,
    elapsed_ms:  elapsed,
  });

  return sendJSON(res, 200, {
    success:      true,
    client_slug:  clientSlug,
    start:        startISO,
    end:          endISO,
    days,
    rooms,
    blocks,
    summary:      summaryRows,
    warnings:     [],
    elapsed_ms:   elapsed,
    inventory_source: isWolfhouseInventoryClient(clientSlug)
      ? 'wolfhouse_airtable_csv' : 'rooms_table',
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 10.7a — Tour Operator block create + room release (staff portal)
//
// GET  /staff/tour-operator/rooms?client=<slug>
// GET  /staff/tour-operator/blocks?client=<slug>
// POST /staff/tour-operator/blocks/preview
// POST /staff/tour-operator/blocks/create
// POST /staff/tour-operator/release/preview
// POST /staff/tour-operator/release
//
// Writes: bookings + booking_beds (+ operator_room_release_requests on release).
// No payments, booking_service_records, Stripe, WhatsApp, or n8n.
// ─────────────────────────────────────────────────────────────────────────────

const TO_OPERATOR_BLOCKS_LIST_SQL = `
SELECT
  b.id::text              AS booking_id,
  b.booking_code,
  b.operator_name,
  b.guest_name,
  b.check_in::text        AS check_in,
  b.check_out::text       AS check_out,
  b.primary_room_code     AS room_code,
  b.status::text          AS status,
  b.block_type::text      AS block_type
FROM bookings b
INNER JOIN clients c ON c.id = b.client_id
WHERE c.slug = $1
  AND b.booking_source = 'operator'
  AND b.block_type = 'whole_room'
  AND b.status NOT IN ('cancelled', 'expired')
ORDER BY b.check_in DESC, b.operator_name ASC NULLS LAST, b.booking_code ASC
`;

const TO_ROOM_BEDS_FOR_BLOCK_SQL = `
SELECT
  bd.id::text             AS bed_id,
  bd.bed_code,
  r.id::text              AS room_id,
  r.room_code
FROM beds bd
INNER JOIN rooms r ON r.id = bd.room_id
INNER JOIN clients c ON c.id = bd.client_id
WHERE c.slug = $1
  AND upper(trim(r.room_code)) = upper(trim($2))
  AND r.active = TRUE
  AND bd.active = TRUE
  AND bd.sellable = TRUE
ORDER BY COALESCE(bd.bed_number, 999) ASC, bd.bed_code ASC
`;

const TO_BED_CONFLICTS_SQL = `
SELECT
  bb.bed_code,
  b.booking_code,
  b.booking_source::text  AS booking_source
FROM booking_beds bb
INNER JOIN bookings b ON b.id = bb.booking_id
INNER JOIN clients c ON c.id = b.client_id
INNER JOIN beds bd ON bd.id = bb.bed_id
INNER JOIN rooms r ON r.id = bd.room_id
WHERE c.slug = $1
  AND upper(trim(r.room_code)) = upper(trim($2))
  AND bb.assignment_start_date < $4::date
  AND bb.assignment_end_date   > $3::date
  AND b.status NOT IN ('cancelled', 'expired')
ORDER BY bb.bed_code ASC, b.booking_code ASC
`;

const TO_OPERATOR_BOOKING_BY_ID_SQL = `
SELECT
  b.id,
  b.booking_code,
  b.operator_name,
  b.primary_room_code,
  b.check_in::text AS check_in,
  b.check_out::text AS check_out,
  b.status::text AS status,
  b.booking_source::text AS booking_source,
  b.block_type::text AS block_type
FROM bookings b
INNER JOIN clients c ON c.id = b.client_id
WHERE c.slug = $1 AND b.id = $2::uuid
LIMIT 1
`;

const TO_RELEASE_BLOCKING_ACTIONS = new Set([
  'missing_required_fields',
  'invalid_date_range',
  'client_not_found',
  'room_not_found',
  'no_matching_operator_booking',
  'ambiguous_operator_booking_match',
  'release_window_does_not_overlap_original_block',
  'postgres_overlap_conflicts_in_release_window',
  'booking_id_mismatch',
]);

function generateTourOperatorBookingCode() {
  const d = new Date().toISOString().slice(0, 10).replace(/-/g, '');
  const rand = crypto.randomBytes(3).toString('hex');
  return `OP-${d}-${rand}`.toUpperCase();
}

function tourOperatorReleaseInputFromBody(body, clientSlug) {
  return {
    clientSlug,
    operator: normalizeOperatorName(body.operator || body.operator_name || ''),
    roomCode: normalizeRoomCode(body.room_code || body.room || ''),
    releaseStart: String(body.release_start || body.release_start_date || '').trim(),
    releaseEnd: String(body.release_end || body.release_end_date || '').trim(),
    requestCode: body.idempotency_key ? String(body.idempotency_key).slice(0, 120) : null,
    notes: String(body.reason || body.notes || '').trim().slice(0, 2000) || null,
    releaseRecordId: null,
  };
}

function tourOperatorPlanIsBlocked(plan) {
  if (!plan || plan.error) return true;
  return (plan.actionable || []).some((a) => TO_RELEASE_BLOCKING_ACTIONS.has(a));
}

/** All active/sellable beds in room — booking_beds for operator whole_room blocks. */
async function tourOperatorAssignWholeRoomBeds(pg, {
  clientId,
  clientSlug,
  bookingId,
  roomCode,
  checkIn,
  checkOut,
  operatorName,
  assignmentNotes = 'Staff Portal tour operator whole-room block',
  replaceExisting = true,
}) {
  const beds = (await pg.query(TO_ROOM_BEDS_FOR_BLOCK_SQL, [clientSlug, roomCode])).rows;
  if (!beds.length) {
    throw Object.assign(new Error('room_not_found_or_no_active_beds'), { code: 'no_room_beds' });
  }
  if (replaceExisting) {
    await pg.query(
      `DELETE FROM booking_beds WHERE client_id = $1 AND booking_id = $2`,
      [clientId, bookingId]
    );
  }
  for (const bed of beds) {
    await pg.query(
      `INSERT INTO booking_beds (
         client_id, booking_id, bed_id, assignment_type, assignment_notes,
         assignment_start_date, assignment_end_date, guest_name, room_code, bed_code
       ) VALUES (
         $1, $2, $3::uuid, 'operator_block', $4,
         $5::date, $6::date, $7, $8, $9
       )`,
      [
        clientId, bookingId, bed.bed_id, assignmentNotes,
        checkIn, checkOut, operatorName, bed.room_code, bed.bed_code,
      ]
    );
  }
  const cntRes = await pg.query(
    `SELECT COUNT(*)::int AS c FROM booking_beds WHERE client_id = $1 AND booking_id = $2`,
    [clientId, bookingId]
  );
  const actual = cntRes.rows[0].c;
  if (actual !== beds.length) {
    throw Object.assign(new Error('operator_bed_assignment_count_mismatch'), {
      expected: beds.length,
      actual,
      booking_id: bookingId,
    });
  }
  await pg.query(
    `UPDATE bookings SET assignment_status = 'assigned' WHERE id = $1 AND client_id = $2`,
    [bookingId, clientId]
  );
  return { bed_count: beds.length, bed_codes: beds.map((b) => b.bed_code) };
}

function toReleaseAppendStaffNotes(existing, note) {
  const base = String(existing || '').trim();
  const addition = String(note || '').trim();
  if (!addition) return base || null;
  if (!base) return addition;
  if (base.includes(addition)) return base;
  return `${base}\n${addition}`;
}

async function toReleaseInsertBlockBooking(pg, clientId, bookingCode, blockPreview, operatorName, roomCode, roomId, splitNote) {
  const metadata = JSON.stringify({
    operator_release_block: bookingCode.endsWith('-A') ? 'A' : 'B',
    operator_release_parent: bookingCode.replace(/-[AB]$/, ''),
    source: 'operator-room-release-staff-portal',
  });
  const staffNotes = `${splitNote}\n${TO_RELEASE_EXECUTE_NOTES}`;
  const { rows } = await pg.query(
    `INSERT INTO bookings (
       client_id, booking_code, guest_name, operator_name, booking_source, block_type,
       status, payment_status, assignment_status, availability_check_status,
       check_in, check_out, guest_count, primary_room_code, room_to_block_id,
       staff_notes, deposit_required_cents, deposit_paid_cents, balance_due_cents,
       total_amount_cents, amount_paid_cents, metadata
     ) VALUES (
       $1, $2, $3, $4, 'operator', 'whole_room', 'confirmed', 'not_requested',
       'unassigned', 'unknown', $5::date, $6::date, 1, $7, $8, $9,
       0, 0, 0, 0, 0, $10::jsonb
     )
     RETURNING id, booking_code, check_in::text AS check_in, check_out::text AS check_out`,
    [
      clientId, bookingCode, operatorName, operatorName,
      blockPreview.check_in, blockPreview.check_out, roomCode, roomId, staffNotes, metadata,
    ]
  );
  return rows[0];
}

async function toReleaseUpsertRequestProcessing(pg, clientId, input, roomId) {
  if (input.requestCode) {
    const { rows: existing } = await pg.query(
      `SELECT id, status::text AS status FROM operator_room_release_requests
       WHERE client_id = $1 AND request_code = $2 ORDER BY updated_at DESC LIMIT 1`,
      [clientId, input.requestCode]
    );
    if (existing.length && existing[0].status === 'processing') {
      return { error: 'request_stuck_processing', request_id: existing[0].id };
    }
    if (existing.length && existing[0].status !== 'completed') {
      const { rows } = await pg.query(
        `UPDATE operator_room_release_requests
         SET status = 'processing', operator_name = $3, room_id = $4, room_code = $5,
             release_start_date = $6::date, release_end_date = $7::date,
             notes = COALESCE($8, notes), error_notes = NULL, updated_at = NOW()
         WHERE id = $1 AND client_id = $2 RETURNING id`,
        [
          existing[0].id, clientId, input.operator, roomId, input.roomCode,
          input.releaseStart, input.releaseEnd, input.notes || null,
        ]
      );
      return { request_id: rows[0].id, created: false };
    }
  }
  const { rows } = await pg.query(
    `INSERT INTO operator_room_release_requests (
       client_id, operator_name, room_id, room_code, release_start_date, release_end_date,
       request_code, notes, status, airtable_record_id
     ) VALUES ($1, $2, $3, $4, $5::date, $6::date, $7, $8, 'processing', $9)
     RETURNING id`,
    [
      clientId, input.operator, roomId, input.roomCode,
      input.releaseStart, input.releaseEnd, input.requestCode || null,
      input.notes || null, input.releaseRecordId || null,
    ]
  );
  return { request_id: rows[0].id, created: true };
}

async function toReleaseAssertPaymentsUnchanged(pg, clientId, bookingId, paymentsBefore, paymentStatusBefore) {
  const paymentsAfter = await toReleaseCountPayments(pg, clientId, bookingId);
  if (paymentsAfter !== paymentsBefore) {
    throw new Error('payments row count changed unexpectedly');
  }
  const { rows } = await pg.query(
    `SELECT payment_status::text AS payment_status FROM bookings WHERE id = $1 AND client_id = $2`,
    [bookingId, clientId]
  );
  if (rows[0].payment_status !== paymentStatusBefore) {
    throw new Error('payment_status changed unexpectedly');
  }
}

/** Release execute with A/B remainder booking_beds for all active/sellable room beds. */
async function tourOperatorExecuteRoomRelease(pg, plan, input) {
  const clientId = plan.client_id;
  const cancel = plan.cancel_phase;
  const split = plan.split_phase;
  const original = cancel.original_booking_preview;
  const originalBookingId = original.booking_id;
  const originalBookingCode = original.booking_code;
  const clientSlug = input.clientSlug;
  const roomCode = input.roomCode;

  const completed = await toReleaseFindCompletedRequest(pg, clientId, input.requestCode);
  if (completed) {
    const orig = await toReleaseLoadBookingSummary(pg, clientId, completed.original_booking_id);
    const blockA = completed.new_booking_a_id
      ? await toReleaseLoadBookingSummary(pg, clientId, completed.new_booking_a_id) : null;
    const blockB = completed.new_booking_b_id
      ? await toReleaseLoadBookingSummary(pg, clientId, completed.new_booking_b_id) : null;
    return {
      idempotent: true,
      request_id: completed.id,
      request_code: completed.request_code,
      original_booking: orig,
      block_a: blockA,
      block_b: blockB,
    };
  }

  const { rows: origRows } = await pg.query(
    `SELECT id, booking_code, status::text AS status, payment_status::text AS payment_status,
            staff_notes, assignment_status::text AS assignment_status
     FROM bookings WHERE id = $1 AND client_id = $2 FOR UPDATE`,
    [originalBookingId, clientId]
  );
  if (!origRows.length) return { error: 'original_booking_not_found' };
  const origBooking = origRows[0];

  if (origBooking.status === 'cancelled' || origBooking.status === 'expired') {
    return {
      error: 'already_cancelled_ambiguous',
      booking_code: origBooking.booking_code,
      status: origBooking.status,
    };
  }

  const paymentsBefore = await toReleaseCountPayments(pg, clientId, originalBookingId);
  const eventsBefore = await toReleaseCountPaymentEvents(pg, clientId, originalBookingId);
  if (paymentsBefore > 0 || eventsBefore > 0) {
    return {
      error: 'payments_exist',
      payments_count: paymentsBefore,
      payment_events_count: eventsBefore,
    };
  }

  const blockValidation = await toReleaseValidateBlockCodes(
    pg, clientId, originalBookingCode, split
  );
  if (blockValidation.error) return blockValidation;

  const { codes } = blockValidation;
  const splitNote = split.split_note;
  const operatorName = input.operator;

  await pg.query('BEGIN');
  try {
    const req = await toReleaseUpsertRequestProcessing(pg, clientId, input, plan.room.room_id);
    if (req.error) {
      throw Object.assign(new Error(req.error), { code: req.error, details: req });
    }

    const deleteBeds = await pg.query(
      `DELETE FROM booking_beds WHERE client_id = $1 AND booking_id = $2`,
      [clientId, originalBookingId]
    );

    const newStaffNotes = toReleaseAppendStaffNotes(origBooking.staff_notes, splitNote);
    const updateOrig = await pg.query(
      `UPDATE bookings
       SET status = 'cancelled', assignment_status = 'needs_review',
           availability_check_status = 'needs_review', staff_notes = $3, updated_at = NOW()
       WHERE id = $1 AND client_id = $2`,
      [originalBookingId, clientId, newStaffNotes]
    );

    let blockAId = blockValidation.existing_a?.id || null;
    let blockBId = blockValidation.existing_b?.id || null;
    let blockACode = null;
    let blockBCode = null;
    let blockABeds = null;
    let blockBBeds = null;

    if (split.should_create_a && !blockAId) {
      const row = await toReleaseInsertBlockBooking(
        pg, clientId, codes.a, split.block_a, operatorName, roomCode, plan.room.room_id, splitNote
      );
      blockAId = row.id;
      blockACode = row.booking_code;
    } else if (blockAId) {
      blockACode = codes.a;
    }
    if (blockAId && split.block_a) {
      blockABeds = await tourOperatorAssignWholeRoomBeds(pg, {
        clientId, clientSlug, bookingId: blockAId, roomCode,
        checkIn: split.block_a.check_in, checkOut: split.block_a.check_out, operatorName,
        assignmentNotes: 'Operator room release remainder segment A',
      });
    }

    if (split.should_create_b && !blockBId) {
      const row = await toReleaseInsertBlockBooking(
        pg, clientId, codes.b, split.block_b, operatorName, roomCode, plan.room.room_id, splitNote
      );
      blockBId = row.id;
      blockBCode = row.booking_code;
    } else if (blockBId) {
      blockBCode = codes.b;
    }
    if (blockBId && split.block_b) {
      blockBBeds = await tourOperatorAssignWholeRoomBeds(pg, {
        clientId, clientSlug, bookingId: blockBId, roomCode,
        checkIn: split.block_b.check_in, checkOut: split.block_b.check_out, operatorName,
        assignmentNotes: 'Operator room release remainder segment B',
      });
    }

    await pg.query(
      `UPDATE operator_room_release_requests
       SET status = 'completed', original_booking_id = $3, new_booking_a_id = $4,
           new_booking_b_id = $5, error_notes = NULL, updated_at = NOW()
       WHERE id = $1 AND client_id = $2`,
      [req.request_id, clientId, originalBookingId, blockAId, blockBId]
    );

    await toReleaseAssertPaymentsUnchanged(
      pg, clientId, originalBookingId, paymentsBefore, origBooking.payment_status
    );

    await pg.query('COMMIT');

    return {
      idempotent: false,
      request_id: req.request_id,
      request_code: input.requestCode || null,
      original_booking_id: originalBookingId,
      original_booking_code: originalBookingCode,
      deleted_beds: deleteBeds.rowCount,
      booking_rows_updated: updateOrig.rowCount,
      block_a: blockAId ? {
        id: blockAId,
        booking_code: blockACode || codes.a,
        bed_count: blockABeds ? blockABeds.bed_count : 0,
        bed_codes: blockABeds ? blockABeds.bed_codes : [],
      } : null,
      block_b: blockBId ? {
        id: blockBId,
        booking_code: blockBCode || codes.b,
        bed_count: blockBBeds ? blockBBeds.bed_count : 0,
        bed_codes: blockBBeds ? blockBBeds.bed_codes : [],
      } : null,
      payments_count: paymentsBefore,
      payment_events_count: eventsBefore,
    };
  } catch (err) {
    await pg.query('ROLLBACK');
    if (input.requestCode) {
      await pg.query(
        `UPDATE operator_room_release_requests
         SET status = 'failed', error_notes = $3, updated_at = NOW()
         WHERE client_id = $1 AND request_code = $2 AND status = 'processing'`,
        [clientId, input.requestCode, String(err.message || err).slice(0, 500)]
      ).catch(() => {});
    }
    throw err;
  }
}

