async function handleTourOperatorBlockPreview(req, res, user) {
  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }
  const clientSlug = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const operatorName = normalizeOperatorName(body.operator_name || body.operator || '');
  const roomCode = normalizeRoomCode(body.room_code || body.room || '');
  const checkIn = String(body.check_in || '').trim();
  const checkOut = String(body.check_out || '').trim();
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!operatorName) return send400(res, 'operator_name is required');
  if (!roomCode) return send400(res, 'room_code is required');
  if (!DATE_RE.test(checkIn) || !DATE_RE.test(checkOut)) return send400(res, 'check_in and check_out must be YYYY-MM-DD');
  if (checkOut <= checkIn) return send400(res, 'check_out must be after check_in');

  try {
    const preview = await withPgClient(async (pg) => {
      const beds = (await pg.query(TO_ROOM_BEDS_FOR_BLOCK_SQL, [clientSlug, roomCode])).rows;
      if (!beds.length) return { error: 'room_not_found_or_no_beds', room_code: roomCode };
      const conflicts = (await pg.query(TO_BED_CONFLICTS_SQL, [clientSlug, roomCode, checkIn, checkOut])).rows;
      return {
        operator_name: operatorName,
        room_code: roomCode,
        check_in: checkIn,
        check_out: checkOut,
        bed_count: beds.length,
        bed_codes: beds.map((b) => b.bed_code),
        conflicts,
        has_conflict: conflicts.length > 0,
        can_create: conflicts.length === 0,
      };
    });
    if (preview.error) return sendJSON(res, 404, { success: false, ...preview });
    return sendJSON(res, 200, { success: true, preview, send_mutation: false });
  } catch (err) {
    return sendJSON(res, 500, { success: false, error: 'preview failed', detail: err.message });
  }
}

async function handleTourOperatorBlockCreate(req, res, user) {
  if (!STAFF_ACTIONS_ENABLED) {
    return sendJSON(res, 403, {
      success: false,
      error: 'Staff write actions are disabled. Set STAFF_ACTIONS_ENABLED=true to enable.',
    });
  }
  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }
  const clientSlug = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const operatorName = normalizeOperatorName(body.operator_name || body.operator || '');
  const roomCode = normalizeRoomCode(body.room_code || body.room || '');
  const checkIn = String(body.check_in || '').trim();
  const checkOut = String(body.check_out || '').trim();
  const manager = String(body.manager || body.contact || '').trim().slice(0, 200) || null;
  const phone = String(body.phone || '').trim().slice(0, 50) || null;
  const email = String(body.email || '').trim().slice(0, 200) || null;
  const notes = String(body.notes || '').trim().slice(0, 2000) || null;
  const staffNote = String(body.staff_note || body.internal_staff_note || '').trim().slice(0, 2000) || null;
  const confirm = body.confirm === true;
  const actorId = user ? user.staff_user_id : 'tour-operator-local';
  const actorRole = user ? user.role : 'operator';

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!operatorName) return send400(res, 'operator_name is required');
  if (!roomCode) return send400(res, 'room_code is required');
  if (!DATE_RE.test(checkIn) || !DATE_RE.test(checkOut)) return send400(res, 'check_in and check_out must be YYYY-MM-DD');
  if (checkOut <= checkIn) return send400(res, 'check_out must be after check_in');
  if (!confirm) return send400(res, 'confirm: true is required');

  const staffNotesParts = [];
  if (notes) staffNotesParts.push(notes);
  if (staffNote) staffNotesParts.push('[staff] ' + staffNote);
  staffNotesParts.push(`Tour operator block created via Staff Portal (${actorId})`);
  const staffNotes = staffNotesParts.join('\n');

  const auditBase = {
    ts: new Date().toISOString(),
    intent: 'api:tour_operator_block_create',
    category: 'tour_operator',
    client_slug: clientSlug,
    operator_name: operatorName,
    room_code: roomCode,
    check_in: checkIn,
    check_out: checkOut,
    staff_user_id: actorId,
    stripe_called: false,
    whatsapp_called: false,
    n8n_called: false,
  };

  try {
    const result = await withPgClient(async (pg) => {
      await pg.query('BEGIN');
      try {
        const clientRes = await pg.query(`SELECT id FROM clients WHERE slug = $1`, [clientSlug]);
        if (!clientRes.rows.length) throw Object.assign(new Error('client_not_found'), { code: 404 });
        const clientId = clientRes.rows[0].id;

        const beds = (await pg.query(TO_ROOM_BEDS_FOR_BLOCK_SQL, [clientSlug, roomCode])).rows;
        if (!beds.length) throw Object.assign(new Error('room_not_found_or_no_active_beds'), { code: 404 });

        const conflicts = (await pg.query(TO_BED_CONFLICTS_SQL, [clientSlug, roomCode, checkIn, checkOut])).rows;
        if (conflicts.length) {
          throw Object.assign(new Error('bed_conflicts'), { code: 409, conflicts });
        }

        const roomId = beds[0].room_id;
        let bookingCode = body.booking_code ? String(body.booking_code).trim().slice(0, 60) : null;
        if (!bookingCode) bookingCode = generateTourOperatorBookingCode();
        const metadata = JSON.stringify({
          source: 'staff_tour_operator',
          manager,
          phone,
          email,
          created_by: actorId,
          created_role: actorRole,
        });

        const bkIns = await pg.query(
          `INSERT INTO bookings (
             client_id, booking_code, guest_name, operator_name, phone, email,
             booking_source, block_type, status, payment_status, assignment_status,
             availability_check_status, check_in, check_out, guest_count,
             primary_room_code, room_to_block_id, staff_notes,
             deposit_required_cents, deposit_paid_cents, balance_due_cents,
             total_amount_cents, amount_paid_cents, metadata
           ) VALUES (
             $1, $2, $3, $4, $5, $6,
             'operator', 'whole_room', 'confirmed', 'not_requested', 'assigned',
             'unknown', $7::date, $8::date, 1,
             $9, $10::uuid, $11,
             0, 0, 0, 0, 0, $12::jsonb
           )
           RETURNING id, booking_code, check_in::text AS check_in, check_out::text AS check_out`,
          [
            clientId, bookingCode, operatorName, operatorName, phone, email,
            checkIn, checkOut, roomCode, roomId, staffNotes, metadata,
          ]
        );
        const booking = bkIns.rows[0];

        const bedAssign = await tourOperatorAssignWholeRoomBeds(pg, {
          clientId,
          clientSlug,
          bookingId: booking.id,
          roomCode,
          checkIn,
          checkOut,
          operatorName,
        });

        await pg.query('COMMIT');
        return {
          booking_id: booking.id,
          booking_code: booking.booking_code,
          check_in: booking.check_in,
          check_out: booking.check_out,
          room_code: roomCode,
          operator_name: operatorName,
          bed_count: bedAssign.bed_count,
          bed_codes: bedAssign.bed_codes,
        };
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });

    appendAuditLog({ ...auditBase, success: true, booking_code: result.booking_code });
    return sendJSON(res, 201, {
      success: true,
      send_mutation: true,
      no_whatsapp: true,
      no_n8n: true,
      no_stripe: true,
      booking: result,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message });
    if (err.code === 409 && err.message === 'bed_conflicts') {
      return sendJSON(res, 409, {
        success: false,
        error: 'bed_conflicts',
        conflicts: err.conflicts || [],
      });
    }
    if (err.code === 404) return sendJSON(res, 404, { success: false, error: err.message });
    return sendJSON(res, 500, { success: false, error: 'create failed', detail: err.message });
  }
}

async function handleTourOperatorReleasePreview(req, res, user) {
  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }
  const clientSlug = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId = String(body.booking_id || '').trim();
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');

  try {
    const out = await withPgClient(async (pg) => {
      const bkRes = await pg.query(TO_OPERATOR_BOOKING_BY_ID_SQL, [clientSlug, bookingId]);
      if (!bkRes.rows.length) return { error: 'booking_not_found', status: 404 };
      const bk = bkRes.rows[0];
      if (bk.booking_source !== 'operator') return { error: 'not_operator_booking', status: 409 };
      if (bk.status === 'cancelled' || bk.status === 'expired') return { error: 'booking_not_active', status: 409 };

      const input = tourOperatorReleaseInputFromBody({
        ...body,
        operator: bk.operator_name,
        room_code: bk.primary_room_code,
      }, clientSlug);
      const plan = await loadOperatorRoomReleaseImpactPlan(pg, input);
      if (plan.match_phase && plan.match_phase.match_count === 1
          && String(plan.match_phase.candidates[0].booking_id) !== String(bookingId)) {
        plan.actionable = (plan.actionable || []).concat(['booking_id_mismatch']);
      }
      return { plan, booking: bk, input, blocked: tourOperatorPlanIsBlocked(plan) };
    });
    if (out.error) return sendJSON(res, out.status || 400, { success: false, error: out.error });
    return sendJSON(res, 200, {
      success: true,
      send_mutation: false,
      preview: out.plan,
      booking: out.booking,
      can_release: !out.blocked,
    });
  } catch (err) {
    return sendJSON(res, 500, { success: false, error: 'preview failed', detail: err.message });
  }
}

async function handleTourOperatorRelease(req, res, user) {
  if (!STAFF_ACTIONS_ENABLED) {
    return sendJSON(res, 403, {
      success: false,
      error: 'Staff write actions are disabled. Set STAFF_ACTIONS_ENABLED=true to enable.',
    });
  }
  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }
  const clientSlug = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId = String(body.booking_id || '').trim();
  const confirm = body.confirm === true;
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (!confirm) return send400(res, 'confirm: true is required');

  const auditBase = {
    ts: new Date().toISOString(),
    intent: 'api:tour_operator_release',
    category: 'tour_operator',
    client_slug: clientSlug,
    booking_id: bookingId,
    staff_user_id: user ? user.staff_user_id : null,
    stripe_called: false,
    whatsapp_called: false,
    n8n_called: false,
  };

  try {
    const out = await withPgClient(async (pg) => {
      const bkRes = await pg.query(TO_OPERATOR_BOOKING_BY_ID_SQL, [clientSlug, bookingId]);
      if (!bkRes.rows.length) return { error: 'booking_not_found', status: 404 };
      const bk = bkRes.rows[0];
      if (bk.booking_source !== 'operator') return { error: 'not_operator_booking', status: 409 };

      const input = tourOperatorReleaseInputFromBody({
        ...body,
        operator: bk.operator_name,
        room_code: body.room_code ? normalizeRoomCode(body.room_code) : normalizeRoomCode(bk.primary_room_code),
      }, clientSlug);

      const releaseStart = input.releaseStart;
      const releaseEnd = input.releaseEnd;
      if (!DATE_RE.test(releaseStart) || !DATE_RE.test(releaseEnd)) {
        return { error: 'release_start and release_end must be YYYY-MM-DD', status: 400 };
      }
      if (releaseEnd <= releaseStart) return { error: 'release_end must be after release_start', status: 400 };
      if (releaseStart < bk.check_in || releaseEnd > bk.check_out) {
        return { error: 'release_dates_outside_block', status: 409 };
      }

      const plan = await loadOperatorRoomReleaseImpactPlan(pg, input);
      if (tourOperatorPlanIsBlocked(plan)) {
        return { error: 'release_blocked', status: 409, plan };
      }
      const matchedId = plan.match_phase && plan.match_phase.candidates[0]
        ? plan.match_phase.candidates[0].booking_id : null;
      if (matchedId && String(matchedId) !== String(bookingId)) {
        return { error: 'booking_id_mismatch', status: 409 };
      }

      const exec = await tourOperatorExecuteRoomRelease(pg, plan, input);
      if (exec.error) return { error: exec.error, status: 409, detail: exec };
      return { exec, plan, booking: bk };
    });

    if (out.error) {
      appendAuditLog({ ...auditBase, success: false, error: out.error });
      return sendJSON(res, out.status || 400, { success: false, error: out.error, detail: out.detail || out.plan || null });
    }

    appendAuditLog({ ...auditBase, success: true, request_id: out.exec.request_id });
    return sendJSON(res, 200, {
      success: true,
      send_mutation: true,
      no_whatsapp: true,
      no_n8n: true,
      no_stripe: true,
      idempotent: !!out.exec.idempotent,
      release: out.exec,
      split: out.plan.split_phase,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message });
    return sendJSON(res, 500, { success: false, error: 'release failed', detail: err.message });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Stage 7.7k3 — Bed reassignment preview handler (proposal-only, no write)
//
// GET /staff/bed-calendar/reassign/preview
//   ?client=<slug>&booking_bed_id=<uuid>&target_bed_code=<bed>
//   &booking_code=<optional>&reason=<optional>
//
// Calls reassignBookingBedSql() with confirm=false ($8=false).
// The UPDATE CTE is gated by confirm, so rows_updated is always 0.
// Wrapped in BEGIN/ROLLBACK — absolutely no booking_beds change can persist.
// The audit_written CTE only fires when updated ran, so no workflow_events row.
// Only the API's own audit log file is written on every call.
//
// Auth: operator/admin/owner minimum. Viewers get 403 when STAFF_AUTH_REQUIRED=true.
// NOT gated by STAFF_ACTIONS_ENABLED — preview is read-only; no write gate needed.
// Does NOT import or call reassign-booking-beds-pg-sql.js (bot reset path).
//
// Safety: booking_beds · bookings · payments · payment_events · staff_handoffs
//         all remain untouched. Protected table delta = 0 guaranteed.
// ─────────────────────────────────────────────────────────────────────────────

async function handleBedReassignPreview(query, res, user) {
  const started = Date.now();

  // ── Extract params ─────────────────────────────────────────────────────────
  const clientSlug    = String(query.client           || DEFAULT_CLIENT).trim();
  const bookingBedId  = String(query.booking_bed_id   || '').trim();
  const targetBedCode = String(query.target_bed_code  || '').trim();
  const reasonNote    = String(query.reason           || 'preview only').trim().slice(0, 500);
  const bookingCodeQ  = String(query.booking_code     || '').trim();

  // ── Input validation ───────────────────────────────────────────────────────
  if (SQL_INJECT_RE.test(clientSlug))
    return send400(res, 'invalid client slug');
  if (!bookingBedId)
    return send400(res, 'booking_bed_id is required');
  if (!UUID_VALIDATE_RE.test(bookingBedId))
    return send400(res, 'booking_bed_id must be a valid UUID');
  if (!targetBedCode)
    return send400(res, 'target_bed_code is required');
  if (SQL_INJECT_RE.test(targetBedCode))
    return send400(res, 'invalid target_bed_code');
  if (SQL_INJECT_RE.test(reasonNote))
    return send400(res, 'invalid reason');

  // ── Audit baseline ─────────────────────────────────────────────────────────
  const actorId   = user ? user.staff_user_id : 'dev-preview-local';
  const actorRole = user ? user.role          : 'operator';

  const auditBase = {
    ts:             new Date().toISOString(),
    intent:         'api:bed_reassign_preview',
    category:       'bed_reassign_api',
    client_slug:    clientSlug,
    booking_bed_id: bookingBedId,
    target_bed_code: targetBedCode,
    staff_user_id:  actorId,
    staff_role:     actorRole,
  };

  let previewRow;
  try {
    previewRow = await withPgClient(async (pg) => {
      // Step 1: resolve booking_code if not supplied by caller
      let bookingCode = bookingCodeQ;
      if (!bookingCode) {
        const lkup = await pg.query(LOOKUP_BOOKING_CODE_SQL, [bookingBedId, clientSlug]);
        if (lkup.rows.length === 0) {
          // Return null to signal not-found (handled below after try/catch)
          return null;
        }
        bookingCode = lkup.rows[0].booking_code;
      }

      // Step 2: run SQL inside BEGIN/ROLLBACK — always rolled back for preview.
      // The helper's UPDATE is already gated by confirm=false, giving rows_updated=0.
      // The ROLLBACK is defence-in-depth: no write can accidentally persist.
      await pg.query('BEGIN');
      let result;
      try {
        result = await pg.query(
          reassignBookingBedSql(),
          [
            clientSlug,   // $1 client_slug
            bookingCode,  // $2 booking_code
            bookingBedId, // $3 booking_bed_id (UUID)
            targetBedCode,// $4 target_bed_code
            actorId,      // $5 staff_user_id
            actorRole,    // $6 staff_role
            reasonNote,   // $7 reason_note
            false,        // $8 confirm = FALSE — preview only, never write
            false,        // $9 manual_operator_lock_override = FALSE (never override in preview)
          ]
        );
      } finally {
        // Always rollback — this is a preview; no writes should persist.
        try { await pg.query('ROLLBACK'); } catch (_) {}
      }
      return result.rows[0] || null;
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'preview query failed', detail: err.message });
  }

  // ── Not-found ──────────────────────────────────────────────────────────────
  if (previewRow === null) {
    appendAuditLog({ ...auditBase, success: false, error: 'assignment_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, {
      success: false,
      error:   'booking_bed_id not found for this client',
      note:    'The assignment may not exist or may belong to a different client.',
    });
  }

  // ── Safety assertion: rows_updated must be 0 for a preview call ───────────
  const rowsUpdated = Number(previewRow.rows_updated || 0);
  if (rowsUpdated !== 0) {
    // This should never happen (confirm=false + ROLLBACK), but log and surface it.
    appendAuditLog({
      ...auditBase, success: false,
      error: 'SAFETY_VIOLATION_rows_updated_nonzero', rows_updated: rowsUpdated,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 500, {
      success: false,
      error:   'Safety check failed: preview returned rows_updated != 0. No changes were committed (transaction was rolled back). Report this immediately.',
      rows_updated: rowsUpdated,
    });
  }

  const elapsed = Date.now() - started;
  appendAuditLog({
    ...auditBase,
    success:      true,
    blocked:      previewRow.blocked,
    block_reason: previewRow.block_reason,
    rows_updated: rowsUpdated,
    elapsed_ms:   elapsed,
  });

  return sendJSON(res, 200, {
    success:              true,
    preview:              true,
    note:                 'Proposal only — confirm=false. No booking_beds row was changed. Transaction was rolled back.',
    action:               previewRow.action,
    booking_code:         previewRow.booking_code,
    old_room_code:        previewRow.old_room_code,
    old_bed_code:         previewRow.old_bed_code,
    new_room_code:        previewRow.new_room_code,
    new_bed_code:         previewRow.new_bed_code,
    assignment_start_date: previewRow.assignment_start_date,
    assignment_end_date:   previewRow.assignment_end_date,
    blocked:              previewRow.blocked,
    block_reason:         previewRow.block_reason,
    conflict_count:       previewRow.conflict_count,
    rows_updated:         rowsUpdated,
    audit_payload:        previewRow.audit_payload,
    rollback_payload:     previewRow.rollback_payload,
    elapsed_ms:           elapsed,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Stage 7.7k5 — Bed reassignment confirmed write endpoint (staff-only, gated)
//
// POST /staff/bed-calendar/reassign/confirm
//
// Request body (JSON):
//   { client, booking_bed_id, target_bed_code, reason, confirm: true,
//     manual_operator_lock_override: false }
//
// Gates (all must pass):
//   1. STAFF_ACTIONS_ENABLED=true (env flag)
//   2. STAFF_AUTH_REQUIRED=true (env flag)
//   3. Authenticated session with role operator/admin/owner
//   4. confirm: true in request body (explicit acknowledgement)
//
// manual_operator_lock_override:
//   Intentionally NOT implemented in this slice (7.7k5).
//   If the current booking_beds row has assignment_type='manual', the helper
//   will block with block_reason='manual_operator_lock' → 409 returned.
//   Override is deferred to a later admin-only slice (7.7k6).
//
// Safety:
//   - Calls reassignBookingBedSql() with confirm=true inside BEGIN/COMMIT.
//   - If blocked OR rows_updated != 1 → ROLLBACK, never commits.
//   - rows_updated safety assertion: if helper returns any value other than 0
//     (blocked) or 1 (success), ROLLBACK and 500.
//   - Does NOT call reassign-booking-beds-pg-sql.js (bot reset path).
//   - Does NOT mutate: payments, payment_events, staff_handoffs, conversations.
//   - Does NOT expose a UI control; NOT wired to any calendar edit button.
// ─────────────────────────────────────────────────────────────────────────────

async function handleBedReassignConfirm(req, res) {
  const started = Date.now();

  // ── 1. Feature flag gate ────────────────────────────────────────────────────
  if (!STAFF_ACTIONS_ENABLED) {
    appendAuditLog({
      ts: new Date().toISOString(), intent: 'api:bed_reassign_confirm',
      category: 'bed_reassignment_api',
      success: false, error: 'feature_flag_disabled', elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 403, {
      success: false,
      error:   'Bed reassignment write is disabled. Set STAFF_ACTIONS_ENABLED=true to enable.',
    });
  }

  // ── 2. Auth gate (session + role) ──────────────────────────────────────────
  // Requires STAFF_AUTH_REQUIRED=true. Token-only path is NOT accepted for
  // confirmed bed reassignment writes — session auth is mandatory.
  if (!STAFF_AUTH_REQUIRED) {
    appendAuditLog({
      ts: new Date().toISOString(), intent: 'api:bed_reassign_confirm',
      category: 'bed_reassignment_api',
      success: false, error: 'auth_not_enabled', elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 403, {
      success: false,
      error:   'STAFF_AUTH_REQUIRED must be true for confirmed bed reassignment writes.',
    });
  }

  let sessionUser;
  try { sessionUser = await loadAuthSession(req); } catch (_) { sessionUser = null; }
  if (!sessionUser) {
    appendAuditLog({
      ts: new Date().toISOString(), intent: 'api:bed_reassign_confirm',
      category: 'bed_reassignment_api',
      success: false, error: 'unauthenticated', elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 401, {
      success: false,
      error:   'Authentication required for confirmed bed reassignment.',
    });
  }
  if (!hasRole(sessionUser.role, 'operator')) {
    appendAuditLog({
      ts: new Date().toISOString(), intent: 'api:bed_reassign_confirm',
      category: 'bed_reassignment_api',
      staff_user_id: sessionUser.staff_user_id, staff_role: sessionUser.role,
      success: false, error: 'insufficient_role', elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 403, {
      success:      false,
      error:        `Role 'operator' or higher required for bed reassignment.`,
      current_role: sessionUser.role,
    });
  }

  // ── 3. Parse body ───────────────────────────────────────────────────────────
  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug    = String(body.client          || DEFAULT_CLIENT).trim();
  const bookingBedId  = String(body.booking_bed_id  || '').trim();
  const targetBedCode = String(body.target_bed_code || '').trim();
  const reasonRaw     = String(body.reason          || '').trim();
  const confirmFlag   = body.confirm;
  // manual_operator_lock_override: must be an explicit boolean true to activate.
  // Any other value (undefined, false, null, string) is treated as false.
  const overrideRaw   = body.manual_operator_lock_override;
  const overrideFlag  = overrideRaw === true;

  // ── 4. Validate body ────────────────────────────────────────────────────────
  if (SQL_INJECT_RE.test(clientSlug))
    return send400(res, 'invalid client slug');
  if (!bookingBedId)
    return send400(res, 'booking_bed_id is required');
  if (!UUID_VALIDATE_RE.test(bookingBedId))
    return send400(res, 'booking_bed_id must be a valid UUID');
  if (!targetBedCode)
    return send400(res, 'target_bed_code is required');
  if (SQL_INJECT_RE.test(targetBedCode))
    return send400(res, 'invalid target_bed_code');
  if (!reasonRaw)
    return send400(res, 'reason is required and must be non-empty');
  if (SQL_INJECT_RE.test(reasonRaw))
    return send400(res, 'unsafe characters in reason');
  if (confirmFlag !== true)
    return send400(res, 'confirm: true is required in request body');

  const reasonNote    = reasonRaw.slice(0, 500);
  const actorId       = sessionUser.staff_user_id;
  const actorRole     = sessionUser.role;

  // ── 4b. Override role gate ──────────────────────────────────────────────────
  // Operators may NOT use manual_operator_lock_override even if they pass true.
  // This is enforced here at the API layer before the SQL is called.
  if (overrideFlag && !hasRole(actorRole, 'admin')) {
    appendAuditLog({
      ts: new Date().toISOString(), intent: 'api:bed_reassign_confirm',
      category: 'bed_reassignment_api',
      client_slug: clientSlug, booking_bed_id: bookingBedId,
      target_bed_code: targetBedCode, staff_user_id: actorId, staff_role: actorRole,
      success: false, error: 'insufficient_override_role',
      manual_operator_lock_override_requested: true,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 403, {
      success:        false,
      error:          'manual_operator_lock_override requires admin or owner role.',
      current_role:   actorRole,
      block_reason:   'insufficient_override_role',
    });
  }

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'api:bed_reassign_confirm',
    category:        'bed_reassignment_api',
    client_slug:     clientSlug,
    booking_bed_id:  bookingBedId,
    target_bed_code: targetBedCode,
    staff_user_id:   actorId,
    staff_role:      actorRole,
    manual_operator_lock_override_requested: overrideFlag,
  };

  // ── 5. Look up booking_code ─────────────────────────────────────────────────
  let bookingCode;
  try {
    const lkup = await withPgClient(async (pg) =>
      pg.query(LOOKUP_BOOKING_CODE_SQL, [bookingBedId, clientSlug])
    );
    if (lkup.rows.length === 0) {
      appendAuditLog({ ...auditBase, success: false, error: 'assignment_not_found', elapsed_ms: Date.now() - started });
      return sendJSON(res, 404, {
        success: false,
        error:   'booking_bed_id not found for this client',
      });
    }
    bookingCode = lkup.rows[0].booking_code;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: 'lookup_failed: ' + err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'booking lookup failed' });
  }

  // ── 6. Execute confirmed reassignment inside transaction ────────────────────
  let resultRow;
  try {
    resultRow = await withPgClient(async (pg) => {
      await pg.query('BEGIN');
      let row;
      try {
        const r = await pg.query(
          reassignBookingBedSql(),
          [
            clientSlug,   // $1 client_slug
            bookingCode,  // $2 booking_code
            bookingBedId, // $3 booking_bed_id (UUID)
            targetBedCode,// $4 target_bed_code
            actorId,      // $5 staff_user_id
            actorRole,    // $6 staff_role
            reasonNote,   // $7 reason_note
            true,         // $8 confirm = TRUE — confirmed write
            overrideFlag, // $9 manual_operator_lock_override (admin/owner only)
          ]
        );
        row = r.rows[0] || null;

        if (!row) {
          await pg.query('ROLLBACK');
          return null;
        }

        const rowsUpdated = Number(row.rows_updated || 0);

        // Blocked by safety gate → rollback, return row for 409 response
        if (row.blocked === true || rowsUpdated === 0) {
          await pg.query('ROLLBACK');
          row._rolled_back = true;
          return row;
        }

        // Unexpected: more than one row updated → safety rollback
        if (rowsUpdated !== 1) {
          await pg.query('ROLLBACK');
          row._safety_violation = true;
          row._rolled_back = true;
          return row;
        }

        // Success: commit
        await pg.query('COMMIT');
        return row;
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: 'write_failed: ' + err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'bed reassignment write failed' });
  }

  if (!resultRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'no_result_row', elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'no result row returned from helper' });
  }

  const rowsUpdated = Number(resultRow.rows_updated || 0);
  const elapsed     = Date.now() - started;

  // ── 7. Safety violation ─────────────────────────────────────────────────────
  if (resultRow._safety_violation) {
    appendAuditLog({
      ...auditBase, success: false,
      error: 'SAFETY_VIOLATION_rows_updated_not_1', rows_updated: rowsUpdated,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 500, {
      success:      false,
      error:        `Safety check failed: rows_updated=${rowsUpdated} (expected 1). Transaction rolled back.`,
      rows_updated: rowsUpdated,
    });
  }

  // ── 8. Blocked ──────────────────────────────────────────────────────────────
  if (resultRow.blocked === true) {
    appendAuditLog({
      ...auditBase, success: false,
      blocked: true, block_reason: resultRow.block_reason,
      rows_updated: rowsUpdated,
      manual_operator_lock_override_applied: false,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 409, {
      success:        false,
      blocked:        true,
      block_reason:   resultRow.block_reason,
      note:           resultRow.block_reason === 'manual_operator_lock'
        ? 'Assignment is manually locked. Use manual_operator_lock_override:true with admin/owner role to bypass.'
        : 'Reassignment blocked — see block_reason.',
      rows_updated:   rowsUpdated,
      old_bed_code:   resultRow.old_bed_code,
      new_bed_code:   resultRow.new_bed_code,
      conflict_count: resultRow.conflict_count,
      manual_operator_lock_override_requested: overrideFlag,
      elapsed_ms:     elapsed,
    });
  }

  // ── 9. Success ──────────────────────────────────────────────────────────────
  const auditPayload = resultRow.audit_payload || {};
  const overrideApplied = !!(auditPayload.manual_operator_lock_override_applied);
  appendAuditLog({
    ...auditBase,
    success:         true,
    rows_updated:    rowsUpdated,
    booking_code:    resultRow.booking_code,
    old_bed_code:    resultRow.old_bed_code,
    new_bed_code:    resultRow.new_bed_code,
    audit_event_id:  resultRow.audit_event_id,
    manual_operator_lock_override_applied: overrideApplied,
    elapsed_ms:      elapsed,
  });

  return sendJSON(res, 200, {
    success:               true,
    action:                'bed_reassignment',
    booking_code:          resultRow.booking_code,
    booking_bed_id:        bookingBedId,
    old_room_code:         resultRow.old_room_code,
    old_bed_code:          resultRow.old_bed_code,
    new_room_code:         resultRow.new_room_code,
    new_bed_code:          resultRow.new_bed_code,
    assignment_start_date: resultRow.assignment_start_date,
    assignment_end_date:   resultRow.assignment_end_date,
    rows_updated:          rowsUpdated,
    audit_event_id:        resultRow.audit_event_id,
    audit_payload:         resultRow.audit_payload,
    rollback_payload:      resultRow.rollback_payload,
    manual_operator_lock_override_requested: overrideFlag,
    manual_operator_lock_override_applied:   overrideApplied,
    elapsed_ms:            elapsed,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Stage 7.7i — Booking context handler (read-only)
//
// GET /staff/bookings/:bookingCode/context?client=<slug>
//   Returns full booking detail: booking, payments, rooming, conversation,
//   handoff state, and add-on summary for the Cami dashboard drawer.
//
// Safety: SELECT-only. No mutations. Viewer auth minimum. Fully audited.
// ─────────────────────────────────────────────────────────────────────────────

const BOOKING_CONTEXT_RE = /^\/staff\/bookings\/([A-Za-z0-9_\-]+)\/context$/;
const BOOKING_GUEST_PACKAGES_RE = /^\/staff\/bookings\/([A-Za-z0-9_\-]+)\/guest-packages$/;
const BOT_BOOKING_GUEST_PACKAGES_RE = /^\/staff\/bot\/bookings\/([A-Za-z0-9_\-]+)\/guest-packages$/;
const BOOKING_LUNA_NOTES_RE = new RegExp(
  `^/staff/bookings/(${UUID_RE})/luna-notes$`, 'i',
);

/** Stage 8.8.14 — safe when migration 010 not applied yet. */
function isMissingBookingServiceRecordsTable(err) {
  if (!err) return false;
  if (err.code === '42P01') return true;
  const msg = String(err.message || '');
  return /booking_service_records/.test(msg) && /does not exist|undefined table/i.test(msg);
}

function bookingContextServiceRecordsSql() {
  const base = getBookingServiceRecordsQuery();
  if (/sr\.metadata/.test(base)) return base;
  return base.replace('sr.notes', 'sr.notes,\n  sr.metadata');
}

async function loadBookingServiceRecords(pg, clientSlug, bookingCode) {
  try {
    const r = await pg.query(bookingContextServiceRecordsSql(), [clientSlug, bookingCode]);
    return { rows: r.rows, available: true };
  } catch (err) {
    if (isMissingBookingServiceRecordsTable(err)) {
      return { rows: [], available: false };
    }
    throw err;
  }
}

async function handleBookingGuestPackagesWrite(bookingCode, req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse(await readBody(req) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const idempotencyKey = String(body.idempotency_key || '').trim();
  const reason = String(body.reason || '').trim().slice(0, 500) || null;

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingCode || bookingCode.length > 64 || SQL_INJECT_RE.test(bookingCode)) {
    return send400(res, 'invalid booking code');
  }
  if (!idempotencyKey) return send400(res, 'idempotency_key is required');

  const actorId = user ? user.staff_user_id : 'dev-guest-packages-local';
  const actorRole = user ? user.role : 'operator';
  const actorLabel = user ? (user.email || user.staff_user_id) : actorId;

  const auditBase = {
    ts: new Date().toISOString(),
    intent: 'api:booking_guest_packages',
    category: 'booking_guest_packages_write',
    client_slug: clientSlug,
    booking_code: bookingCode,
    idempotency_key: idempotencyKey,
    staff_user_id: actorId,
    staff_role: actorRole,
    reason,
  };

  let bookingRow;
  try {
    const bookingRes = await withPgClient((pg) =>
      pg.query(EDIT_PREVIEW_BOOKING_BY_CODE_SQL, [clientSlug, bookingCode]),
    );
    bookingRow = bookingRes.rows[0] || null;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'booking lookup failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found', updated: false });
  }

  const guestCount = Math.max(1, Number(bookingRow.guest_count) || 1);
  const metadata = bookingRow.metadata || {};
  const normalized = normalizeGuestPackagesInput(
    body.guest_packages,
    guestCount,
    bookingRow.package_code,
  );
  if (normalized.error) {
    return send400(res, normalized.error);
  }

  const beforeGuestPackages = normalizeGuestPackagesFromBooking(bookingRow, metadata);
  const afterGuestPackages = normalized.guest_packages;
  const beforePackageCode = bookingRow.package_code || null;
  const afterPackageCode = guestPackagesMajorityStorageCode(afterGuestPackages);

  const packagesEqual = beforeGuestPackages.every((gp, i) => {
    const after = afterGuestPackages[i];
    return editPreviewPackageStorageCode(gp.package_code) === editPreviewPackageStorageCode(after.package_code);
  }) && beforeGuestPackages.length === afterGuestPackages.length;

  if (packagesEqual) {
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, updated: false, idempotent: true, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      success: true,
      ok: true,
      updated: false,
      idempotent: true,
      guest_packages: afterGuestPackages,
      before: { guest_packages: beforeGuestPackages, package_code: beforePackageCode },
      after: { guest_packages: afterGuestPackages, package_code: afterPackageCode },
      message: 'Guest packages already match the requested values.',
      elapsed_ms: elapsed,
    });
  }

  try {
    await withPgClient(async (pg) => {
      await pg.query(
        `UPDATE bookings b
            SET metadata = jsonb_set(
                  COALESCE(b.metadata, '{}'::jsonb),
                  '{guest_packages}',
                  $3::jsonb,
                  true
                ),
                package_code = $4,
                updated_at = NOW()
          FROM clients c
         WHERE b.client_id = c.id
           AND c.slug = $1
           AND b.booking_code = $2`,
        [clientSlug, bookingCode, JSON.stringify(afterGuestPackages), afterPackageCode],
      );
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'guest_packages update failed', detail: err.message });
  }

  const elapsed = Date.now() - started;
  appendAuditLog({
    ...auditBase,
    success: true,
    updated: true,
    actor: actorLabel,
    before_guest_packages: beforeGuestPackages,
    after_guest_packages: afterGuestPackages,
    elapsed_ms: elapsed,
  });

  return sendJSON(res, 200, {
    success: true,
    ok: true,
    updated: true,
    guest_packages: afterGuestPackages,
    package_code: afterPackageCode,
    before: { guest_packages: beforeGuestPackages, package_code: beforePackageCode },
    after: { guest_packages: afterGuestPackages, package_code: afterPackageCode },
    message: 'Guest packages updated.',
    elapsed_ms: elapsed,
  });
}

async function handleBookingLunaNoteAppend(bookingId, req, res, user) {
  const started = Date.now();
  let body = {};
  try {
    body = JSON.parse(await readBody(req) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const text = String(body.text || body.note || '').trim();
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!text) return send400(res, 'text is required');
  if (!UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');

  const actorId = user ? user.staff_user_id : 'dev-luna-notes-local';

  try {
    const out = await withPgClient(async (pg) => appendBookingStaffNote(pg, {
      client_slug: clientSlug,
      booking_id: bookingId,
      text,
      staff_user_id: actorId,
    }));
    if (!out.success) {
      return sendJSON(res, 400, { success: false, error: out.error || 'append_failed' });
    }
    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:booking_luna_note_append',
      category: 'booking_luna_notes',
      client_slug: clientSlug,
      booking_id: bookingId,
      staff_user_id: actorId,
      success: true,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 200, {
      success: true,
      note: out.note,
      luna_guest_notes: out.luna_guest_notes,
    });
  } catch (err) {
    return sendJSON(res, 500, { success: false, error: 'append failed', detail: err.message });
  }
}

async function handleBookingContext(bookingCode, query, res, user) {
  const started    = Date.now();
  const clientSlug = (String(query.client || DEFAULT_CLIENT)).trim();
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!bookingCode || bookingCode.length > 64 || SQL_INJECT_RE.test(bookingCode)) {
    return send400(res, 'invalid booking code');
  }

  const auditBase = {
    ts:            new Date().toISOString(),
    intent:        'api:booking_context',
    category:      'booking_context_api',
    client_slug:   clientSlug,
    booking_code:  bookingCode,
    staff_user_id: user ? user.staff_user_id : null,
  };

  let bookingRows, paymentRows, roomingRows, convRows, handoffRows, addonRows, metaRows;
  let serviceRecordRows = [];
  let serviceRecordsAvailable = false;
  let transferRecordRows = [];
  let transfersAvailable = true;
  let pauseGateResult = null;
  try {
    [bookingRows, paymentRows, roomingRows, convRows, handoffRows, addonRows, metaRows, serviceRecordRows, serviceRecordsAvailable, transferRecordRows, transfersAvailable, pauseGateResult] =
      await withPgClient(async (pg) => {
        const [b, p, r, c, h, a, m, svc] = await Promise.all([
          pg.query(getBookingDetailQuery(),             [clientSlug, bookingCode]),
          pg.query(BOOKING_PAYMENTS_LEDGER_SQL,         [clientSlug, bookingCode]),
          pg.query(BOOKING_CONTEXT_ROOMING_SQL,       [clientSlug, bookingCode]),
          pg.query(getBookingConversationQuery(),       [clientSlug, bookingCode]),
          pg.query(getBookingHandoffQuery(),            [clientSlug, bookingCode]),
          pg.query(getBookingAddOnSummaryQuery(),       [clientSlug, bookingCode]).catch(() => ({ rows: [] })),
          pg.query(
            `SELECT b.metadata
               FROM bookings b
               INNER JOIN clients c ON c.id = b.client_id
              WHERE c.slug = $1 AND b.booking_code = $2
              LIMIT 1`,
            [clientSlug, bookingCode]
          ),
          loadBookingServiceRecords(pg, clientSlug, bookingCode),
        ]);
        const bkRow = b.rows[0] || null;
        let transfers = [];
        let xferAvailable = true;
        if (bkRow && bkRow.booking_id) {
          try {
            transfers = await listBookingTransfersForBooking(pg, {
              client_slug: clientSlug,
              booking_id: bkRow.booking_id,
            });
          } catch (err) {
            if (isMissingBookingTransfersTable(err)) {
              xferAvailable = false;
            } else {
              throw err;
            }
          }
        }
        let pauseGate = null;
        if (c.rows.length > 0) {
          const convRow = c.rows[0];
          try {
            pauseGate = await checkGuestAutomationPauseState(pg, {
              client_slug:     clientSlug,
              conversation_id: convRow.conversation_id,
              guest_phone:     convRow.phone || (bkRow && bkRow.phone),
              booking_code:    bookingCode,
            });
          } catch (_) {
            pauseGate = { bot_paused: false, live_send_blocked: false, source: 'default_active' };
          }
        }
        return [b.rows, p.rows, r.rows, c.rows, h.rows, a.rows, m.rows, svc.rows, svc.available, transfers, xferAvailable, pauseGate];
      });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'query failed', detail: err.message });
  }

  if (bookingRows.length === 0) {
    appendAuditLog({ ...auditBase, success: false, error: 'not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found', booking_code: bookingCode });
  }

  const bk = bookingRows[0];
  const bkMetadata = (metaRows[0] && metaRows[0].metadata) || {};
  const confirmationDraft = bkMetadata.confirmation_draft || null;
  const lunaGuestNotes = getLunaGuestNotesFromMetadata(bkMetadata);

  // Payments aggregate — paid truth from paid payment rows only (10.6b)
  const totalPaid = paymentLedgerPaidTotalCents(paymentRows);
  const latestStatus = paymentRows.length > 0 ? paymentRows[0].payment_status : null;

  // Rooming
  const assignedRooms = [...new Set(roomingRows.map(r => r.room_code).filter(Boolean))];
  const assignedBeds  = [...new Set(roomingRows.map(r => r.bed_code).filter(Boolean))];

  const elapsed = Date.now() - started;
  appendAuditLog({
    ...auditBase,
    success:          true,
    payment_rows:     paymentRows.length,
    rooming_rows:     roomingRows.length,
    conv_linked:      convRows.length > 0,
    handoff_open:     handoffRows.length > 0,
    addon_rows:       addonRows.length,
    service_records:  serviceRecordRows.length,
    service_records_available: serviceRecordsAvailable,
    elapsed_ms:       elapsed,
  });

  let conversationPayload = null;
  if (convRows.length > 0) {
    const convRow = convRows[0];
    const lunaPaused = pauseGateResult && pauseGateResult.bot_paused === true;
    conversationPayload = {
      conversation_id:      convRow.conversation_id,
      needs_human:          convRow.needs_human,
      bot_mode:             convRow.bot_mode,
      luna_paused:          lunaPaused,
      pending_action:       convRow.pending_action,
      conversation_status:  convRow.conversation_status,
      last_message_preview: convRow.last_message_preview,
    };
  }

  const pendingManualServices = filterPendingManualServiceRecords(serviceRecordRows).map((row) => ({
    service_type: row.service_type,
    staff_line: formatPendingManualServiceStaffLine(row),
    requested_at: row.requested_at || row.created_at || null,
    status: row.status,
    source: row.source,
  }));

  const serviceChargesDue = buildServiceChargesDueFromContext({
    booking: bk,
    serviceRecords: serviceRecordRows,
    paymentRows,
  });

  let transfersDrawer = null;
  try {
    transfersDrawer = buildTransfersDrawerPayload(clientSlug, bk, transferRecordRows, {
      transfers_available: transfersAvailable,
    });
  } catch (_) {
    transfersDrawer = null;
  }

  const guestAccommodationLines = buildGuestAccommodationLines(clientSlug, bk, bkMetadata);

  return sendJSON(res, 200, {
    success:      true,
    client_slug:  clientSlug,
    booking_code: bookingCode,
    guest_accommodation_lines: guestAccommodationLines,
    booking: {
      booking_id:          bk.booking_id,
      booking_code:        bk.booking_code,
      guest_name:          bk.guest_name,
      phone:               bk.phone,
      email:               bk.email,
      guest_count:         bk.guest_count,
      package_code:        bk.package_code,
      check_in:            bk.check_in,
      check_out:           bk.check_out,
      status:              bk.status,
      payment_status:      bk.payment_status,
      assignment_status:   bk.assignment_status,
      requested_room_type: bk.requested_room_type,
      room_preference:     bk.room_preference,
      primary_room_code:   bk.primary_room_code,
      needs_rooming_review:bk.needs_rooming_review,
      rooming_notes:       bk.rooming_notes,
      total_amount_cents:  bk.total_amount_cents,
      deposit_required_cents: bk.deposit_required_cents,
      amount_paid_cents:   bk.amount_paid_cents,
      balance_due_cents:   bk.balance_due_cents,
      metadata:            bkMetadata,
      confirmation_draft:  confirmationDraft,
    },
    payments: {
      rows:                  paymentRows,
      amount_paid_cents:     totalPaid,
      total_amount_cents:    Number(bk.total_amount_cents || 0),
      deposit_required_cents:Number(bk.deposit_required_cents || 0),
      balance_due_cents:     Number(bk.balance_due_cents || 0),
      latest_status:         latestStatus,
    },
    rooming: {
      assignments:       roomingRows,
      assigned_room_codes: assignedRooms,
      assigned_bed_codes:  assignedBeds,
      notes:             bk.rooming_notes || null,
    },
    conversation: conversationPayload,
    handoff: handoffRows.length > 0 ? {
      handoff_id:    handoffRows[0].handoff_id,
      reason_code:   handoffRows[0].reason_code,
      priority:      handoffRows[0].priority,
      status:        handoffRows[0].status,
      assigned_staff:handoffRows[0].assigned_staff,
      opened_at:     handoffRows[0].opened_at,
    } : null,
    addons: {
      rows: addonRows,
      note: addonRows.length === 0
        ? 'No add-on orders found for this booking'
        : null,
    },
    service_records: serviceRecordRows,
    service_records_available: serviceRecordsAvailable,
    pending_manual_services: pendingManualServices,
    service_charges_due_cents: serviceChargesDue.service_charges_due_cents,
    service_charges_due_lines: serviceChargesDue.service_charges_due_lines,
    accommodation_balance_due_cents: serviceChargesDue.accommodation_balance_due_cents,
    total_due_at_checkout_cents: serviceChargesDue.total_due_at_checkout_cents,
    transfers: transferRecordRows,
    transfers_drawer: transfersDrawer,
    luna_guest_notes: lunaGuestNotes,
    warnings: [],
    elapsed_ms: elapsed,
  });
}

